import { NextResponse } from 'next/server';
import { supabase } from '@/lib/supabase';
import { supabaseAdmin } from '@/lib/supabase-admin';

export async function GET(request: Request) {
    try {
        const { searchParams } = new URL(request.url);
        const period = searchParams.get('period');
        const from = searchParams.get('from');
        const to = searchParams.get('to');

        let dateFrom: string | null = null;
        let dateTo: string | null = null;

        if (from && to) {
            dateFrom = new Date(from).toISOString();
            dateTo = new Date(to).toISOString();
        } else if (period) {
            const now = new Date();
            dateTo = now.toISOString();
            switch (period) {
                case '7d': dateFrom = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000).toISOString(); break;
                case '30d': dateFrom = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000).toISOString(); break;
                case '3m': dateFrom = new Date(now.getFullYear(), now.getMonth() - 3, now.getDate()).toISOString(); break;
                case '6m': dateFrom = new Date(now.getFullYear(), now.getMonth() - 6, now.getDate()).toISOString(); break;
            }
        }

        // Build WHERE clause
        const conditions: string[] = [];
        const params: string[] = [];
        if (dateFrom) {
            params.push(dateFrom);
            conditions.push(`r.created_at >= $${params.length}`);
        }
        if (dateTo) {
            params.push(dateTo);
            conditions.push(`r.created_at <= $${params.length}`);
        }
        const whereClause = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';

        // Generate monthly trend params for last 6 months
        const now = new Date();
        const monthKeys: { key: string; label: string; start: string; end: string }[] = [];
        for (let i = 5; i >= 0; i--) {
            const date = new Date(now.getFullYear(), now.getMonth() - i, 1);
            const endDate = new Date(now.getFullYear(), now.getMonth() - i + 1, 0, 23, 59, 59);
            const key = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
            const label = date.toLocaleDateString('id-ID', { month: 'short', year: '2-digit' });
            monthKeys.push({ key, label, start: date.toISOString(), end: endDate.toISOString() });
        }

        // Run all aggregation queries in SQL via parallel Promise.all
        const [stationResult, divisionResult, summaryResult, stationsList] = await Promise.all([
            // Station stats (aggregated in SQL instead of fetching all rows)
            supabaseAdmin.rpc('run_analytics_query', {
                query_text: `
                    SELECT
                        COALESCE(s.code, 'Unknown') AS station,
                        count(*) AS total,
                        count(*) FILTER (WHERE r.status = 'SELESAI') AS resolved,
                        count(*) FILTER (WHERE r.status = 'MENUNGGU_FEEDBACK') AS pending,
                        count(*) FILTER (WHERE r.status = 'SUDAH_DIVERIFIKASI') AS in_progress,
                        count(*) FILTER (WHERE r.severity = 'high') AS high,
                        count(*) FILTER (WHERE r.severity = 'medium') AS medium,
                        count(*) FILTER (WHERE r.severity = 'low') AS low
                    FROM reports r
                    LEFT JOIN stations s ON r.station_id = s.id
                    ${whereClause}
                    GROUP BY COALESCE(s.code, 'Unknown')
                    ORDER BY count(*) DESC
                `,
                query_params: params,
            }),

            // Division stats
            supabaseAdmin.rpc('run_analytics_query', {
                query_text: `
                    SELECT
                        CASE
                            WHEN u.division IN ('OS', 'OP', 'OT', 'UQ') THEN u.division
                            ELSE 'Lainnya'
                        END AS division,
                        count(*) AS total,
                        count(*) FILTER (WHERE r.status = 'SELESAI') AS resolved,
                        count(*) FILTER (WHERE r.status IN ('MENUNGGU_FEEDBACK', 'SUDAH_DIVERIFIKASI')) AS pending,
                        count(*) FILTER (WHERE r.severity = 'high') AS high
                    FROM reports r
                    LEFT JOIN users u ON r.user_id = u.id
                    ${whereClause}
                    GROUP BY CASE WHEN u.division IN ('OS', 'OP', 'OT', 'UQ') THEN u.division ELSE 'Lainnya' END
                    ORDER BY count(*) DESC
                `,
                query_params: params,
            }),

            // Summary + severity + status + incident types + monthly trend (single query with CTEs)
            supabaseAdmin.rpc('run_analytics_query', {
                query_text: `
                    WITH base AS (
                        SELECT r.id, r.status, r.severity, r.created_at, it.name AS incident_type_name
                        FROM reports r
                        LEFT JOIN incident_types it ON r.incident_type_id = it.id
                        ${whereClause}
                    ),
                    summary AS (
                        SELECT
                            count(*) AS total_reports,
                            count(*) FILTER (WHERE status = 'SELESAI') AS resolved,
                            count(*) FILTER (WHERE status = 'MENUNGGU_FEEDBACK') AS pending,
                            count(*) FILTER (WHERE status = 'SUDAH_DIVERIFIKASI') AS verified,
                            count(*) FILTER (WHERE severity = 'high') AS high_severity
                        FROM base
                    ),
                    severity_dist AS (
                        SELECT json_agg(json_build_object('name', name, 'value', val, 'color', color) ORDER BY val DESC) AS data
                        FROM (
                            SELECT 'High' AS name, count(*) FILTER (WHERE severity = 'high') AS val, '#ef4444' AS color FROM base
                            UNION ALL
                            SELECT 'Medium', count(*) FILTER (WHERE severity = 'medium'), '#f59e0b' FROM base
                            UNION ALL
                            SELECT 'Low', count(*) FILTER (WHERE severity = 'low'), '#10b981' FROM base
                        ) t
                    ),
                    status_dist AS (
                        SELECT json_agg(json_build_object('name', name, 'value', val, 'color', color)) AS data
                        FROM (
                            SELECT 'Menunggu Feedback' AS name, count(*) FILTER (WHERE status = 'MENUNGGU_FEEDBACK') AS val, '#f59e0b' AS color FROM base
                            UNION ALL
                            SELECT 'Sudah Diverifikasi', count(*) FILTER (WHERE status = 'SUDAH_DIVERIFIKASI'), '#3b82f6' FROM base
                            UNION ALL
                            SELECT 'Selesai', count(*) FILTER (WHERE status = 'SELESAI'), '#10b981' FROM base
                        ) t
                    ),
                    incident_dist AS (
                        SELECT json_agg(json_build_object('name', name, 'value', val) ORDER BY val DESC) AS data
                        FROM (
                            SELECT COALESCE(incident_type_name, 'Lainnya') AS name, count(*) AS val
                            FROM base
                            GROUP BY name
                            ORDER BY val DESC
                            LIMIT 8
                        ) t
                    ),
                    monthly AS (
                        SELECT json_agg(json_build_object(
                            'month', month_label,
                            'total', total,
                            'resolved', resolved,
                            'high', high
                        ) ORDER BY month_key) AS data
                        FROM (
                            SELECT
                                date_trunc('month', created_at) AS month_key,
                                to_char(date_trunc('month', created_at), 'Mon YY') AS month_label,
                                count(*) AS total,
                                count(*) FILTER (WHERE status = 'SELESAI') AS resolved,
                                count(*) FILTER (WHERE severity = 'high') AS high
                            FROM base
                            GROUP BY date_trunc('month', created_at)
                            ORDER BY month_key
                        ) t
                    )
                    SELECT
                        s.total_reports, s.resolved, s.pending, s.verified, s.high_severity,
                        COALESCE(sev.data, '[]'::json) AS severity_data,
                        COALESCE(st.data, '[]'::json) AS status_data,
                        COALESCE(inc.data, '[]'::json) AS incident_data,
                        COALESCE(m.data, '[]'::json) AS trend_data
                    FROM summary s
                    LEFT JOIN severity_dist sev ON true
                    LEFT JOIN status_dist st ON true
                    LEFT JOIN incident_dist inc ON true
                    LEFT JOIN monthly m ON true
                `,
                query_params: params,
            }),

            // Stations list (lightweight, cached separately)
            supabase.from('stations').select('code, name').order('code'),
        ]);

        // Parse station data
        const stationData = (stationResult.data || []).map((row: any) => ({
            station: row.station,
            total: Number(row.total),
            resolved: Number(row.resolved),
            pending: Number(row.pending),
            inProgress: Number(row.in_progress),
            high: Number(row.high),
            medium: Number(row.medium),
            low: Number(row.low),
            resolutionRate: Number(row.total) > 0 ? Math.round((Number(row.resolved) / Number(row.total)) * 100) : 0,
        }));

        // Parse division data
        const divisionData = (divisionResult.data || []).map((row: any) => ({
            division: row.division,
            total: Number(row.total),
            resolved: Number(row.resolved),
            pending: Number(row.pending),
            high: Number(row.high),
            resolutionRate: Number(row.total) > 0 ? Math.round((Number(row.resolved) / Number(row.total)) * 100) : 0,
        }));

        // Parse summary data
        const summaryRow = summaryResult.data?.[0] || {};
        const totalReports = Number(summaryRow.total_reports) || 0;
        const resolvedReports = Number(summaryRow.resolved) || 0;

        return NextResponse.json({
            stationData,
            divisionData,
            trendData: Array.isArray(summaryRow.trend_data) ? summaryRow.trend_data : [],
            severityData: Array.isArray(summaryRow.severity_data) ? summaryRow.severity_data : [],
            statusData: Array.isArray(summaryRow.status_data) ? summaryRow.status_data : [],
            incidentData: Array.isArray(summaryRow.incident_data) ? summaryRow.incident_data : [],
            stations: stationsList.data || [],
            summary: {
                totalReports,
                resolvedReports,
                pendingReports: Number(summaryRow.pending) || 0,
                verifiedReports: Number(summaryRow.verified) || 0,
                highSeverity: Number(summaryRow.high_severity) || 0,
                avgResolutionRate: totalReports > 0 ? Math.round((resolvedReports / totalReports) * 100) : 0,
                stationCount: stationData.length,
            }
        }, {
            headers: {
                'Cache-Control': 'public, s-maxage=120, stale-while-revalidate=300',
                'CDN-Cache-Control': 'public, s-maxage=120, stale-while-revalidate=300',
            },
        });
    } catch (error) {
        console.error('Analytics error:', error);
        return NextResponse.json({ error: 'Failed to fetch analytics' }, { status: 500 });
    }
}

import { NextResponse } from 'next/server';
import { supabase } from '@/lib/supabase';
import { validateStatusTransition, getTimestampFieldForStatus, getUserFieldForStatus } from '@/lib/utils/validate-transition';

// GET all reports (for admin)
export async function GET(request: Request) {
    try {
        const { searchParams } = new URL(request.url);
        const status = searchParams.get('status');
        const station = searchParams.get('station');
        const search = searchParams.get('search');
        const severity = searchParams.get('severity');
        const mainCategory = searchParams.get('main_category');
        const from = searchParams.get('from');
        const to = searchParams.get('to');
        const targetDivision = searchParams.get('target_division');

        let query = supabase
            .from('reports')
            .select(`
        *,
        users:user_id (
          full_name,
          email
        ),
        stations:station_id (
          code,
          name
        )
      `)
            .order('created_at', { ascending: false });

        if (status && status !== 'all') {
            query = query.eq('status', status);
        }

        if (station && station !== 'all') {
            query = query.eq('station_id', station);
        }

        if (severity && severity !== 'all') {
            query = query.eq('severity', severity);
        }

        if (mainCategory && mainCategory !== 'all') {
            query = query.eq('main_category', mainCategory);
        }

        if (from) {
            query = query.gte('created_at', from);
        }

        if (to) {
            query = query.lte('created_at', to);
        }

        if (targetDivision && targetDivision !== 'all') {
            query = query.eq('target_division', targetDivision);
        }

        // Search by case number / title / reference_number / flight_number
        if (search) {
            query = query.or(`title.ilike.%${search}%,reference_number.ilike.%${search}%,flight_number.ilike.%${search}%`);
        }

        const { data, error } = await query;

        if (error) throw error;

        return NextResponse.json(data);
    } catch (error) {
        console.error('Error fetching reports:', error);
        return NextResponse.json({ error: 'Gagal memuat laporan' }, { status: 500 });
    }
}

// PATCH to update report status
export async function PATCH(request: Request) {
    try {
        const body = await request.json();
        const { reportId, action, userId, notes, resolution_evidence_url } = body;

        if (!reportId || !action) {
            return NextResponse.json({ error: 'reportId dan action wajib diisi' }, { status: 400 });
        }

        // Get current report
        const { data: report, error: fetchError } = await supabase
            .from('reports')
            .select('status')
            .eq('id', reportId)
            .single();

        if (fetchError || !report) {
            return NextResponse.json({ error: 'Laporan tidak ditemukan' }, { status: 404 });
        }

        // Get user role
        let userRole = body.userRole;
        if (!userRole && userId) {
            const { data: user } = await supabase
                .from('users')
                .select('role')
                .eq('id', userId)
                .single();
            userRole = user?.role;
        }

        if (!userRole) {
            return NextResponse.json({ error: 'Role pengguna tidak ditemukan' }, { status: 400 });
        }

        // Validate transition
        const validation = validateStatusTransition(report.status, action, userRole);
        if (!validation.valid) {
            return NextResponse.json({ error: validation.error }, { status: 403 });
        }

        const newStatus = validation.newStatus!;
        const updateData: Record<string, any> = {
            status: newStatus,
            updated_at: new Date().toISOString(),
        };

        // Set timestamp field for the transition
        const timestampField = getTimestampFieldForStatus(newStatus);
        if (timestampField) {
            updateData[timestampField] = new Date().toISOString();
        }

        // Set user field for the transition
        const userField = getUserFieldForStatus(newStatus);
        if (userField && userId) {
            updateData[userField] = userId;
        }

        // Add notes if provided
        if (notes) {
            if (action === 'verify') {
                updateData.validation_notes = notes;
            } else if (action === 'close') {
                updateData.investigator_notes = notes;
            } else if (action === 'reopen') {
                updateData.manager_notes = notes;
            }
        }

        // Add resolution evidence URL if provided
        if (resolution_evidence_url) {
            updateData.resolution_evidence_url = resolution_evidence_url;
        }

        // If reopening, clear resolved timestamps
        if (action === 'reopen') {
            updateData.resolved_at = null;
            updateData.resolved_by = null;
        }

        const { error } = await supabase
            .from('reports')
            .update(updateData)
            .eq('id', reportId);

        if (error) throw error;

        return NextResponse.json({ success: true, newStatus });
    } catch (error) {
        console.error('Error updating report:', error);
        return NextResponse.json({ error: 'Gagal mengubah status' }, { status: 500 });
    }
}

import { NextResponse } from 'next/server';
import { supabase } from '@/lib/supabase';
import { supabaseAdmin } from '@/lib/supabase-admin';

export async function GET(request: Request) {
    try {
        const { searchParams } = new URL(request.url);
        const period = searchParams.get('period');
        const from = searchParams.get('from');
        const to = searchParams.get('to');

        // Build date filter
        let dateFrom: string | null = null;
        let dateTo: string | null = null;

        if (from && to) {
            dateFrom = new Date(from).toISOString();
            dateTo = new Date(to).toISOString();
        } else if (period) {
            const now = new Date();
            dateTo = now.toISOString();
            switch (period) {
                case '7d':
                    dateFrom = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000).toISOString();
                    break;
                case '30d':
                    dateFrom = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000).toISOString();
                    break;
                case '3m':
                    dateFrom = new Date(now.getFullYear(), now.getMonth() - 3, now.getDate()).toISOString();
                    break;
                case '6m':
                    dateFrom = new Date(now.getFullYear(), now.getMonth() - 6, now.getDate()).toISOString();
                    break;
            }
        }

        const now = new Date();
        const startOfDay = new Date(now.getFullYear(), now.getMonth(), now.getDate()).toISOString();
        const startOfWeek = new Date(now.getFullYear(), now.getMonth(), now.getDate() - 7).toISOString();
        const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1).toISOString();

        // Build date condition for parameterized query
        const dateCondition = dateFrom && dateTo
            ? `created_at >= $1 AND created_at <= $2`
            : dateFrom
                ? `created_at >= $1`
                : 'TRUE';

        const params: string[] = [];
        if (dateFrom) params.push(dateFrom);
        if (dateTo) params.push(dateTo);

        const paramOffset = params.length;

        // Consolidated CTE query: replaces 13 separate count queries with 1
        const sql = `
            WITH filtered AS (
                SELECT status, severity, sla_deadline, station_id, location
                FROM reports
                WHERE ${dateCondition}
            ),
            counts AS (
                SELECT
                    count(*) AS total,
                    count(*) FILTER (WHERE status = 'MENUNGGU_FEEDBACK') AS menunggu_feedback,
                    count(*) FILTER (WHERE status = 'SUDAH_DIVERIFIKASI') AS sudah_diverifikasi,
                    count(*) FILTER (WHERE status = 'SELESAI') AS selesai,
                    count(*) FILTER (WHERE severity = 'high') AS high_severity,
                    count(*) FILTER (WHERE severity = 'medium') AS medium_severity,
                    count(*) FILTER (WHERE severity = 'low') AS low_severity,
                    count(*) FILTER (WHERE sla_deadline < $${paramOffset + 1} AND status != 'SELESAI') AS sla_breach
                FROM filtered
            ),
            trends AS (
                SELECT
                    count(*) FILTER (WHERE created_at >= $${paramOffset + 2}) AS today,
                    count(*) FILTER (WHERE created_at >= $${paramOffset + 3}) AS this_week,
                    count(*) FILTER (WHERE created_at >= $${paramOffset + 4}) AS this_month
                FROM reports
            ),
            user_counts AS (
                SELECT
                    count(*) FILTER (WHERE status = 'pending') AS pending_users,
                    count(*) FILTER (WHERE status = 'active') AS active_users
                FROM users
            ),
            location_stats AS (
                SELECT
                    COALESCE(s.code, f.location, 'Tidak Diketahui') AS loc,
                    count(*) AS cnt
                FROM filtered f
                LEFT JOIN stations s ON f.station_id = s.id
                GROUP BY loc
                ORDER BY cnt DESC
                LIMIT 5
            )
            SELECT
                c.total, c.menunggu_feedback, c.sudah_diverifikasi, c.selesai,
                c.high_severity, c.medium_severity, c.low_severity, c.sla_breach,
                t.today, t.this_week, t.this_month,
                u.pending_users, u.active_users,
                COALESCE(json_agg(json_build_object('location', ls.loc, 'count', ls.cnt)) FILTER (WHERE ls.loc IS NOT NULL), '[]'::json) AS top_locations
            FROM counts c, trends t, user_counts u
            LEFT JOIN location_stats ls ON TRUE
            GROUP BY c.total, c.menunggu_feedback, c.sudah_diverifikasi, c.selesai,
                     c.high_severity, c.medium_severity, c.low_severity, c.sla_breach,
                     t.today, t.this_week, t.this_month,
                     u.pending_users, u.active_users
        `;

        const allParams = [
            ...params,
            now.toISOString(),
            startOfDay,
            startOfWeek,
            startOfMonth,
        ];

        // Run consolidated query + recent reports in parallel (2 queries instead of 15)
        const [statsResult, recentResult] = await Promise.all([
            supabaseAdmin.rpc('run_analytics_query', {
                query_text: sql,
                query_params: allParams,
            }),
            supabase.from('reports')
                .select('id, title, location, status, severity, created_at, priority, sla_deadline, users:user_id(full_name), stations:station_id(code)')
                .order('created_at', { ascending: false })
                .limit(5),
        ]);

        // Fallback to original approach if RPC fails
        if (statsResult.error) {
            console.error('CTE stats query failed, using fallback:', statsResult.error);
            return fallbackStats(request);
        }

        const row = statsResult.data?.[0] || {};
        const totalReports = Number(row.total) || 0;
        const selesai = Number(row.selesai) || 0;
        const resolutionRate = totalReports ? Math.round((selesai / totalReports) * 100) : 0;

        return NextResponse.json({
            overview: {
                totalReports,
                menungguFeedback: Number(row.menunggu_feedback) || 0,
                sudahDiverifikasi: Number(row.sudah_diverifikasi) || 0,
                selesai,
                pendingUsers: Number(row.pending_users) || 0,
                activeUsers: Number(row.active_users) || 0,
                resolutionRate,
                slaBreachCount: Number(row.sla_breach) || 0,
            },
            severity: {
                high: Number(row.high_severity) || 0,
                medium: Number(row.medium_severity) || 0,
                low: Number(row.low_severity) || 0,
            },
            trends: {
                today: Number(row.today) || 0,
                thisWeek: Number(row.this_week) || 0,
                thisMonth: Number(row.this_month) || 0,
            },
            recentReports: recentResult.data || [],
            topLocations: Array.isArray(row.top_locations) ? row.top_locations : [],
        }, {
            headers: {
                'Cache-Control': 'public, s-maxage=60, stale-while-revalidate=120',
                'CDN-Cache-Control': 'public, s-maxage=60, stale-while-revalidate=120',
            },
        });
    } catch (error) {
        console.error('Stats error:', error);
        return NextResponse.json({ error: 'Failed to fetch stats' }, { status: 500 });
    }
}

// Fallback: original 15-query approach (used if CTE/RPC is unavailable)
async function fallbackStats(request: Request) {
    const { searchParams } = new URL(request.url);
    const period = searchParams.get('period');
    const from = searchParams.get('from');
    const to = searchParams.get('to');

    let dateFrom: string | null = null;
    let dateTo: string | null = null;

    if (from && to) {
        dateFrom = new Date(from).toISOString();
        dateTo = new Date(to).toISOString();
    } else if (period) {
        const now = new Date();
        dateTo = now.toISOString();
        switch (period) {
            case '7d': dateFrom = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000).toISOString(); break;
            case '30d': dateFrom = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000).toISOString(); break;
            case '3m': dateFrom = new Date(now.getFullYear(), now.getMonth() - 3, now.getDate()).toISOString(); break;
            case '6m': dateFrom = new Date(now.getFullYear(), now.getMonth() - 6, now.getDate()).toISOString(); break;
        }
    }

    const now = new Date();
    const startOfDay = new Date(now.getFullYear(), now.getMonth(), now.getDate()).toISOString();
    const startOfWeek = new Date(now.getFullYear(), now.getMonth(), now.getDate() - 7).toISOString();
    const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1).toISOString();

    const applyDateFilter = (query: any) => {
        if (dateFrom) query = query.gte('created_at', dateFrom);
        if (dateTo) query = query.lte('created_at', dateTo);
        return query;
    };

    const [
        { count: totalReports },
        { count: menungguFeedback },
        { count: sudahDiverifikasi },
        { count: selesai },
        { count: pendingUsers },
        { count: activeUsers },
        { count: todayReports },
        { count: weekReports },
        { count: monthReports },
        { count: highSeverity },
        { count: mediumSeverity },
        { count: lowSeverity },
        { count: slaBreachCount },
        { data: recentReports },
        { data: locationStats },
    ] = await Promise.all([
        applyDateFilter(supabase.from('reports').select('*', { count: 'exact', head: true })),
        applyDateFilter(supabase.from('reports').select('*', { count: 'exact', head: true }).eq('status', 'MENUNGGU_FEEDBACK')),
        applyDateFilter(supabase.from('reports').select('*', { count: 'exact', head: true }).eq('status', 'SUDAH_DIVERIFIKASI')),
        applyDateFilter(supabase.from('reports').select('*', { count: 'exact', head: true }).eq('status', 'SELESAI')),
        supabase.from('users').select('*', { count: 'exact', head: true }).eq('status', 'pending'),
        supabase.from('users').select('*', { count: 'exact', head: true }).eq('status', 'active'),
        supabase.from('reports').select('*', { count: 'exact', head: true }).gte('created_at', startOfDay),
        supabase.from('reports').select('*', { count: 'exact', head: true }).gte('created_at', startOfWeek),
        supabase.from('reports').select('*', { count: 'exact', head: true }).gte('created_at', startOfMonth),
        applyDateFilter(supabase.from('reports').select('*', { count: 'exact', head: true }).eq('severity', 'high')),
        applyDateFilter(supabase.from('reports').select('*', { count: 'exact', head: true }).eq('severity', 'medium')),
        applyDateFilter(supabase.from('reports').select('*', { count: 'exact', head: true }).eq('severity', 'low')),
        applyDateFilter(supabase.from('reports').select('*', { count: 'exact', head: true })
            .lt('sla_deadline', now.toISOString()).not('status', 'eq', 'SELESAI')),
        supabase.from('reports').select('id, title, location, status, severity, created_at, priority, sla_deadline, users:user_id(full_name), stations:station_id(code)').order('created_at', { ascending: false }).limit(5),
        applyDateFilter(supabase.from('reports').select('location, stations:station_id(code)')),
    ]);

    const locationBreakdown: Record<string, number> = {};
    locationStats?.forEach((report: any) => {
        const station = Array.isArray(report.stations) ? report.stations[0] : report.stations;
        const loc = station?.code || report.location || 'Tidak Diketahui';
        locationBreakdown[loc] = (locationBreakdown[loc] || 0) + 1;
    });

    const topLocations = Object.entries(locationBreakdown)
        .sort((a, b) => b[1] - a[1])
        .slice(0, 5)
        .map(([location, count]) => ({ location, count }));

    const resolutionRate = totalReports ? Math.round(((selesai || 0) / totalReports) * 100) : 0;

    return NextResponse.json({
        overview: {
            totalReports: totalReports || 0,
            menungguFeedback: menungguFeedback || 0,
            sudahDiverifikasi: sudahDiverifikasi || 0,
            selesai: selesai || 0,
            pendingUsers: pendingUsers || 0,
            activeUsers: activeUsers || 0,
            resolutionRate,
            slaBreachCount: slaBreachCount || 0,
        },
        severity: {
            high: highSeverity || 0,
            medium: mediumSeverity || 0,
            low: lowSeverity || 0,
        },
        trends: {
            today: todayReports || 0,
            thisWeek: weekReports || 0,
            thisMonth: monthReports || 0,
        },
        recentReports: recentReports || [],
        topLocations,
    }, {
        headers: {
            'Cache-Control': 'public, s-maxage=60, stale-while-revalidate=120',
            'CDN-Cache-Control': 'public, s-maxage=60, stale-while-revalidate=120',
        },
    });
}

