/**
 * GET /api/auth/me
 * Returns current user's profile including station info
 */
export async function GET(request: Request) {
    try {
        const cookieStore = await cookies();
        const token = cookieStore.get('session')?.value;

        const demoEnabled = process.env.DEMO_MODE === 'true';
        const isDemo = demoEnabled && (request.headers.get('x-demo') === 'true');

        if (!token) {
            if (isDemo) {
                return NextResponse.json({
                    id: 'demo-user-id',
                    email: 'demo@gapura.demo',
                    full_name: 'Demo User',
                    nik: 'DEMO123',
                    phone: '08123456789',
                    role: 'ANALYST',
                    division: 'OS',
                    status: 'ACTIVE',
                    station_id: 'demo-station-id',
                    station: {
                        id: 'demo-station-id',
                        code: 'CGK',
                        name: 'Soekarno-Hatta International Airport'
                    }
                });
            }
            return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
        }

        const payload = await verifySession(token);
        if (!payload) {
            return NextResponse.json({ error: 'Invalid session' }, { status: 401 });
        }

        // Get user with station info
        const { data: userData, error } = await supabase
            .from('users')
            .select(`
                id,
                email,
                full_name,
                nik,
                phone,
                role,
                division,
                status,
                station_id,
                stations:station_id (
                    id,
                    code,
                    name
                )
            `)
            .eq('id', payload.id)
            .single();

        if (error) {
            console.error('Error fetching user:', error);
            return NextResponse.json({ error: 'Failed to fetch user' }, { status: 500 });
        }

        // Format response
        const response = {
            id: userData.id,
            email: userData.email,
            full_name: userData.full_name,
            nik: userData.nik,
            phone: userData.phone,
            role: userData.role,
            division: userData.division,
            status: userData.status,
            station_id: userData.station_id,
            station: userData.stations ? {
                id: (userData.stations as any).id,
                code: (userData.stations as any).code,
                name: (userData.stations as any).name,
            } : null,
        };

        return NextResponse.json(response);
    } catch (error) {
        console.error('Error in /api/auth/me:', error);
        return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
    }
}

import { NextResponse } from 'next/server';
import { supabase } from '@/lib/supabase';

export async function GET() {
  try {
    const fields = ['hub', 'branch', 'airline', 'airline_type', 'main_category', 'area'];

    // We fetch all distinct values in one go using a custom RPC or multiple queries.
    // For simplicity and speed, we'll use Promise.all with small queries since Supabase 
    // doesn't have a native "SELECT DISTINCT FROM multiple columns" easily without custom SQL.

    const results = await Promise.all(
      fields.map(async (field) => {
        const { data, error } = await supabase
          .from('reports')
          .select(field)
          .not(field, 'is', null)
          .order(field);

        if (error) throw error;

        // Manual distinct filter since PostgREST select distinct is tricky with just one col
        const uniqueValues = Array.from(new Set(data.map((item: any) => item[field])));
        return { field, values: uniqueValues };
      })
    );

    const filterOptions = results.reduce((acc: any, curr) => {
      acc[curr.field] = curr.values.map(val => ({
        value: val,
        label: val === '#N/A' ? 'N/A' : val
      }));
      return acc;
    }, {});

    return NextResponse.json(filterOptions);
  } catch (error) {
    console.error('Error fetching filters:', error);
    return NextResponse.json({ error: 'Failed to fetch filters' }, { status: 500 });
  }
}

