    const cacheKey = generateCacheKey(body);

    // Check cache first
    const cachedInsights = getCachedInsights(cacheKey);
    if (cachedInsights) {
      console.log(`[AI Insights] Cache hit for tile: ${tileId}`);
      return NextResponse.json({
        insights: cachedInsights,
