                        resolvedReports={stats?.overview.selesai || 0}
                        period={period}
                        onPeriodChange={(p) => setPeriod(p)}
                    />

                    {stats?.severity.high && stats.severity.high > 0 && (
                        <div
                            className="card-solid flex items-center gap-4 animate-fade-in-up cursor-pointer"
                            style={{
                                background: 'oklch(0.60 0.22 25 / 0.08)',
                                border: '1px solid oklch(0.60 0.22 25 / 0.2)',
                                padding: 'var(--space-lg)'
                            }}
                            onClick={() => router.push('/dashboard/admin/drilldown?type=severity&value=high')}
                        >
                            <div
                                className="p-3 rounded-xl"
                                style={{ background: 'oklch(0.60 0.22 25 / 0.15)' }}
                            >
                                <AlertTriangle size={24} style={{ color: 'oklch(0.50 0.20 25)' }} />
                            </div>
                            <div className="flex-1">
                                <p className="font-bold" style={{ color: 'oklch(0.40 0.18 25)' }}>
                                    {stats.severity.high} Laporan Prioritas Tinggi
                                </p>
                                <p className="text-sm" style={{ color: 'oklch(0.55 0.15 25)' }}>
                                    Membutuhkan penanganan segera
                                </p>
                            </div>
                            <div
                                className="btn-primary"
                                style={{
                                    background: 'oklch(0.55 0.20 25)',
                                    boxShadow: '0 4px 16px oklch(0.55 0.20 25 / 0.3)'
                                }}
                            >
                                Lihat
                                <ArrowRight size={16} />
                            </div>
                        </div>
                    )}
                </div>
            </PresentationSlide>

            {/* Slide 2: Severity + Activity + Top Locations */}
            <PresentationSlide
                title="Analisis & Tren"
                subtitle="Breakdown severity, aktivitas, dan lokasi terbanyak"
                icon={TrendingUp}
                hint="Klik item untuk melihat detail laporan"
            >
                <div className="bento-grid bento-3">
                    {/* Severity Breakdown */}
                    <div className="card-solid animate-fade-in-up">
                        <p className="text-xs font-semibold uppercase tracking-wider mb-5" style={{ color: 'var(--text-muted)' }}>
                            Berdasarkan Severity
                        </p>
                        <div className="space-y-4">
                            {[
                                { label: 'High (Accident)', value: stats?.severity.high || 0, color: 'oklch(0.55 0.20 25)', icon: AlertTriangle, filterValue: 'high' },
                                { label: 'Medium (Incident)', value: stats?.severity.medium || 0, color: 'oklch(0.65 0.18 75)', icon: AlertCircle, filterValue: 'medium' },
                                { label: 'Low (Hazard)', value: stats?.severity.low || 0, color: 'oklch(0.55 0.15 160)', icon: Shield, filterValue: 'low' },
                            ].map((item) => {
                                const Icon = item.icon;
                                return (
                                    <div
                                        key={item.label}
                                        className="flex items-center justify-between cursor-pointer hover:bg-[var(--surface-2)] rounded-lg p-2 -mx-2 transition-colors"
                                        onClick={() => router.push(`/dashboard/admin/drilldown?type=severity&value=${item.filterValue}`)}
                                    >
                                        <div className="flex items-center gap-3">
                                            <div
                                                className="p-2 rounded-lg"
                                                style={{ background: `${item.color} / 0.12)`.replace(')', '') }}
                                            >
                                                <Icon size={16} style={{ color: item.color }} />
                                            </div>
                                            <span className="text-sm" style={{ color: 'var(--text-secondary)' }}>{item.label}</span>
                                        </div>
                                        <span className="text-xl font-bold" style={{ color: item.color }}>
                                            {item.value}
                                        </span>
                                    </div>
                                );
                            })}
                        </div>
                    </div>

                    {/* Activity Trends */}
                    <div className="card-solid animate-fade-in-up" style={{ animationDelay: '80ms' }}>
                        <p className="text-xs font-semibold uppercase tracking-wider mb-5" style={{ color: 'var(--text-muted)' }}>
                            Aktivitas
                        </p>
                        <div className="space-y-4">
                            {[
                                { label: 'Hari Ini', value: stats?.trends.today, trendKey: 'today' },
                                { label: 'Minggu Ini', value: stats?.trends.thisWeek, trendKey: 'thisWeek' },
                                { label: 'Bulan Ini', value: stats?.trends.thisMonth, trendKey: 'thisMonth' },
                            ].map((item) => (
                                <div
                                    key={item.label}
                                    className="flex items-center justify-between cursor-pointer hover:bg-[var(--surface-2)] rounded-lg p-2 -mx-2 transition-colors"
                                    onClick={() => router.push(`/dashboard/admin/drilldown?type=trend&value=${item.trendKey}`)}
                                >
                                    <span className="text-sm" style={{ color: 'var(--text-secondary)' }}>{item.label}</span>
                                    <span className="text-xl font-bold" style={{ color: 'var(--text-primary)' }}>{item.value}</span>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Top Locations */}
                    <div className="card-solid animate-fade-in-up" style={{ animationDelay: '160ms' }}>
                        <p className="text-xs font-semibold uppercase tracking-wider mb-5" style={{ color: 'var(--text-muted)' }}>
                            Lokasi Terbanyak
                        </p>
                        <div className="space-y-4">
                            {stats?.topLocations.length === 0 ? (
                                <p className="text-sm" style={{ color: 'var(--text-muted)' }}>Belum ada data</p>
                            ) : (
                                stats?.topLocations.slice(0, 4).map((loc, idx) => (
                                    <div
                                        key={idx}
                                        className="cursor-pointer hover:bg-[var(--surface-2)] rounded-lg p-2 -mx-2 transition-colors"
                                        onClick={() => router.push(`/dashboard/admin/drilldown?type=location&value=${encodeURIComponent(loc.location)}`)}
                                    >
                                        <div className="flex items-center justify-between mb-2">
                                            <span className="text-sm truncate max-w-[140px]" style={{ color: 'var(--text-secondary)' }}>
                                                {loc.location}
                                            </span>
                                            <span className="text-sm font-bold" style={{ color: 'var(--text-primary)' }}>
                                                {loc.count}
                                            </span>
                                        </div>
                                        <div className="h-2 rounded-full overflow-hidden" style={{ background: 'var(--surface-4)' }}>
                                            <div
                                                className="h-full rounded-full transition-all duration-500"
                                                style={{
                                                    width: `${(loc.count / maxLocation) * 100}%`,
                                                    background: 'linear-gradient(90deg, var(--brand-gradient-start), var(--brand-gradient-end))'
                                                }}
                                            />
                                        </div>
                                    </div>
                                ))
                            )}
                        </div>
                    </div>
                </div>
            </PresentationSlide>

            {/* Slide 3: Recent Reports */}
            <PresentationSlide
                title="Laporan Terbaru"
                subtitle="5 laporan terakhir"
                icon={FileText}
            >
                <div className="card-solid" style={{ padding: 0, overflow: 'hidden' }}>
                    {stats?.recentReports.length === 0 ? (
                        <div className="py-16 text-center">
                            <FileText size={40} style={{ color: 'var(--text-muted)' }} className="mx-auto mb-4 opacity-50" />
                            <p style={{ color: 'var(--text-muted)' }}>Belum ada laporan</p>
                        </div>
                    ) : (
                        <div>
                            {stats?.recentReports.map((report, idx) => (
                                <div
                                    key={report.id}
                                    onClick={() => setSelectedReport(report as unknown as Report)}
                                    className="flex items-center gap-4 transition-colors hover:bg-[var(--surface-3)]"
                                    style={{
                                        padding: 'var(--space-lg) var(--space-xl)',
                                        borderBottom: idx < (stats?.recentReports.length || 0) - 1 ? '1px solid var(--surface-4)' : 'none',
                                        cursor: 'pointer'
                                    }}
                                >
                                    <div
                                        className="w-2 h-2 rounded-full flex-shrink-0"
                                        style={{
                                            background: report.severity === 'high' ? 'oklch(0.55 0.20 25)' :
                                                       report.severity === 'medium' ? 'oklch(0.65 0.18 75)' :
                                                       'oklch(0.55 0.15 160)'
                                        }}
                                    />
                                    <div className="flex-1 min-w-0">
                                        <p className="font-medium truncate" style={{ color: 'var(--text-primary)' }}>
                                            {report.title}
                                        </p>
                                        <div className="flex items-center gap-3 mt-1">
                                            {report.stations && (
                                                <span className="flex items-center gap-1 text-xs" style={{ color: 'var(--text-muted)' }}>
                                                    <MapPin size={12} />
                                                    {report.stations.code}
                                                </span>
                                            )}
                                            <span className="text-xs" style={{ color: 'var(--text-muted)' }}>
                                                {report.users?.full_name}
                                            </span>
                                        </div>
                                    </div>
                                    <span className="text-xs" style={{ color: 'var(--text-muted)' }}>
                                        {new Date(report.created_at).toLocaleDateString('id-ID', { day: 'numeric', month: 'short' })}
                                    </span>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </PresentationSlide>

            {/* Slide 4: Quick Actions */}
            <PresentationSlide
                title="Aksi Cepat"
                subtitle="Kelola laporan dan pengguna"
                icon={Zap}
                className="!min-h-0"
            >
                <div className="bento-grid bento-2">
                    <Link
                        href="/dashboard/admin/reports"
                        className="card-solid flex items-center gap-4 group animate-fade-in-up"
                    >
                        <div
                            className="p-4 rounded-xl transition-all group-hover:scale-105"
                            style={{ background: 'oklch(0.65 0.18 160 / 0.1)' }}
                        >
                            <FileText size={24} style={{ color: 'var(--brand-primary)' }} />
                        </div>
                        <div className="flex-1">
                            <p className="font-bold" style={{ color: 'var(--text-primary)' }}>Kelola Laporan</p>
                            <p className="text-sm" style={{ color: 'var(--text-muted)' }}>Tinjau dan proses insiden</p>
                        </div>
                        <ArrowRight size={18} className="group-hover:translate-x-1 transition-transform" style={{ color: 'var(--text-muted)' }} />
                    </Link>

                    <Link
                        href="/dashboard/admin/users"
                        className="card-solid flex items-center gap-4 group animate-fade-in-up"
                        style={{ animationDelay: '80ms' }}
                    >
                        <div
                            className="p-4 rounded-xl transition-all group-hover:scale-105"
                            style={{ background: 'oklch(0.60 0.15 250 / 0.1)' }}
                        >
                            <Users size={24} style={{ color: 'oklch(0.55 0.15 250)' }} />
                        </div>
                        <div className="flex-1">
                            <p className="font-bold" style={{ color: 'var(--text-primary)' }}>Kelola Pengguna</p>
                            <p className="text-sm" style={{ color: 'var(--text-muted)' }}>Akses & persetujuan pengguna</p>
                        </div>
                        <ArrowRight size={18} className="group-hover:translate-x-1 transition-transform" style={{ color: 'var(--text-muted)' }} />
                    </Link>
                </div>
            </PresentationSlide>

            {/* Report Detail Modal */}
            <ReportDetailModal
                isOpen={!!selectedReport}
                onClose={() => setSelectedReport(null)}
                report={selectedReport}
                userRole="SUPER_ADMIN"
            />
        </div>
    );
}

'use client';

import { useState, useEffect, useRef } from 'react';
import { useParams, useRouter } from 'next/navigation';
import {
    ArrowLeft, AlertCircle, Loader2
} from 'lucide-react';
import { supabase } from '@/lib/supabase';
import { Report, User } from '@/types';
import { ReportDetailView } from '@/components/dashboard/ReportDetailView';

export default function ReportDetailPage() {
    const params = useParams();
    const router = useRouter();
    const reportId = params.id as string;

    const [report, setReport] = useState<Report | null>(null);
    const [loading, setLoading] = useState(true);
    const [actionLoading, setActionLoading] = useState(false);
    const [error, setError] = useState('');
    const [user, setUser] = useState<User | null>(null);



    useEffect(() => {
        fetchUser();
        fetchReport();
    }, [reportId]);

    const fetchUser = async () => {
        try {
            const res = await fetch('/api/auth/me');
            if (res.ok) {
                const data = await res.json();
                setUser(data);
            }
        } catch (err) {
            console.error('Error fetching user:', err);
        }
    };

    const fetchReport = async () => {
        try {
            const res = await fetch(`/api/reports/${reportId}`);
            if (!res.ok) throw new Error('Failed to load report');
            const data = await res.json();
            setReport(data);
            setLoading(false);
        } catch (err) {
            setError(err instanceof Error ? err.message : 'Unknown error');
            setLoading(false);
        }
    };

    const handleStatusUpdate = async (id: string, status: string, notes?: string) => {
        setActionLoading(true);
        try {
            // Use the Admin API for status updates, consistent with the main list page
            const res = await fetch('/api/admin/reports', {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ reportId: id, status, notes }),
            });

            if (res.ok) {
                await fetchReport();
            } else {
                alert('Gagal mengubah status');
            }
        } catch (error) {
            console.error('Error updating status:', error);
            alert('Terjadi kesalahan sistem');
        } finally {
            setActionLoading(false);
        }
    };

    if (loading) {
        return (
            <div className="flex items-center justify-center min-h-screen">
                <Loader2 className="w-8 h-8 animate-spin text-[var(--brand-primary)]" />
            </div>
        );
    }

    if (error || !report) {
        return (
            <div className="flex flex-col items-center justify-center min-h-screen gap-4">
                <AlertCircle className="w-12 h-12 text-red-500" />
                <h2 className="text-xl font-bold">Error Loading Report</h2>
                <p className="text-gray-500">{error}</p>
                <button 
                    onClick={() => router.back()}
                    className="flex items-center gap-2 text-[var(--brand-primary)] font-bold hover:underline"
                >
                    <ArrowLeft size={16} /> Kembali
                </button>
            </div>
        );
    }

    return (
        <div className="h-screen bg-[var(--surface-1)] overflow-hidden">
            <ReportDetailView 
                report={report} 
                onUpdateStatus={handleStatusUpdate}
                onRefresh={fetchReport}
                onClose={() => router.push('/dashboard/admin/reports')}
                userRole={user?.role || 'DIVISI_OS'}
                isModal={false}
                currentUserId={user?.id}
            />
        </div>
    );
}

'use client';

import { useEffect, useState } from 'react';
import {
    FileText, Search, Filter, ChevronDown, RefreshCw,
    MapPin, Calendar, User, AlertTriangle,
    Plane, Building2
} from 'lucide-react';
import { STATUS_CONFIG, SEVERITY_CONFIG, ReportStatus } from '@/lib/constants/report-status';
import { Report } from '@/types';
import { DashboardHeader } from '@/components/dashboard/DashboardHeader';
import { type TimePeriod } from '@/components/dashboard/TimePeriodFilter';
import { ReportDetailModal } from '@/components/dashboard/ReportDetailModal';

export default function AdminReportsPage() {
    const [reports, setReports] = useState<Report[]>([]);
    const [loading, setLoading] = useState(true);
    const [stationFilter, setStationFilter] = useState('all');
    const [filter, setFilter] = useState('all');
    const [severityFilter, setSeverityFilter] = useState('all');
    const [stations, setStations] = useState<Array<{ id: string; code: string; name: string }>>([]);
    const [search, setSearch] = useState('');
    const [selectedReport, setSelectedReport] = useState<Report | null>(null);
    const [period, setPeriod] = useState<TimePeriod>(null);

    const fetchStations = async () => {
        try {
            const res = await fetch('/api/master-data?type=stations');
            const data = await res.json();
            if (Array.isArray(data)) setStations(data);
            else if (data.stations) setStations(data.stations);
        } catch (error) {
            console.error('Error fetching stations:', error);
        }
    };

    const fetchReports = async () => {
        setLoading(true);
        try {
            const queryParams = new URLSearchParams();
            if (filter !== 'all') queryParams.append('status', filter);
            if (stationFilter !== 'all') queryParams.append('station', stationFilter);
            const res = await fetch(`/api/admin/reports?${queryParams.toString()}`);
            const data = await res.json();
            setReports(Array.isArray(data) ? data : []);
        } catch (error) {
            console.error('Error:', error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => { fetchReports(); }, [filter, stationFilter]);
    useEffect(() => { fetchStations(); }, []);

    const filteredReports = reports.filter(report => {
        const matchesSearch = report.title.toLowerCase().includes(search.toLowerCase()) ||
            report.location?.toLowerCase().includes(search.toLowerCase()) ||
            report.users?.full_name.toLowerCase().includes(search.toLowerCase()) ||
            report.stations?.name.toLowerCase().includes(search.toLowerCase()) ||
            report.id.toLowerCase().includes(search.toLowerCase()) ||
            report.reference_number?.toLowerCase().includes(search.toLowerCase()) ||
            report.flight_number?.toLowerCase().includes(search.toLowerCase());
        const matchesSeverity = severityFilter === 'all' || report.severity === severityFilter;
        return matchesSearch && matchesSeverity;
    });

    const stats = {
        total: reports.length,
        high: reports.filter(r => r.severity === 'high').length,
        pending: reports.filter(r => r.status === 'MENUNGGU_FEEDBACK').length,
        resolved: reports.filter(r => r.status === 'SELESAI').length,
    };

    return (
        <div className="space-y-8 stagger-children">
            {/* Header */}
            <DashboardHeader
                title="Kelola Laporan"
                subtitle="Kelola dan tindaklanjuti semua laporan masuk"
                totalReports={reports.length}
                pendingReports={reports.filter(r => r.status === 'MENUNGGU_FEEDBACK').length}
                resolvedReports={reports.filter(r => r.status === 'SELESAI').length}
                period={period}
                onPeriodChange={(p) => setPeriod(p)}
            />

            {/* Filters */}
            <div className="flex flex-col gap-4 animate-fade-in-up" style={{ animationDelay: '100ms' }}>
                <div className="relative">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5" style={{ color: 'var(--text-muted)' }} />
                    <input
                        type="text"
                        placeholder="Cari laporan, nomor kasus, lokasi, pelapor, atau station..."
                        value={search}
                        onChange={(e) => setSearch(e.target.value)}
                        className="input-field"
                        style={{ paddingLeft: 'calc(var(--space-lg) + 1.5rem)' }}
                    />
                </div>
                <div className="flex flex-wrap gap-3">
                    <div className="relative flex-1 min-w-[160px]">
                        <select value={stationFilter} onChange={(e) => setStationFilter(e.target.value)} className="input-field pl-10 pr-10 cursor-pointer" style={{ background: 'var(--surface-2)' }}>
                            <option value="all">Semua Station</option>
                            {stations.map((s) => (<option key={s.id} value={s.id}>{s.code} - {s.name}</option>))}
                        </select>
                        <Building2 className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4" style={{ color: 'var(--text-muted)' }} />
                        <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4" style={{ color: 'var(--text-muted)' }} />
                    </div>
                    <div className="relative flex-1 min-w-[140px]">
                        <select value={filter} onChange={(e) => setFilter(e.target.value)} className="input-field pl-10 pr-10 cursor-pointer" style={{ background: 'var(--surface-2)' }}>
                            <option value="all">Semua Status</option>
                            <option value="MENUNGGU_FEEDBACK">Menunggu Feedback</option>
                            <option value="SUDAH_DIVERIFIKASI">Sudah Diverifikasi</option>
                            <option value="SELESAI">Selesai</option>
                        </select>
                        <Filter className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4" style={{ color: 'var(--text-muted)' }} />
                        <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4" style={{ color: 'var(--text-muted)' }} />
                    </div>
                    <div className="relative flex-1 min-w-[140px]">
                        <select value={severityFilter} onChange={(e) => setSeverityFilter(e.target.value)} className="input-field pl-10 pr-10 cursor-pointer" style={{ background: 'var(--surface-2)' }}>
                            <option value="all">Semua Severity</option>
                            <option value="high">🔴 High</option>
                            <option value="medium">🟡 Medium</option>
                            <option value="low">🟢 Low</option>
                        </select>
                        <AlertTriangle className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4" style={{ color: 'var(--text-muted)' }} />
                        <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4" style={{ color: 'var(--text-muted)' }} />
                    </div>
                </div>
            </div>

            {/* Reports Table */}
            <div className="card-solid animate-fade-in-up" style={{ padding: 0, overflow: 'hidden', animationDelay: '150ms' }}>
                {/* Table Header */}
                <div 
                    className="flex items-center justify-between" 
                    style={{ padding: 'var(--space-lg) var(--space-xl)', borderBottom: '1px solid var(--surface-4)' }}
                >
                    <div className="flex items-center gap-3">
                        <div className="p-2.5 rounded-xl" style={{ background: 'oklch(0.55 0.14 160 / 0.12)' }}>
                            <FileText size={18} style={{ color: 'var(--brand-primary)' }} />
                        </div>
                        <div>
                            <h3 className="font-bold" style={{ color: 'var(--text-primary)' }}>Daftar Laporan</h3>
                            <p className="text-xs" style={{ color: 'var(--text-muted)' }}>{filteredReports.length} laporan</p>
                        </div>
                    </div>
                </div>

                {loading ? (
                    <div className="flex items-center justify-center py-16">
                        <div className="w-10 h-10 rounded-full border-4 animate-spin" style={{ borderColor: 'var(--surface-4)', borderTopColor: 'var(--brand-primary)' }} />
                    </div>
                ) : filteredReports.length === 0 ? (
                    <div className="py-16 text-center">
                        <FileText size={40} style={{ color: 'var(--text-muted)' }} className="mx-auto mb-4 opacity-50" />
                        <p style={{ color: 'var(--text-muted)' }}>Tidak ada laporan ditemukan</p>
                    </div>
                ) : (
                    <div className="overflow-x-auto">
                        <table className="w-full text-sm">
                            <thead>
                                <tr style={{ background: 'var(--surface-3)', borderBottom: '1px solid var(--surface-4)' }}>
                                    <th className="text-left py-3 px-5 font-semibold text-xs uppercase tracking-wider" style={{ color: 'var(--text-muted)', width: '45%' }}>Laporan</th>
                                    <th className="text-left py-3 px-4 font-semibold text-xs uppercase tracking-wider" style={{ color: 'var(--text-muted)' }}>Pelapor</th>
                                    <th className="text-center py-3 px-4 font-semibold text-xs uppercase tracking-wider" style={{ color: 'var(--text-muted)' }}>Severity</th>
                                    <th className="text-center py-3 px-4 font-semibold text-xs uppercase tracking-wider" style={{ color: 'var(--text-muted)' }}>Status</th>
                                    <th className="text-right py-3 px-5 font-semibold text-xs uppercase tracking-wider" style={{ color: 'var(--text-muted)' }}>Tanggal</th>
                                </tr>
                            </thead>
                            <tbody>
                                {filteredReports.map((report, idx) => {
                                    const severity = SEVERITY_CONFIG[report.severity as keyof typeof SEVERITY_CONFIG] || SEVERITY_CONFIG.low;
                                    const status = STATUS_CONFIG[report.status as ReportStatus] || STATUS_CONFIG.MENUNGGU_FEEDBACK;
                                    const SevIcon = severity.icon;
                                    const StatIcon = status.icon;

                                    return (
                                        <tr
                                            key={report.id}
                                            className="cursor-pointer transition-colors"
                                            style={{ 
                                                borderBottom: '1px solid var(--surface-4)',
                                                borderLeft: `3px solid ${severity.color}`
                                            }}
                                            onClick={() => setSelectedReport(report)}
                                            onMouseEnter={(e) => e.currentTarget.style.background = 'var(--surface-3)'}
                                            onMouseLeave={(e) => e.currentTarget.style.background = 'transparent'}
                                        >
                                            {/* Report Info */}
                                            <td className="py-4 px-5">
                                                <div className="flex items-start gap-3">
                                                    <div className="p-2 rounded-lg flex-shrink-0" style={{ background: severity.bg }}>
                                                        <SevIcon size={16} style={{ color: severity.color }} />
                                                    </div>
                                                    <div className="min-w-0">
                                                        <div className="flex items-center gap-2 mb-1">
                                                            <span className="px-1.5 py-0.5 rounded text-[10px] font-bold uppercase" style={{ background: 'var(--surface-4)', color: 'var(--text-secondary)' }}>
                                                                {report.stations?.code || report.branch || 'N/A'}
                                                            </span>
                                                            {report.flight_number && (
                                                                <span className="flex items-center gap-1 text-[10px] font-medium" style={{ color: 'oklch(0.50 0.12 250)' }}>
                                                                    <Plane size={10} />
                                                                    {report.flight_number}
                                                                </span>
                                                            )}
                                                        </div>
                                                        <p className="font-semibold truncate max-w-[280px]" style={{ color: 'var(--text-primary)' }}>{report.title}</p>
                                                        {report.location && (
                                                            <p className="text-xs flex items-center gap-1 mt-1 truncate max-w-[250px]" style={{ color: 'var(--text-muted)' }}>
                                                                <MapPin size={10} />
                                                                {report.location}
                                                            </p>
                                                        )}
                                                    </div>
                                                </div>
                                            </td>

                                            {/* Reporter */}
                                            <td className="py-4 px-4">
                                                <p className="font-medium truncate max-w-[120px]" style={{ color: 'var(--text-primary)' }}>{report.users?.full_name || report.reporter_name || '-'}</p>
                                            </td>

                                            {/* Severity Badge */}
                                            <td className="py-4 px-4 text-center">
                                                <span 
                                                    className="inline-flex items-center gap-1 px-2.5 py-1 rounded-lg text-xs font-bold text-white"
                                                    style={{ background: severity.color }}
                                                >
                                                    {severity.label}
                                                </span>
                                            </td>

                                            {/* Status Badge */}
                                            <td className="py-4 px-4 text-center">
                                                <span 
                                                    className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-semibold"
                                                    style={{ background: status.bgColor, color: status.color }}
                                                >
                                                    <StatIcon size={12} />
                                                    {status.label}
                                                </span>
                                            </td>

                                            {/* Date */}
                                            <td className="py-4 px-5 text-right">
                                                <p className="text-xs font-medium" style={{ color: 'var(--text-secondary)' }}>
                                                    {new Date(report.created_at).toLocaleDateString('id-ID', { day: 'numeric', month: 'short' })}
                                                </p>
                                                <p className="text-[10px]" style={{ color: 'var(--text-muted)' }}>
                                                    {new Date(report.created_at).toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit' })}
                                                </p>
                                            </td>
                                        </tr>
                                    );
                                })}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>

            {/* Detail Modal */}
            {selectedReport && (
                <ReportDetailModal
                    report={selectedReport}
                    onClose={() => setSelectedReport(null)}
                    userRole="SUPER_ADMIN"
                    onStatusChange={fetchReports}
                />
            )}
        </div>
    );
}

'use client';
import { useEffect, useState } from 'react';
import {
    Users, Search, RefreshCw, Check, X, Shield, User,
    Filter, ChevronDown, Mail, Calendar, Building2, Briefcase, Phone,
    Eye, Wrench, Star, Edit2, Save
} from 'lucide-react';
import type { UserRole, DivisionType } from '@/types';

interface UserData {
    id: string;
    email: string;
    full_name: string;
    nik: string;
    phone: string;
    role: UserRole;
    division: DivisionType;
    status: 'pending' | 'active' | 'rejected';
    created_at: string;
    stations: { code: string; name: string } | null;
    units: { name: string } | null;
    positions: { name: string } | null;
}

const statusConfig = {
    pending: { label: 'Pending', color: 'bg-amber-100 text-amber-700 border-amber-200' },
    active: { label: 'Aktif', color: 'bg-emerald-100 text-emerald-700 border-emerald-200' },
    rejected: { label: 'Ditolak', color: 'bg-red-100 text-red-700 border-red-200' },
};

const roleConfig: Record<UserRole, { label: string; color: string; icon: typeof User }> = {
    CABANG: { label: 'Cabang', color: 'bg-slate-100 text-slate-700', icon: User },
    DIVISI_OS: { label: 'Divisi OS', color: 'bg-blue-100 text-blue-700', icon: Eye },
    DIVISI_OT: { label: 'Divisi OT', color: 'bg-orange-100 text-orange-700', icon: Wrench },
    DIVISI_OP: { label: 'Divisi OP', color: 'bg-teal-100 text-teal-700', icon: User },
    DIVISI_UQ: { label: 'Divisi UQ', color: 'bg-pink-100 text-pink-700', icon: Shield },
    ANALYST: { label: 'Analyst', color: 'bg-indigo-100 text-indigo-700', icon: Star },
    SUPER_ADMIN: { label: 'Super Admin', color: 'bg-purple-100 text-purple-700', icon: Shield },
};

const divisionConfig: Record<DivisionType, string> = {
    GENERAL: 'Umum',
    OS: 'Operational Services',
    OT: 'Teknik (GSE)',
    OP: 'Operasi',
    UQ: 'Quality',
};

// --- Edit User Modal Component ---
function EditUserModal({ user, onClose, onSave, isLoading }: { 
    user: UserData, 
    onClose: () => void, 
    onSave: (data: { role: UserRole, division: DivisionType }) => void,
    isLoading: boolean
}) {
    const [role, setRole] = useState<UserRole>(user.role);
    const [division, setDivision] = useState<DivisionType>(user.division || 'GENERAL');

    return (
        <div className="fixed inset-0 z-50 bg-black/50 backdrop-blur-sm flex items-center justify-center p-4">
            <div className="bg-white rounded-2xl shadow-xl max-w-md w-full p-6 animate-scale-in">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="text-lg font-bold text-gray-900">Edit User</h3>
                    <button onClick={onClose} className="p-2 hover:bg-gray-100 rounded-lg transition-colors">
                        <X size={20} />
                    </button>
                </div>

                <div className="space-y-4">
                    <div>
                        <label className="block text-xs font-bold uppercase text-gray-500 mb-1">Nama Lengkap</label>
                        <p className="font-semibold text-gray-900">{user.full_name}</p>
                    </div>

                    <div>
                         <label className="block text-xs font-bold uppercase text-gray-500 mb-2">Role</label>
                         <select 
                            value={role} 
                            onChange={(e) => setRole(e.target.value as UserRole)}
                            className="w-full p-3 rounded-xl border border-gray-200 bg-gray-50 font-medium focus:ring-2 focus:ring-blue-500/20 outline-none"
                        >
                            {Object.entries(roleConfig).map(([key, config]) => (
                                <option key={key} value={key}>{config.label}</option>
                            ))}
                         </select>
                    </div>

                    <div>
                         <label className="block text-xs font-bold uppercase text-gray-500 mb-2">Divisi</label>
                         <select 
                            value={division} 
                            onChange={(e) => setDivision(e.target.value as DivisionType)}
                            className="w-full p-3 rounded-xl border border-gray-200 bg-gray-50 font-medium focus:ring-2 focus:ring-blue-500/20 outline-none"
                        >
                            {Object.entries(divisionConfig).map(([key, label]) => (
                                <option key={key} value={key}>{label}</option>
                            ))}
                         </select>
                    </div>
                </div>

                <div className="flex gap-3 mt-8">
                    <button onClick={onClose} className="flex-1 py-2.5 rounded-xl border border-gray-200 text-gray-600 font-semibold hover:bg-gray-50">
                        Batal
                    </button>
                    <button 
                        onClick={() => onSave({ role, division })}
                        disabled={isLoading}
                        className="flex-1 py-2.5 rounded-xl bg-blue-600 text-white font-semibold hover:bg-blue-700 flex items-center justify-center gap-2"
                    >
                        {isLoading ? <RefreshCw className="animate-spin" size={18} /> : <Save size={18} />}
                        Simpan Perubahan
                    </button>
                </div>
            </div>
        </div>
    );
}


export default function AdminUsersPage() {
    const [users, setUsers] = useState<UserData[]>([]);
    const [loading, setLoading] = useState(true);
    const [filter, setFilter] = useState('all');
    const [search, setSearch] = useState('');
    const [actionLoading, setActionLoading] = useState<string | null>(null);
    const [editingUser, setEditingUser] = useState<UserData | null>(null);

    const fetchUsers = async () => {
        setLoading(true);
        try {
            const res = await fetch(`/api/admin/users?status=${filter === 'all' ? '' : filter}`);
            const data = await res.json();
            setUsers(Array.isArray(data) ? data : []);
        } catch (error) {
            console.error('Error:', error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchUsers();
    }, [filter]);

    const updateUserStatus = async (userId: string, status: string) => {
        setActionLoading(userId);
        try {
            await fetch('/api/admin/users', {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ userId, status }),
            });
            fetchUsers();
        } catch (error) {
            alert('Gagal mengubah status');
        } finally {
            setActionLoading(null);
        }
    };

    const handleSaveUser = async (data: { role: UserRole, division: DivisionType }) => {
        if (!editingUser) return;
        setActionLoading(editingUser.id);
        
        try {
            const res = await fetch('/api/admin/users', {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ 
                    userId: editingUser.id, 
                    role: data.role,
                    division: data.division 
                }),
            });

            if (!res.ok) throw new Error('Failed to update');
            
            setEditingUser(null);
            fetchUsers();
        } catch (error) {
            alert('Gagal menyimpan perubahan user');
        } finally {
            setActionLoading(null);
        }
    };

    const filteredUsers = users.filter(user =>
        user.full_name?.toLowerCase().includes(search.toLowerCase()) ||
        user.email?.toLowerCase().includes(search.toLowerCase()) ||
        user.nik?.toLowerCase().includes(search.toLowerCase())
    );

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="flex items-start justify-between gap-4">
                <div>
                    <h1 className="text-2xl sm:text-3xl font-bold text-slate-900">Kelola User</h1>
                    <p className="text-slate-500 mt-1 text-sm sm:text-base">Kelola semua pengguna dalam sistem</p>
                </div>
                <button
                    onClick={fetchUsers}
                    className="flex items-center gap-2 px-3 py-2 rounded-xl border-2 border-slate-200 bg-white text-slate-600 hover:bg-slate-50 hover:border-slate-300 transition-colors text-sm font-medium flex-shrink-0"
                >
                    <RefreshCw className="w-4 h-4" />
                    <span className="hidden sm:inline">Refresh</span>
                </button>
            </div>

            {/* Stats Cards */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-3 sm:gap-4">
                <div className="bg-white rounded-xl border border-slate-100 p-3 sm:p-4">
                    <p className="text-xs sm:text-sm text-slate-500">Total User</p>
                    <p className="text-xl sm:text-2xl font-bold text-slate-900">{users.length}</p>
                </div>
                <div className="bg-emerald-50 rounded-xl border border-emerald-100 p-3 sm:p-4">
                    <p className="text-xs sm:text-sm text-emerald-600">Aktif</p>
                    <p className="text-xl sm:text-2xl font-bold text-emerald-700">{users.filter(u => u.status === 'active').length}</p>
                </div>
                <div className="bg-amber-50 rounded-xl border border-amber-100 p-3 sm:p-4">
                    <p className="text-xs sm:text-sm text-amber-600">Pending</p>
                    <p className="text-xl sm:text-2xl font-bold text-amber-700">{users.filter(u => u.status === 'pending').length}</p>
                </div>
                <div className="bg-purple-50 rounded-xl border border-purple-100 p-3 sm:p-4">
                    <p className="text-xs sm:text-sm text-purple-600">Super Admin</p>
                    <p className="text-xl sm:text-2xl font-bold text-purple-700">{users.filter(u => u.role === 'SUPER_ADMIN').length}</p>
                </div>
            </div>

            {/* Filters */}
            <div className="flex flex-col gap-3">
                <div className="relative flex-1">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
                    <input
                        type="text"
                        placeholder="Cari nama, email, atau NIK..."
                        value={search}
                        onChange={(e) => setSearch(e.target.value)}
                        className="w-full pl-12 pr-4 py-3 rounded-xl border-2 border-slate-200 bg-white focus:border-blue-500 focus:outline-none transition-colors text-sm"
                    />
                </div>
                <div className="relative w-full sm:w-auto">
                    <select
                        value={filter}
                        onChange={(e) => setFilter(e.target.value)}
                        className="w-full sm:w-auto appearance-none pl-10 pr-10 py-3 rounded-xl border-2 border-slate-200 bg-white text-slate-700 font-medium focus:border-blue-500 focus:outline-none cursor-pointer text-sm"
                    >
                        <option value="all">Semua Status</option>
                        <option value="pending">Pending</option>
                        <option value="active">Aktif</option>
                        <option value="rejected">Ditolak</option>
                    </select>
                    <Filter className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                    <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                </div>
            </div>

            {/* Users Table */}
            <div className="bg-white rounded-2xl border border-slate-100 overflow-hidden shadow-sm">
                {loading ? (
                    <div className="p-12 text-center">
                        <div className="w-12 h-12 border-4 border-blue-200 border-t-blue-600 rounded-full animate-spin mx-auto" />
                    </div>
                ) : filteredUsers.length === 0 ? (
                    <div className="p-12 text-center">
                        <Users className="w-12 h-12 text-slate-300 mx-auto mb-4" />
                        <p className="text-slate-500">Tidak ada user ditemukan</p>
                    </div>
                ) : (
                    <div className="overflow-x-auto">
                        <table className="w-full">
                            <thead>
                                <tr className="bg-slate-50/50 border-b border-slate-100">
                                    <th className="px-6 py-4 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">User</th>
                                    <th className="px-6 py-4 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Station / Unit</th>
                                    <th className="px-6 py-4 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Role</th>
                                    <th className="px-6 py-4 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Status</th>
                                    <th className="px-6 py-4 text-right text-xs font-semibold text-slate-500 uppercase tracking-wider">Aksi</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-100">
                                {filteredUsers.map((user) => {
                                    const RoleIcon = roleConfig[user.role]?.icon || User;
                                    return (
                                        <tr key={user.id} className="hover:bg-slate-50/50 transition-colors">
                                            <td className="px-6 py-4">
                                                <div className="flex items-center gap-4">
                                                    <div className={`w-11 h-11 rounded-full flex items-center justify-center text-white font-bold ${user.role === 'SUPER_ADMIN' ? 'bg-gradient-to-br from-purple-500 to-violet-600' : user.role === 'ANALYST' ? 'bg-gradient-to-br from-indigo-500 to-purple-500' : 'bg-gradient-to-br from-blue-500 to-cyan-500'}`}>
                                                        {user.full_name?.charAt(0).toUpperCase() || 'U'}
                                                    </div>
                                                    <div>
                                                        <p className="font-semibold text-slate-900">{user.full_name}</p>
                                                        <p className="text-xs text-slate-500 flex items-center gap-1">
                                                            <Mail size={10} />
                                                            {user.email}
                                                        </p>
                                                        {user.nik && (
                                                            <p className="text-xs text-slate-400">NIK: {user.nik}</p>
                                                        )}
                                                    </div>
                                                </div>
                                            </td>
                                            <td className="px-6 py-4">
                                                <div className="text-sm">
                                                    {user.stations && (
                                                        <p className="font-medium text-slate-700 flex items-center gap-1">
                                                            <Building2 size={12} className="text-slate-400" />
                                                            {user.stations.code}
                                                        </p>
                                                    )}
                                                    {user.division && (
                                                        <p className="text-xs font-bold text-slate-600 mt-0.5">{divisionConfig[user.division] || user.division}</p>
                                                    )}
                                                    {user.units && (
                                                        <p className="text-xs text-slate-500">{user.units.name}</p>
                                                    )}
                                                </div>
                                            </td>
                                            <td className="px-6 py-4">
                                                <span className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-semibold ${roleConfig[user.role]?.color || 'bg-slate-100 text-slate-700'}`}>
                                                    <RoleIcon size={12} />
                                                    {roleConfig[user.role]?.label || user.role}
                                                </span>
                                            </td>
                                            <td className="px-6 py-4">
                                                <span className={`inline-flex items-center px-3 py-1 rounded-full text-xs font-semibold border ${statusConfig[user.status].color}`}>
                                                    {statusConfig[user.status].label}
                                                </span>
                                            </td>
                                            <td className="px-6 py-4">
                                                <div className="flex justify-end gap-2">
                                                    {/* Edit Button for Active Users */}
                                                    <button 
                                                        onClick={() => setEditingUser(user)}
                                                        className="p-2 text-blue-600 hover:bg-blue-50 rounded-lg transition-colors border border-transparent hover:border-blue-100"
                                                        title="Edit User"
                                                    >
                                                        <Edit2 size={16} />
                                                    </button>

                                                    {user.status === 'pending' && (
                                                        <>
                                                            <button
                                                                onClick={() => updateUserStatus(user.id, 'rejected')}
                                                                disabled={actionLoading === user.id}
                                                                className="p-2 text-red-600 hover:bg-red-50 rounded-lg transition-colors disabled:opacity-50"
                                                                title="Tolak"
                                                            >
                                                                <X size={18} />
                                                            </button>
                                                            <button
                                                                onClick={() => updateUserStatus(user.id, 'active')}
                                                                disabled={actionLoading === user.id}
                                                                className="inline-flex items-center gap-1.5 px-4 py-2 rounded-xl bg-emerald-500 text-white font-medium text-sm hover:bg-emerald-600 transition-colors disabled:opacity-50"
                                                            >
                                                                <Check size={16} />
                                                                Setujui
                                                            </button>
                                                        </>
                                                    )}
                                                    {user.status === 'active' && (
                                                        <button
                                                            onClick={() => updateUserStatus(user.id, 'rejected')}
                                                            disabled={actionLoading === user.id}
                                                            className="p-2 text-red-600 hover:bg-red-50 rounded-lg transition-colors disabled:opacity-50"
                                                            title="Nonaktifkan"
                                                        >
                                                            <Shield size={16} />
                                                        </button>
                                                    )}
                                                    {user.status === 'rejected' && (
                                                        <button
                                                            onClick={() => updateUserStatus(user.id, 'active')}
                                                            disabled={actionLoading === user.id}
                                                            className="inline-flex items-center gap-1.5 px-4 py-2 rounded-xl border border-emerald-200 text-emerald-600 font-medium text-sm hover:bg-emerald-50 transition-colors disabled:opacity-50"
                                                        >
                                                            <Check size={16} />
                                                            Aktifkan
                                                        </button>
                                                    )}
                                                </div>
                                            </td>
                                        </tr>
                                    );
                                })}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>

            {/* Render Edit Modal */}
            {editingUser && (
                <EditUserModal 
                    user={editingUser} 
                    onClose={() => setEditingUser(null)} 
                    onSave={handleSaveUser}
                    isLoading={actionLoading === editingUser.id}
                />
            )}
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';
import { BuilderLayout } from '@/components/builder/BuilderLayout';
import { Trash2, ExternalLink, Clock, ChevronDown, ChevronUp, BarChart3 } from 'lucide-react';

interface SavedDashboard {
  id: string;
  name: string;
  description: string | null;
  slug: string;
  created_at: string;
}

export default function DashboardBuilderPage() {
  const [savedDashboards, setSavedDashboards] = useState<SavedDashboard[]>([]);
  const [savedExpanded, setSavedExpanded] = useState(false);

  useEffect(() => {
    fetchDashboards();
  }, []);

  const fetchDashboards = async () => {
    try {
      const res = await fetch('/api/dashboards');
      if (res.ok) {
        const data = await res.json();
        setSavedDashboards(data.dashboards || []);
      }
    } catch { /* ignore */ }
  };

  const handleSave = async (name: string, description: string, tiles: any[], config?: any) => {
    try {
      const response = await fetch('/api/dashboards', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          name,
          description,
          charts: tiles.map((t, i) => ({
            title: t.title,
            chartType: t.chartType,
            dataField: t.dataField || 'custom',
            width: t.width || 'half',
            position: i,
            query_config: t.query_config,
            visualization_config: t.visualization_config,
            layout: t.layout,
            page_name: t.page_name || 'Ringkasan Umum',
          })),
          config: config || { dateRange: '7d', autoRefresh: true, theme: 'dark' },
        }),
      });

      if (!response.ok) {
        const error = await response.json();
        throw new Error(error.error || 'Failed to save');
      }

      const result = await response.json();
      fetchDashboards();
      return { embedUrl: result.dashboard.embedUrl };
    } catch (err) {
      console.error('Failed to save dashboard:', err);
      return null;
    }
  };

  const handleDelete = async (id: string) => {
    try {
      const res = await fetch(`/api/dashboards?id=${id}`, { method: 'DELETE' });
      if (res.ok) {
        setSavedDashboards(prev => prev.filter(d => d.id !== id));
      }
    } catch { /* ignore */ }
  };

  return (
    <div
      className="fixed inset-0 flex flex-col bg-[var(--surface-1)] md:left-[260px]"
      style={{ zIndex: 10 }}
    >
      {/* Builder — takes remaining space, scrolls internally */}
      <div className="flex-1 min-h-0 overflow-hidden">
        <BuilderLayout onSaveDashboard={handleSave} />
      </div>

      {/* Saved Dashboards — fixed at bottom, collapsible */}
      {savedDashboards.length > 0 && (
        <div className="shrink-0 border-t border-[var(--surface-4)] bg-[var(--surface-1)]">
          {/* Collapsible header */}
          <button
            onClick={() => setSavedExpanded(!savedExpanded)}
            className="w-full flex items-center justify-between px-6 py-3 hover:bg-[var(--surface-2)] transition-colors"
          >
            <div className="flex items-center gap-2">
