    const handleReset = () => {
        setSelectedHub('all');
        setSelectedBranch('all');
        setSelectedMaskapai('all');
        setSelectedAirlines('all');
        setSelectedCategory('all');
        setSelectedArea('all');
    };

    return (
        <div className="p-6 space-y-6 min-h-screen bg-[var(--surface-1)] text-[var(--text-primary)] font-sans">
            {/* Top Header */}
