                    {/* Share removed as per previous task */}
                    <button className="p-2 rounded-full border border-[var(--border-subtle)] hover:bg-[var(--surface-2)] transition-colors">
                        <MoreVertical size={16} />
                    </button>
                </div>
            </div>

            {/* Main Content Card */}
            <GlassCard className="space-y-6" padding="lg">
                <div className="flex justify-between items-start">
                    <div className="flex items-center gap-4">
                         {/* Logo Placeholder */}
                        <div className="w-16 h-16 bg-green-100 rounded-lg flex items-center justify-center text-green-600 font-bold text-xs uppercase text-center border-2 border-green-500">
                             Gapura<br/>Logo
                        </div>
                        <div>
                            <h2 className="text-3xl font-bold text-[var(--brand-primary)]">Landside & Airside Customer Feedback</h2>
                             <div className="flex items-center gap-2 mt-2 bg-green-500 text-white px-3 py-1 rounded w-fit">
                                <span className="font-semibold">Irregularity, Complain & Compliment Report</span>
                            </div>
                        </div>
                    </div>

                    {/* Date Range Picker Placeholder */}
                     <div className="bg-white border text-black border-gray-200 rounded-md px-4 py-2 flex items-center gap-2 min-w-[200px]">
                        <Calendar size={16} className="text-gray-500"/>
                        <span className="text-sm">Select date range</span>
                    </div>
                </div>

                {/* Filters Row */}
                <div className="grid grid-cols-3 gap-4">
                    <PrismSelect label="HUB Area" options={options.hub} value={selectedHub} onChange={setSelectedHub} placeholder="Select HUB" />
                    <PrismSelect label="Branch / Station" options={options.branch} value={selectedBranch} onChange={setSelectedBranch} placeholder="Select Branch" />
                    <PrismSelect label="Domestic / International" options={options.airline_type} value={selectedMaskapai} onChange={setSelectedMaskapai} placeholder="Select Type" />
                    <PrismSelect label="Airlines Name" options={options.airline} value={selectedAirlines} onChange={setSelectedAirlines} placeholder="Select Airline" />
                    <PrismSelect label="Case Category" options={options.main_category} value={selectedCategory} onChange={setSelectedCategory} placeholder="Select Category" />
                    <PrismSelect label="Operational Area" options={options.area} value={selectedArea} onChange={setSelectedArea} placeholder="Select Area" />
                </div>

                {/* KPI/Stats Row */}
                <div className="grid grid-cols-4 gap-6 text-center border-t border-b border-[var(--border-subtle)] py-6">
                    <div>
                        <div className="text-sm text-[var(--text-secondary)] mb-1">Report</div>
                        <div className="text-4xl font-bold text-[var(--brand-primary)]">427</div>
                    </div>
                    <div>
                         <div className="text-sm text-[var(--text-secondary)] mb-1">Branch</div>
                        <div className="text-4xl font-bold text-[var(--brand-primary)]">27</div>
                    </div>
                     <div>
                         <div className="text-sm text-[var(--text-secondary)] mb-1">Airlines</div>
                        <div className="text-4xl font-bold text-[var(--brand-primary)]">33</div>
                    </div>
                     <div>
                         <div className="text-sm text-[var(--text-secondary)] mb-1">Compliment Report</div>
                        <div className="text-4xl font-bold text-[var(--brand-primary)]">18</div>
                    </div>
                </div>

                {/* Charts Area */}
                <CustomerFeedbackDashboardCharts 
                    filters={{
                        hub: selectedHub,
                        branch: selectedBranch,
                        maskapai: selectedMaskapai,
                        airlines: selectedAirlines,
                        category: selectedCategory,
                        area: selectedArea
                    }}
                />


                {/* Detail Table Placeholder */}
                 <div className="min-h-[200px] flex items-center justify-center border-2 dashed border-[var(--border-subtle)] rounded-xl bg-[var(--surface-2)]">
                    <p className="text-[var(--text-muted)]">Collapsible Detail Table will be rendered here...</p>
                </div>

            </GlassCard>
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import {
    Plane, MapPin, Building2, AlertTriangle, CheckCircle, ChevronRight, ArrowLeft,
    Loader2, Wrench, Package, MessageSquare, Clock, Calendar,
    ToggleLeft, ToggleRight, FileText, Gauge, Link, Plus, X
} from 'lucide-react';
import { WizardStep } from '@/components/ui/WizardStep';
import { IRREGULARITY_CATEGORIES, AREA_TYPES, routeReportToDivision } from '@/lib/constants/irregularity-types';
import { PRIORITY_CONFIG, type ReportPriority } from '@/lib/constants/report-status';
import { AIRLINES } from '@/lib/constants/airlines';

const REPORT_CATEGORIES = [
    { id: 'Irregularity', label: 'Irregularity' },
    { id: 'Complaint', label: 'Complaint' },
    { id: 'Compliment', label: 'Compliment' },
];

const AREA_OPTIONS = [
    { id: 'TERMINAL', label: 'Terminal Area' },
    { id: 'APRON', label: 'Apron Area' },
    { id: 'GENERAL', label: 'General' },
];

const AREA_CATEGORIES: Record<string, string[]> = {
    'TERMINAL': [
        'Passenger, Baggage & Document Profiling',
        'Boarding Management',
        'Baggage/Special/Irregularities Handling',
        'Accuracy & Completeness of Service',
        'Procedure Competencies',
        'Cleanliness Table',
        'Avoids taking initiative to help',
        'Lack communication skills',
        'Other'
    ],
    'APRON': [
        'Preparation Before ETA',
        'Flight Document Handling',
        'The Availability of GSE',
        'Accurancy & Completeness of Service (Apron)',
        'Qualified Competencies (Apron)',
        'Procedure Competencies',
        'Cleanliness of GSE',
        'Prompt Service and Certainty',
        'Specific Needs of Customers',
        'Other'
    ],
    'GENERAL': ['Other']
};

// Airlines considered local (Indonesian carriers)
const LOKAL_AIRLINE_CODES = ['GA', 'QG', 'JT', 'ID', 'IW', 'IU', 'QZ', 'SJ', 'IN', 'IP', '8B', 'SI', 'IL'];

function getAirlineType(airlineName: string): 'Lokal' | 'MPA' {
    const airline = AIRLINES.find(a => a.name === airlineName);
    if (!airline) return 'MPA';
    return LOKAL_AIRLINE_CODES.includes(airline.code) ? 'Lokal' : 'MPA';
}

function getHubForStation(stationCode: string): string {
    if (['CGK', 'SUB', 'DPS'].includes(stationCode)) return stationCode;
    if (['UPG', 'MDC', 'BPN'].includes(stationCode)) return 'UPG';
    if (['KNO', 'PDG', 'PKU', 'BTH', 'PLM'].includes(stationCode)) return 'KNO';
    return 'CGK';
}

function getWeekInMonth(date: Date): number {
    const day = date.getDate();
    return Math.ceil(day / 7);
}

type FormData = {
    // Step 1: Detail Report
    incident_date: string;
    airline: string;
    flight_number: string;
    station_id: string; // Branch
    route: string;
    main_category: string; // Irregularity/Complaint/Compliment

    // Step 2: Area
    area: string;

    // Step 3: Area Category
    area_category: string;

    // Step 4: Report Details
    description: string; // "Report"
    root_cause: string;
    action_taken: string;
    severity: ReportPriority; // Replacing SLA

    // Step 5: Evidence
    reporter_name: string;
    evidence_urls: string[];
};

export default function NewReportWizard() {
    const router = useRouter();
    const [step, setStep] = useState(1);
    const [loading, setLoading] = useState(false);
    const [success, setSuccess] = useState(false);
    const [error, setError] = useState('');
    const [userStation, setUserStation] = useState<{ id: string; code: string; name: string } | null>(null);
    const [stations, setStations] = useState<Array<{ id: string; code: string; name: string }>>([]);
    const [selectedStationId, setSelectedStationId] = useState<string>('');
    const [newLinkInput, setNewLinkInput] = useState('');

    const [formData, setFormData] = useState<FormData>({
        incident_date: new Date().toISOString().split('T')[0],
        airline: '',
        flight_number: '',
        station_id: '',
        route: '',
        main_category: 'Irregularity', // Default
        
        area: '',
        area_category: '',
        
        description: '',
        root_cause: '',
        action_taken: '',
        severity: 'medium',
        
        reporter_name: '',
        evidence_urls: [],
    });

    // Fetch user's station and all stations on mount
    useEffect(() => {
        const fetchData = async () => {
            try {
                // Fetch all stations
                const stationsRes = await fetch('/api/master-data?type=stations');
                const stationsData = await stationsRes.json();
                if (Array.isArray(stationsData)) {
                    setStations(stationsData);
                }

                // Fetch user's station as default
                const userRes = await fetch('/api/auth/me');
                if (userRes.ok) {
                    const userData = await userRes.json();
                    if (userData.station) {
                        setUserStation(userData.station);
                        setSelectedStationId(userData.station.id); // Set default to user's station
                    }
                }
            } catch (err) {
                console.error('Failed to fetch data:', err);
            }
        };
        fetchData();
    }, []);

    // Hide mobile bottom navigation on this page
    useEffect(() => {
        const hideMobileNav = () => {
            const mobileNav = document.querySelector('[data-hide-mobile-nav]');
            if (mobileNav) {
                (mobileNav as HTMLElement).style.display = 'none';
            }
        };

        hideMobileNav();

        // Show mobile nav when leaving the page
        return () => {
            const mobileNav = document.querySelector('[data-hide-mobile-nav]');
            if (mobileNav) {
                (mobileNav as HTMLElement).style.display = '';
            }
        };
    }, []);

    const handleAddLink = () => {
        const link = newLinkInput.trim();
        if (!link) return;

        if (formData.evidence_urls.length >= 3) {
            setError('Maksimal 3 link');
            return;
        }

        try {
            new URL(link);
        } catch {
            setError('Link tidak valid. Pastikan format URL benar (contoh: https://drive.google.com/...)');
            return;
        }

        setError('');
        setFormData(prev => ({
            ...prev,
            evidence_urls: [...prev.evidence_urls, link],
        }));
        setNewLinkInput('');
    };

    const removeLink = (index: number) => {
        setFormData(prev => ({
            ...prev,
            evidence_urls: prev.evidence_urls.filter((_, i) => i !== index),
        }));
    };

    const nextStep = () => setStep(prev => Math.min(prev + 1, 5));
    const prevStep = () => setStep(prev => Math.max(prev - 1, 1));

    const isStepValid = (): boolean => {
        switch (step) {
            case 1:
                return !!(formData.incident_date && formData.airline && formData.flight_number && selectedStationId && formData.route && formData.main_category);
            case 2:
                return !!formData.area;
            case 3:
                return !!formData.area_category;
            case 4:
                return !!(formData.description && formData.root_cause && formData.action_taken);
            case 5:
                return !!(formData.reporter_name && formData.evidence_urls.length > 0);
            default:
                return false;
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError('');

        try {
            // Derive auto-populated fields
            const selectedStation = stations.find(s => s.id === selectedStationId);
            const stationCode = selectedStation?.code || '';
            const eventDate = new Date(formData.incident_date);

            const res = await fetch('/api/reports', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    ...formData,
                    title: `${formData.airline} ${formData.flight_number} - ${formData.main_category}`,
                    station_id: selectedStationId,
                    sub_category: formData.area_category,
                    // New CSV-aligned fields
                    station_code: stationCode,
                    hub: getHubForStation(stationCode),
                    airline_type: getAirlineType(formData.airline),
                    report_content: formData.description,
                    reporting_branch: stationCode,
                    week_in_month: getWeekInMonth(eventDate),
                    reporter_email: undefined,
                    form_submitted_at: new Date().toISOString(),
                    form_completed_at: new Date().toISOString(),
                }),
            });

            if (!res.ok) {
                const data = await res.json();
                throw new Error(data.error || 'Gagal mengirim laporan');
            }

            setSuccess(true);
            setTimeout(() => {
                router.push('/dashboard/employee');
            }, 3000);
        } catch (err: any) {
            setError(err.message || 'Terjadi kesalahan');
        } finally {
            setLoading(false);
        }
    };

    const selectedCategory = IRREGULARITY_CATEGORIES.find(c => c.id === 'IRREGULARITY'); // Dummy default to allow build

    if (success) {
        return (
            <div className="flex items-center justify-center min-h-[80vh]">
                <div className="text-center animate-scale-in p-12 card-glass max-w-lg mx-auto">
                    <div className="w-28 h-28 bg-emerald-100/50 rounded-full flex items-center justify-center mx-auto mb-8 ring-8 ring-emerald-50/50 animate-bounce">
                        <CheckCircle className="w-16 h-16 text-emerald-600" />
                    </div>
                    <h2 className="text-4xl font-bold mb-4" style={{ color: 'var(--text-primary)' }}>Laporan Terkirim!</h2>
                    <p className="text-lg mb-8" style={{ color: 'var(--text-secondary)' }}>
                        Terima kasih atas kontribusi Anda dalam menjaga kualitas dan keselamatan operasional.
                    </p>
                    <p className="text-sm font-medium animate-pulse" style={{ color: 'var(--brand-primary)' }}>
                        Mengalihkan ke dashboard...
                    </p>
                </div>
            </div>
        );
    }

    return (
        <div className="max-w-5xl mx-auto space-y-8 pb-32 md:pb-8 pt-8">
            {/* Header */}
            <div className="text-center space-y-2 animate-fade-in-up px-4">
                <h1 className="text-2xl md:text-3xl font-bold tracking-tight">Buat Laporan Irregularity</h1>
                <p className="text-base md:text-lg" style={{ color: 'var(--text-secondary)' }}>
                    Langkah {step} dari 5
                </p>
            </div>

            {/* Progress Bar */}
            <div className="px-4">
                <div className="flex items-center gap-2 max-w-md mx-auto">
                    {[1, 2, 3, 4, 5].map((s) => (
                        <div key={s} className="flex-1 flex items-center">
                            <div 
                                className={`h-2 flex-1 rounded-full transition-all ${s <= step ? 'bg-emerald-500' : 'bg-slate-200'}`}
                            />
                        </div>
                    ))}
                </div>
                <div className="flex justify-between max-w-md mx-auto mt-2 text-xs font-medium" style={{ color: 'var(--text-muted)' }}>
                    <span>Detail</span>
                    <span>Area</span>
                    <span>Kategori</span>
                    <span>Isi</span>
                    <span>Bukti</span>
                </div>
            </div>

            {error && (
                <div className="mx-auto max-w-2xl p-4 rounded-xl flex items-center gap-3 animate-fade-in-up" style={{ background: 'oklch(0.60 0.22 25 / 0.1)', color: 'oklch(0.55 0.18 25)' }}>
                    <AlertTriangle className="w-5 h-5 flex-shrink-0" />
                    <p>{error}</p>
                </div>
            )}

            <form onSubmit={handleSubmit} className="min-h-[400px]">
                {/* Step 1: Detail Report */}
                <WizardStep isActive={step === 1}>
                    <div className="max-w-3xl mx-auto space-y-8">
                        <div className="text-center space-y-2">
                            <h2 className="text-2xl font-bold">Detail Report</h2>
                            <p style={{ color: 'var(--text-secondary)' }}>Lengkapi informasi dasar penerbangan</p>
                        </div>

                        <div className="card-solid p-6 md:p-8 space-y-6" style={{ background: 'var(--surface-2)' }}>
                            {/* Date of Event */}
                            <div className="space-y-2">
                                <label className="label flex items-center gap-2">
                                    <Calendar className="w-4 h-4" />
                                    1. Date of Event <span className="text-red-500">*</span>
                                </label>
                                <input
                                    type="date"
                                    required
                                    max={new Date().toISOString().split('T')[0]}
                                    className="input-field"
                                    value={formData.incident_date}
                                    onChange={e => setFormData({ ...formData, incident_date: e.target.value })}
                                />
                            </div>

                            {/* Airlines */}
                            <div className="space-y-2">
                                <label className="label">2. Airlines <span className="text-red-500">*</span></label>
                                <select
                                    required
                                    className="input-field"
                                    value={formData.airline}
                                    onChange={e => setFormData({ ...formData, airline: e.target.value })}
                                >
                                    <option value="">Select Airline...</option>
                                    {AIRLINES.map((airline) => (
                                        <option key={airline.code} value={airline.name}>
                                            {airline.name} ({airline.code})
                                        </option>
                                    ))}
                                </select>
                            </div>

                            {/* Flight Number */}
                            <div className="space-y-2">
                                <label className="label">3. Flight Number <span className="text-red-500">*</span></label>
                                <input
                                    type="text"
                                    required
                                    className="input-field uppercase"
                                    placeholder="e.g. CZ-123"
                                    value={formData.flight_number}
                                    onChange={e => setFormData({ ...formData, flight_number: e.target.value })}
                                />
                            </div>

                            {/* Branch */}
                            <div className="space-y-2">
                                <label className="label">4. Branch (cth: CGK, UPG, DPS) <span className="text-red-500">*</span></label>
                                <select
                                    required
                                    className="input-field"
                                    value={selectedStationId}
                                    onChange={e => setSelectedStationId(e.target.value)}
                                >
                                    <option value="">Select Branch...</option>
                                    {stations.map((station) => (
                                        <option key={station.id} value={station.id}>
                                            {station.code} - {station.name}
                                        </option>
                                    ))}
                                </select>
                            </div>

                            {/* Route */}
                            <div className="space-y-2">
                                <label className="label">5. Route <span className="text-red-500">*</span></label>
                                <input
                                    type="text"
                                    required
                                    className="input-field uppercase"
                                    placeholder="e.g. NRT-CGK"
                                    value={formData.route}
                                    onChange={e => setFormData({ ...formData, route: e.target.value })}
                                />
                            </div>

                             {/* Report Category */}
                             <div className="space-y-2">
                                <label className="label">6. Report Category <span className="text-red-500">*</span></label>
                                <div className="flex flex-col gap-3">
                                    {REPORT_CATEGORIES.map((cat) => (
                                        <button
                                            key={cat.id}
                                            type="button"
                                            onClick={() => setFormData({ ...formData, main_category: cat.id })}
                                            className="flex items-center gap-3 p-3 rounded-lg hover:bg-black/5 transition-colors text-left"
                                        >
                                            <div className={`w-5 h-5 rounded-full border flex items-center justify-center ${formData.main_category === cat.id ? 'border-emerald-500' : 'border-gray-400'}`}>
                                                {formData.main_category === cat.id && (
                                                    <div className="w-3 h-3 rounded-full bg-emerald-500" />
                                                )}
                                            </div>
                                            <span>{cat.label}</span>
                                        </button>
                                    ))}
                                </div>
                            </div>
                        </div>
                    </div>
                </WizardStep>

                {/* Step 2: Area */}
                <WizardStep isActive={step === 2}>
                    <div className="max-w-3xl mx-auto space-y-8">
                        <div className="text-center space-y-2">
                            <h2 className="text-2xl font-bold">Section</h2>
                            <p style={{ color: 'var(--text-secondary)' }}>Choose the area of the incident</p>
                        </div>

                        <div className="card-solid p-6 md:p-8 space-y-6" style={{ background: 'var(--surface-2)' }}>
                            <div className="space-y-4">
                                <label className="label">7. Area <span className="text-red-500">*</span></label>
                                <div className="flex flex-col gap-3">
                                    {AREA_OPTIONS.map((area) => (
                                        <button
                                            key={area.id}
                                            type="button"
                                            onClick={() => setFormData({ ...formData, area: area.id, area_category: '' })}
                                            className="flex items-center gap-3 p-3 rounded-lg hover:bg-black/5 transition-colors text-left"
                                        >
                                            <div className={`w-5 h-5 rounded-full border flex items-center justify-center ${formData.area === area.id ? 'border-emerald-500' : 'border-gray-400'}`}>
                                                {formData.area === area.id && (
                                                    <div className="w-3 h-3 rounded-full bg-emerald-500" />
                                                )}
                                            </div>
                                            <span>{area.label}</span>
                                        </button>
                                    ))}
                                </div>
                            </div>
                        </div>
                    </div>
                </WizardStep>

                {/* Step 3: Area Category */}
                <WizardStep isActive={step === 3}>
                    <div className="max-w-3xl mx-auto space-y-8">
                        <div className="text-center space-y-2">
                            <h2 className="text-2xl font-bold">{AREA_OPTIONS.find(a => a.id === formData.area)?.label}</h2>
                            <p style={{ color: 'var(--text-secondary)' }}>Specify the category for {AREA_OPTIONS.find(a => a.id === formData.area)?.label}</p>
                        </div>

                        <div className="card-solid p-6 md:p-8 space-y-6" style={{ background: 'var(--surface-2)' }}>
                            <div className="space-y-4">
                                <label className="label">8. {AREA_OPTIONS.find(a => a.id === formData.area)?.label} Category <span className="text-red-500">*</span></label>
                                <div className="flex flex-col gap-3">
                                    {AREA_CATEGORIES[formData.area]?.map((cat, idx) => (
                                        <button
                                            key={idx}
                                            type="button"
                                            onClick={() => setFormData({ ...formData, area_category: cat })}
                                            className="flex items-center gap-3 p-3 rounded-lg hover:bg-black/5 transition-colors text-left"
                                        >
                                            <div className={`w-5 h-5 rounded-full border flex items-center justify-center ${formData.area_category === cat ? 'border-emerald-500' : 'border-gray-400'}`}>
                                                {formData.area_category === cat && (
                                                    <div className="w-3 h-3 rounded-full bg-emerald-500" />
                                                )}
                                            </div>
                                            <span>{cat}</span>
                                        </button>
                                    ))}
                                </div>
                            </div>
                        </div>
                    </div>
                </WizardStep>

                {/* Step 4: Report Details */}
                <WizardStep isActive={step === 4}>
                    <div className="max-w-3xl mx-auto space-y-8">
                        <div className="text-center space-y-2">
                            <h2 className="text-2xl font-bold">Irregularity / Complaint</h2>
                            <p style={{ color: 'var(--text-secondary)' }}>Fill in the details</p>
                        </div>

                        <div className="card-solid p-6 md:p-8 space-y-6" style={{ background: 'var(--surface-2)' }}>
                            {/* Report / Description */}
                            <div className="space-y-2">
                                <label className="label">9. Report <span className="text-red-500">*</span></label>
                                <textarea
                                    required
                                    className="input-field min-h-[100px] resize-y"
                                    placeholder="Enter your answer"
                                    value={formData.description}
                                    onChange={e => setFormData({ ...formData, description: e.target.value })}
                                />
                            </div>

                            {/* Root Cause */}
                            <div className="space-y-2">
                                <label className="label">10. Root Cause <span className="text-red-500">*</span></label>
                                <textarea
                                    required
                                    className="input-field min-h-[100px] resize-y"
                                    placeholder="Enter your answer"
                                    value={formData.root_cause}
                                    onChange={e => setFormData({ ...formData, root_cause: e.target.value })}
                                />
                            </div>

                            {/* Action Taken */}
                            <div className="space-y-2">
                                <label className="label">11. Action Taken <span className="text-red-500">*</span></label>
                                <textarea
                                    required
                                    className="input-field min-h-[100px] resize-y"
                                    placeholder="Enter your answer"
                                    value={formData.action_taken}
                                    onChange={e => setFormData({ ...formData, action_taken: e.target.value })}
                                />
                            </div>

                             {/* Severity */}
                             <div className="space-y-2">
                                <label className="label flex items-center gap-2">
                                    <AlertTriangle className="w-4 h-4" />
                                    Severity
                                </label>
                                <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
                                    {(Object.entries(PRIORITY_CONFIG) as [ReportPriority, typeof PRIORITY_CONFIG[ReportPriority]][]).map(([key, config]) => {
                                        const isSelected = formData.severity === key;
                                        return (
                                            <button
                                                key={key}
                                                type="button"
                                                onClick={() => setFormData({ ...formData, severity: key })}
                                                className={`p-3 rounded-xl border-2 transition-all text-center ${
                                                    isSelected ? 'border-current' : 'border-transparent'
                                                }`}
                                                style={{
                                                    background: isSelected ? config.bgColor : 'var(--surface-3)',
                                                    color: isSelected ? config.color : 'var(--text-primary)',
                                                    borderColor: isSelected ? config.color : 'transparent',
                                                }}
                                            >
                                                <span className="font-bold text-sm block">{config.label}</span>
                                            </button>
                                        );
                                    })}
                                </div>
                            </div>
                        </div>
                    </div>
                </WizardStep>

                {/* Step 5: Evidence */}
                <WizardStep isActive={step === 5}>
                    <div className="max-w-3xl mx-auto space-y-8">
                        <div className="text-center space-y-2">
                            <h2 className="text-2xl font-bold">Evidence</h2>
                            <p style={{ color: 'var(--text-secondary)' }}>Lampirkan link Google Drive sebagai bukti</p>
                        </div>

                        <div className="card-solid p-6 md:p-8 space-y-6" style={{ background: 'var(--surface-2)' }}>
                            {/* Report By */}
                            <div className="space-y-2">
                                <label className="label">12. Report By <span className="text-red-500">*</span></label>
                                <input
                                    type="text"
                                    required
                                    className="input-field"
                                    placeholder="Enter your answer"
                                    value={formData.reporter_name}
                                    onChange={e => setFormData({ ...formData, reporter_name: e.target.value })}
                                />
                            </div>

                            {/* Google Drive Link */}
                            <div className="space-y-4">
                                <label className="label">13. Link Google Drive Evidence <span className="text-red-500">*</span></label>

                                {/* Added Links */}
                                {formData.evidence_urls.length > 0 && (
                                    <div className="space-y-2">
                                        {formData.evidence_urls.map((url, idx) => (
                                            <div key={idx} className="flex items-center gap-2 p-3 bg-emerald-50 rounded-xl border border-emerald-200">
                                                <Link className="w-4 h-4 text-emerald-600 shrink-0" />
                                                <a
                                                    href={url}
                                                    target="_blank"
                                                    rel="noopener noreferrer"
                                                    className="text-sm text-emerald-700 hover:underline truncate flex-1"
                                                >
                                                    {url}
                                                </a>
                                                <button
                                                    type="button"
                                                    onClick={() => removeLink(idx)}
                                                    className="p-1 hover:bg-red-100 text-red-500 rounded-lg transition-colors shrink-0"
                                                >
                                                    <X className="w-4 h-4" />
                                                </button>
                                            </div>
                                        ))}
                                    </div>
                                )}

                                {/* Add Link Input */}
                                {formData.evidence_urls.length < 3 && (
                                    <div className="space-y-3">
                                        <div className="flex gap-2">
                                            <input
                                                type="url"
                                                className="input-field flex-1"
                                                placeholder="https://drive.google.com/..."
                                                value={newLinkInput}
                                                onChange={e => setNewLinkInput(e.target.value)}
                                                onKeyDown={e => { if (e.key === 'Enter') { e.preventDefault(); handleAddLink(); } }}
                                            />
                                            <button
                                                type="button"
                                                onClick={handleAddLink}
                                                className="px-4 py-2 bg-emerald-500 text-white rounded-xl font-semibold hover:bg-emerald-600 transition-colors flex items-center gap-1.5"
                                            >
                                                <Plus className="w-4 h-4" />
                                                Tambah
                                            </button>
                                        </div>
                                        <p className="text-xs" style={{ color: 'var(--text-muted)' }}>
                                            Paste link Google Drive (maks. {3 - formData.evidence_urls.length} lagi)
                                        </p>
                                    </div>
                                )}
                            </div>

                        </div>
                    </div>
                </WizardStep>

                {/* Navigation */}
                <div className="fixed bottom-0 left-0 right-0 md:bottom-6 md:right-6 md:left-auto p-4 md:p-0 bg-white/80 backdrop-blur-xl md:bg-transparent border-t md:border-none z-[100] flex items-center justify-between md:justify-end gap-4">
                    <button
                        type="button"
                        onClick={prevStep}
                        className={`btn-secondary h-12 w-12 rounded-full p-0 flex items-center justify-center !shadow-lg bg-white transition-opacity ${step > 1 ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
                    >
                        <ArrowLeft className="w-5 h-5" />
                    </button>
                    
                    {step < 5 ? (
                        <button
                            type="button"
                            onClick={nextStep}
                            disabled={!isStepValid()}
                            className="flex-1 md:flex-none h-12 px-6 rounded-full bg-emerald-500 text-white shadow-lg shadow-emerald-500/30 flex items-center justify-center gap-2 font-bold hover:bg-emerald-600 disabled:opacity-50 disabled:cursor-not-allowed transition-all"
                        >
                            Lanjut
                            <ChevronRight className="w-5 h-5" />
                        </button>
                    ) : (
                        <button
                            type="submit"
                            disabled={!isStepValid() || loading}
                            className="flex-1 md:flex-none h-12 px-6 rounded-full bg-gradient-to-r from-emerald-500 to-teal-500 text-white shadow-lg shadow-emerald-500/30 flex items-center justify-center gap-2 font-bold disabled:opacity-50 disabled:cursor-not-allowed transition-all"
                        >
                            {loading ? (
                                <Loader2 className="w-5 h-5 animate-spin" />
                            ) : (
                                <>
                                    Kirim Laporan
                                    <FileText className="w-5 h-5" />
                                </>
                            )}
                        </button>
                    )}
                </div>

                {/* Step Indicator */}
                <div className="fixed top-20 md:top-24 right-4 md:right-6 z-[100] bg-white/80 backdrop-blur-md px-4 py-2 rounded-full border shadow-sm flex items-center gap-2">
                    <span className="text-sm font-bold">Langkah {step}/4</span>
                </div>
            </form>
        </div>
    );
}

'use client';

import { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { 
    Plus, MapPin, Clock, FileText, RefreshCw, 
    ArrowUpRight, CheckCircle2, AlertCircle, 
    Search, ChevronRight, LayoutDashboard, History
} from 'lucide-react';

import { PrismButton } from '@/components/ui/PrismButton';
import { cn } from '@/lib/utils';
import { STATUS_CONFIG, type ReportStatus } from '@/lib/constants/report-status';
import { CreateReportModal } from '@/components/dashboard/CreateReportModal';
import { ReportDetailModal } from '@/components/dashboard/ReportDetailModal';
import { Report } from '@/types';

export default function EmployeeDashboard() {
    const router = useRouter();
    const [reports, setReports] = useState<Report[]>([]);
    const [loading, setLoading] = useState(true);
    const [greeting, setGreeting] = useState('');
    const [showCreateModal, setShowCreateModal] = useState(false);
    const [selectedReport, setSelectedReport] = useState<Report | null>(null);

    useEffect(() => {
        const hour = new Date().getHours();
        if (hour < 12) setGreeting('Selamat Pagi');
        else if (hour < 15) setGreeting('Selamat Siang');
        else if (hour < 18) setGreeting('Selamat Sore');
        else setGreeting('Selamat Malam');

        fetchReports();
    }, []);

    const fetchReports = async () => {
        try {
            setLoading(true);
            const res = await fetch('/api/reports');
            if (res.ok) {
                const data = await res.json();
                setReports(Array.isArray(data) ? data : []);
            }
        } catch (error) {
            console.error('Error:', error);
            setReports([]);
        } finally {
            setLoading(false);
        }
    };
    
    const fetchStats = async () => {
        // re-fetch to update stats
        await fetchReports();
    }

    const handleReportClick = (report: Report) => {
        setSelectedReport(report);
    }

    // Derived Stats
    const stats = {
        total: reports.length,
        inProgress: reports.filter(r => ['MENUNGGU_FEEDBACK', 'SUDAH_DIVERIFIKASI'].includes(r.status)).length,
        resolved: reports.filter(r => r.status === 'SELESAI').length,
    };

    return (
        <div className="space-y-8 stagger-children pb-24">
            
            {/* Header with Mobile FAB integration */}
            <header className="flex flex-col md:flex-row md:items-center justify-between gap-6 animate-fade-in-up">
                <div>
                    <div className="flex items-center gap-2 mb-2">
                        <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
                        <p className="text-xs font-bold tracking-widest uppercase text-[var(--text-muted)]">
                            Operasional Stasiun
                        </p>
                    </div>
                    <h1 className="text-3xl font-bold tracking-tight text-[var(--text-primary)]">
                        {greeting}, <span className="text-[var(--brand-primary)]">Petugas</span>
                    </h1>
                    <p className="text-[var(--text-secondary)]">
                        Kendali Stasiun &bull; Dasbor Operasional
                    </p>
                </div>
                
                {/* Desktop Actions */}
                <div className="hidden md:flex relative group perspective-1000">
                     <motion.div 
                        animate={{ opacity: [0.2, 0.4, 0.2] }}
                        transition={{ duration: 3, repeat: Infinity }}
                        className="absolute -inset-0.5 bg-gradient-to-r from-emerald-400 to-teal-400 rounded-xl blur opacity-20 group-hover:opacity-60"
                     />
                     <motion.button
                        whileHover={{ scale: 1.05 }}
                        whileTap={{ scale: 0.95 }}
                        transition={{ type: "spring", stiffness: 400, damping: 10 }}
                        onClick={() => setShowCreateModal(true)}
                        className="relative w-full md:w-auto bg-gradient-to-br from-[#022c22] to-[#064e3b] text-white px-6 py-2.5 rounded-xl font-bold text-xs tracking-widest uppercase shadow-xl hover:shadow-emerald-500/20 border border-emerald-500/30 flex items-center gap-2 overflow-hidden ring-1 ring-white/10"
                    >
                        <div className="absolute inset-0 bg-gradient-to-tr from-white/0 via-white/10 to-white/0 skew-x-12 translate-x-[-150%] group-hover:translate-x-[150%] transition-transform duration-700 ease-out" />
                        
                        <div className="bg-emerald-500/20 p-1 rounded-lg">
                            <Plus size={14} className="text-emerald-300" strokeWidth={3} />
                        </div>
                        <span className="bg-clip-text text-transparent bg-gradient-to-r from-emerald-50 via-white to-emerald-100 group-hover:text-white transition-colors relative z-10">
                            Buat Laporan
                        </span>
                    </motion.button>
                </div>
            </header>

            {/* Quick Stats */}
            <div className="bento-grid bento-3">
                <div className="card-solid flex flex-col justify-between group h-full animate-fade-in-up">
                    <div className="flex justify-between items-start">
                        <p className="text-xs font-bold text-[var(--text-secondary)] uppercase tracking-wider">Laporan Saya</p>
                        <FileText size={20} className="text-[var(--text-muted)]" />
                    </div>
                    <div>
                        <p className="text-4xl font-bold text-[var(--text-primary)]">{stats.total}</p>
                        <p className="text-xs text-[var(--text-muted)] mt-1">Total diajukan</p>
                    </div>
                </div>

                <div className="card-solid flex flex-col justify-between group h-full animate-fade-in-up" style={{ animationDelay: '100ms' }}>
                    <div className="flex justify-between items-start">
                        <p className="text-xs font-bold text-[var(--text-secondary)] uppercase tracking-wider">Sedang Proses</p>
                        <History size={20} className="text-[var(--status-warning)]" />
                    </div>
                    <div>
                        <p className="text-4xl font-bold text-[var(--status-warning)]">{stats.inProgress}</p>
                        <div className="h-1 w-full bg-[var(--surface-3)] rounded-full mt-4 overflow-hidden">
                            <div className="h-full bg-amber-500 rounded-full w-[60%]" />
                        </div>
                    </div>
                </div>

                <div className="card-solid flex flex-col justify-between group h-full animate-fade-in-up" style={{ animationDelay: '200ms' }}>
                    <div className="flex justify-between items-start">
                        <p className="text-xs font-bold text-[var(--text-secondary)] uppercase tracking-wider">Selesai</p>
                        <CheckCircle2 size={20} className="text-[var(--status-success)]" />
                    </div>
                    <div>
                        <p className="text-4xl font-bold text-[var(--status-success)]">{stats.resolved}</p>
                        <p className="text-xs text-[var(--text-muted)] mt-1">Berhasil ditangani</p>
                    </div>
                </div>
            </div>

            {/* Data Table View - PREMIUM REDESIGN */}
            <div className="space-y-6">
                <div className="flex items-center justify-between pb-4">
                    <div>
                        <h3 className="text-xl font-bold flex items-center gap-2 text-gray-900">
                            <LayoutDashboard size={24} className="text-[var(--brand-primary)]" />
                            Daftar Laporan
                        </h3>
                        <p className="text-xs text-gray-400 mt-1 font-medium ml-8">
                            Aktivitas dan status laporan terkini
                        </p>
                    </div>
                </div>

                <div className="bg-white/80 backdrop-blur-xl rounded-3xl border border-white/20 shadow-xl overflow-hidden ring-1 ring-black/5">
                    {/* Floating Toolbar inside Card */}
                    <div className="p-5 border-b border-gray-100 flex justify-between items-center bg-white/50">
                        <div className="flex items-center gap-2">
                            <div className="h-2 w-2 rounded-full bg-emerald-500 animate-pulse"/>
                            <span className="text-xs font-bold text-gray-500 uppercase tracking-widest">Live Updates</span>
                        </div>
                        <div className="relative group">
                            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none transition-colors group-focus-within:text-[var(--brand-primary)] text-gray-400">
                                <Search size={16} />
                            </div>
                            <input 
                                type="text" 
                                placeholder="Cari ID, Lokasi, atau Judul..." 
                                className="pl-10 pr-4 py-2.5 bg-gray-50/50 border border-gray-200 rounded-xl text-sm focus:ring-4 focus:ring-[var(--brand-primary)]/10 focus:border-[var(--brand-primary)] outline-none w-72 transition-all hover:bg-white"
                            />
                        </div>
                    </div>

                    <div className="overflow-x-auto">
                        <table className="w-full text-sm text-left">
                            <thead className="bg-gray-50/80 text-[10px] uppercase font-bold text-gray-400 border-b border-gray-100 tracking-wider">
                                <tr>
                                    <th className="px-6 py-4">ID Laporan</th>
                                    <th className="px-6 py-4">Status & Prioritas</th>
                                    <th className="px-6 py-4">Judul & Lokasi</th>
                                    <th className="px-6 py-4">Waktu</th>
                                    <th className="px-6 py-4 text-right">Aksi</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-50 bg-white/40">
                                {reports.length === 0 ? (
                                    <tr>
                                        <td colSpan={5} className="px-6 py-24 text-center text-gray-400">
                                            <div className="flex flex-col items-center gap-4 animate-scale-in">
                                                <div className="w-16 h-16 bg-gray-50 rounded-full flex items-center justify-center shadow-inner">
                                                    <History size={32} className="opacity-30" />
                                                </div>
                                                <p className="font-medium">Belum ada laporan yang diajukan</p>
                                                <button 
                                                    onClick={() => setShowCreateModal(true)}
                                                    className="text-xs text-[var(--brand-primary)] font-bold hover:underline"
                                                >
                                                    + Buat Laporan Baru
                                                </button>
                                            </div>
                                        </td>
                                    </tr>
                                ) : (
                                    reports.map((report, idx) => {
                                        const statusConfig = STATUS_CONFIG[report.status as ReportStatus] || STATUS_CONFIG.MENUNGGU_FEEDBACK;
                                        const severityKey = report.severity || 'medium';
                                        const priorityColor = severityKey === 'urgent' ? 'text-red-600 bg-red-50 border-red-100' : 
                                                            severityKey === 'high' ? 'text-orange-600 bg-orange-50 border-orange-100' : 
                                                            severityKey === 'medium' ? 'text-amber-600 bg-amber-50 border-amber-100' : 
                                                            'text-emerald-600 bg-emerald-50 border-emerald-100';

                                        return (
                                            <tr 
                                                key={report.id} 
                                                className="group hover:bg-gradient-to-r hover:from-white hover:to-gray-50 transition-all cursor-pointer duration-300 ease-out"
                                                onClick={() => handleReportClick(report)}
                                                style={{ animationDelay: `${idx * 50}ms` }}
                                            >
                                                <td className="px-6 py-5">
                                                    <div className="flex items-center gap-3">
                                                        <div className={cn("w-1.5 h-1.5 rounded-full", statusConfig.textClass?.replace('text-', 'bg-'))} />
                                                        <span className="font-mono text-xs font-bold text-gray-500 group-hover:text-[var(--brand-primary)] transition-colors">
                                                            #{report.id.slice(0, 8).toUpperCase()}
                                                        </span>
                                                    </div>
                                                </td>
                                                <td className="px-6 py-5">
                                                    <div className="flex flex-col items-start gap-2">
                                                         <span className={cn(
                                                            "px-2.5 py-1 rounded-lg text-[10px] font-extrabold uppercase tracking-widest border shadow-sm",
                                                            statusConfig.bgClass,
                                                            statusConfig.textClass,
                                                            statusConfig.borderClass
                                                        )}>
                                                            {statusConfig.label}
                                                        </span>
                                                        <div className={cn("text-[9px] font-bold px-2 py-0.5 rounded-md uppercase flex items-center gap-1 border", priorityColor)}>
                                                            <AlertCircle size={8} strokeWidth={3} />
                                                            {severityKey}
                                                        </div>
                                                    </div>
                                                </td>
                                                <td className="px-6 py-5">
                                                    <div className="max-w-[280px]">
                                                        <p className="font-bold text-gray-900 group-hover:text-[var(--brand-primary)] transition-colors mb-1 truncate text-sm">
                                                            {report.title}
                                                        </p>
                                                        <div className="flex items-center gap-2 text-xs text-gray-400">
                                                            <MapPin size={10} />
                                                            <span className="truncate">{report.location || report.stations?.name}</span>
                                                        </div>
                                                    </div>
                                                </td>
                                                <td className="px-6 py-5">
                                                    <div className="flex flex-col text-xs">
                                                        <span className="font-bold text-gray-700">
                                                            {new Date(report.created_at).toLocaleDateString('id-ID', {day: 'numeric', month: 'short'})}
                                                        </span>
                                                        <span className="text-gray-400 text-[10px] font-medium mt-0.5">
                                                            {new Date(report.created_at).toLocaleTimeString('id-ID', {hour: '2-digit', minute: '2-digit'})}
                                                        </span>
                                                    </div>
                                                </td>
                                                <td className="px-6 py-5 text-right">
                                                    <div className="relative flex justify-end">
                                                        <div className="w-8 h-8 rounded-full bg-gray-50 flex items-center justify-center text-gray-300 group-hover:bg-[var(--brand-primary)] group-hover:text-white group-hover:shadow-lg group-hover:shadow-emerald-500/30 transition-all duration-300 transform group-hover:scale-110">
                                                            <ArrowUpRight size={16} />
                                                        </div>
                                                    </div>
                                                </td>
                                            </tr>
                                        );
                                    })
                                )}
                            </tbody>
                        </table>
                    </div>
                </div>
            </div>

            {/* Mobile FAB */}
            <button 
                onClick={() => setShowCreateModal(true)}
                className="md:hidden fixed bottom-6 right-6 w-14 h-14 bg-[var(--brand-primary)] text-white rounded-full shadow-lg flex items-center justify-center z-50 hover:scale-110 active:scale-95 transition-all"
            >
                <Plus size={24} />
            </button>

            {/* Modals */}
            <ReportDetailModal
                isOpen={!!selectedReport}
                onClose={() => setSelectedReport(null)}
                report={selectedReport}
            />

            <CreateReportModal 
                isOpen={showCreateModal}
                onClose={() => setShowCreateModal(false)}
                onSuccess={() => {
                    fetchReports();
                    fetchStats();
                    setShowCreateModal(false);
                }}
            />
        </div>
    );
}

'use client';

import { useState, useEffect, useRef } from 'react';
import { useParams, useRouter } from 'next/navigation';
import {
    ArrowLeft, MapPin, Calendar, Clock, Plane, Wrench, User, Building2,
    AlertCircle, CheckCircle, Loader2, Send, MessageSquare, Link, ExternalLink
} from 'lucide-react';
import { STATUS_CONFIG, canPerformAction, type ReportStatus } from '@/lib/constants/report-status';

import { supabase } from '@/lib/supabase';

interface Report {
    id: string;
    title: string;
    description: string;
    status: ReportStatus;
    target_division: string;
    area: string;
    specific_location: string;
    incident_date: string;
    incident_time: string;
    is_flight_related: boolean;
    flight_number: string | null;
    aircraft_reg: string | null;
    is_gse_related: boolean;
    gse_number: string | null;
    main_category: string;
    sub_category: string;
    immediate_action: string | null;
    evidence_urls: string[] | null;
    partner_evidence_urls: string[] | null;
    partner_response_notes: string | null;
    validation_notes: string | null;
    created_at: string;
    acknowledged_at: string | null;
    started_at: string | null;
    validated_at: string | null;
    users: { id: string; full_name: string; email: string } | null;
    branch: string | null;
    stations: { id: string; code: string; name: string } | null;
    acknowledged_user: { id: string; full_name: string } | null;
    validated_user: { id: string; full_name: string } | null;
    comments: Comment[];
}

interface Comment {
    id: string;
    content: string;
    is_system_message: boolean;
    created_at: string;
    attachments: string[] | null;
    users: { id: string; full_name: string; role: string } | null;
}

interface UserSession {
    id: string;
    role: string;
    division?: string;
}

export default function EmployeeReportDetailPage() {
    const params = useParams();
    const router = useRouter();
    const reportId = params.id as string;

    const [report, setReport] = useState<Report | null>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [user, setUser] = useState<UserSession | null>(null);

    // Comment state
    const [newComment, setNewComment] = useState('');
    const [sendingComment, setSendingComment] = useState(false);
    const commentsEndRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        fetchReport();
        fetchUser();

        const channel = supabase
            .channel(`report-comments-${reportId}`)
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'report_comments',
                    filter: `report_id=eq.${reportId}`,
                },
                () => {
                     fetchReport();
                }
            )
            .subscribe();

        return () => {
            supabase.removeChannel(channel);
        };
    }, [reportId]);

    useEffect(() => {
        commentsEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, [report?.comments]);

    const fetchUser = async () => {
        try {
            const res = await fetch('/api/auth/me');
            if (res.ok) {
                const data = await res.json();
                setUser({ id: data.id, role: data.role, division: data.division });
            }
        } catch (err) {
            console.error('Failed to fetch user:', err);
        }
    };

    const fetchReport = async () => {
        try {
            const res = await fetch(`/api/reports/${reportId}`);
            if (!res.ok) throw new Error('Failed to fetch report');
            const data = await res.json();
            setReport(data);
        } catch (err) {
            setError('Gagal memuat laporan');
        } finally {
            setLoading(false);
        }
    };

    const sendComment = async () => {
        if (!newComment.trim()) return;

        setSendingComment(true);
        try {
            const res = await fetch(`/api/reports/${reportId}/comments`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ content: newComment }),
            });

            if (res.ok) {
                setNewComment('');
                await fetchReport();
            }
        } catch (err) {
            console.error('Failed to send comment:', err);
        } finally {
            setSendingComment(false);
        }
    };

    if (loading) {
        return (
            <div className="flex items-center justify-center min-h-[60vh]">
                <Loader2 className="w-8 h-8 animate-spin text-emerald-500" />
            </div>
        );
    }

    if (!report) {
        return (
            <div className="text-center py-20">
                <AlertCircle className="w-12 h-12 mx-auto mb-4 text-red-500" />
                <p className="text-lg font-medium">Laporan tidak ditemukan</p>
                <button
                    onClick={() => router.push('/dashboard/employee')}
                    className="mt-4 btn-secondary"
                >
                    Kembali ke Dashboard
                </button>
            </div>
        );
    }

    const statusConfig = STATUS_CONFIG[report.status];
    const canComment = user && canPerformAction('comment', report.status, user.role, report.target_division, user.division);

    return (
        <div className="max-w-4xl mx-auto space-y-6 pb-24">
            {/* Header */}
            <div className="flex items-center gap-4">
                <button
                    onClick={() => router.back()}
                    className="p-2 rounded-xl hover:bg-slate-100 transition-colors"
                >
                    <ArrowLeft className="w-5 h-5" />
                </button>
                <div className="flex-1">
                    <h1 className="text-xl font-bold">{report.title}</h1>
                    <p className="text-sm" style={{ color: 'var(--text-muted)' }}>
                        Laporan Anda
                    </p>
                </div>
                <div 
                    className="px-4 py-2 rounded-full font-medium text-sm"
                    style={{ background: statusConfig.bgColor, color: statusConfig.color }}
                >
                    {statusConfig.label}
                </div>
            </div>

            {/* Status Progress */}
            <div className="card-solid p-6" style={{ background: 'var(--surface-2)' }}>
                <h3 className="font-bold mb-4">Status Laporan</h3>
                <div className="flex items-center gap-2">
                    {['OPEN', 'ACKNOWLEDGED', 'ON_PROGRESS', 'WAITING_VALIDATION', 'CLOSED'].map((s, idx) => {
                        const isActive = s === report.status;
                        const isPassed = ['OPEN', 'ACKNOWLEDGED', 'ON_PROGRESS', 'WAITING_VALIDATION', 'CLOSED']
                            .indexOf(report.status) >= idx;
                        return (
                            <div key={s} className="flex-1 flex items-center">
                                <div className={`h-2 flex-1 rounded-full transition-all ${
                                    isPassed ? 'bg-emerald-500' : 'bg-slate-200'
                                }`} />
                            </div>
                        );
                    })}
                </div>
                <p className="text-sm mt-3" style={{ color: 'var(--text-secondary)' }}>
                    {statusConfig.description}
                </p>
            </div>

            {/* Report Details */}
            <div className="card-solid p-6" style={{ background: 'var(--surface-2)' }}>
                <h2 className="font-bold text-lg mb-4">Detail Laporan</h2>

                <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-6">
                    <div className="space-y-1">
                        <p className="text-xs" style={{ color: 'var(--text-muted)' }}>Station</p>
                        <p className="font-medium text-sm">{report.stations?.code || report.branch || '-'}</p>
                    </div>
                    <div className="space-y-1">
                        <p className="text-xs" style={{ color: 'var(--text-muted)' }}>Tanggal</p>
                        <p className="font-medium text-sm">{report.incident_date || '-'}</p>
                    </div>
                    <div className="space-y-1">
                        <p className="text-xs" style={{ color: 'var(--text-muted)' }}>Area</p>
                        <p className="font-medium text-sm">{report.area || '-'}</p>
                    </div>
                    <div className="space-y-1">
                        <p className="text-xs" style={{ color: 'var(--text-muted)' }}>Ditangani oleh</p>
                        <p className="font-bold text-sm" style={{ color: 'var(--brand-primary)' }}>
                            Divisi {report.target_division}
                        </p>
                    </div>
                </div>

                {report.is_flight_related && (
                    <div className="flex items-center gap-4 p-3 rounded-xl bg-blue-50 mb-4">
                        <Plane className="w-5 h-5 text-blue-500" />
                        <div>
                            <p className="text-sm font-medium">Flight: {report.flight_number}</p>
                            {report.aircraft_reg && <p className="text-xs text-blue-600">Reg: {report.aircraft_reg}</p>}
                        </div>
                    </div>
                )}

                {report.is_gse_related && (
                    <div className="flex items-center gap-4 p-3 rounded-xl bg-amber-50 mb-4">
                        <Wrench className="w-5 h-5 text-amber-500" />
                        <p className="text-sm font-medium">GSE: {report.gse_number}</p>
                    </div>
                )}

                <div className="space-y-2 mb-4">
                    <p className="text-sm font-medium">Kronologis:</p>
                    <p className="text-sm leading-relaxed" style={{ color: 'var(--text-secondary)' }}>
                        {report.description}
                    </p>
                </div>

                {report.evidence_urls && report.evidence_urls.length > 0 && (
                    <div className="space-y-2">
                        <p className="text-sm font-medium">Link Bukti:</p>
                        <div className="space-y-2">
                            {report.evidence_urls.map((url, idx) => (
                                <a
                                    key={idx}
                                    href={url}
                                    target="_blank"
                                    rel="noopener noreferrer"
                                    className="flex items-center gap-2 p-3 bg-blue-50 rounded-xl border border-blue-200 hover:bg-blue-100 transition-colors"
                                >
                                    <Link className="w-4 h-4 text-blue-500 shrink-0" />
                                    <span className="text-sm text-blue-700 truncate flex-1">{url}</span>
                                    <ExternalLink className="w-4 h-4 text-blue-400 shrink-0" />
                                </a>
                            ))}
                        </div>
                    </div>
                )}
            </div>

            {/* Partner Response (if any) */}
            {report.partner_evidence_urls && report.partner_evidence_urls.length > 0 && (
                <div className="card-solid p-6 border-2 border-purple-200" style={{ background: 'oklch(0.55 0.22 280 / 0.05)' }}>
                    <h2 className="font-bold text-lg mb-4 flex items-center gap-2">
                        <CheckCircle className="w-5 h-5 text-purple-500" />
                        Tanggapan dari Divisi {report.target_division}
                    </h2>
                    {report.partner_response_notes && (
                        <p className="text-sm mb-4" style={{ color: 'var(--text-secondary)' }}>
                            {report.partner_response_notes}
                        </p>
                    )}
                    <div className="space-y-2">
                        {report.partner_evidence_urls.map((url, idx) => (
                            <a
                                key={idx}
                                href={url}
                                target="_blank"
                                rel="noopener noreferrer"
                                className="flex items-center gap-2 p-3 bg-purple-50 rounded-xl border border-purple-200 hover:bg-purple-100 transition-colors"
                            >
                                <Link className="w-4 h-4 text-purple-500 shrink-0" />
                                <span className="text-sm text-purple-700 truncate flex-1">{url}</span>
                                <ExternalLink className="w-4 h-4 text-purple-400 shrink-0" />
                            </a>
                        ))}
                    </div>
                </div>
            )}

            {/* Timeline */}
            <div className="card-solid p-6" style={{ background: 'var(--surface-2)' }}>
                <h2 className="font-bold text-lg mb-4">Timeline</h2>

                <div className="space-y-4 max-h-[300px] overflow-y-auto pr-2">
                    <div className="flex gap-3">
                        <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center shrink-0">
                            <MessageSquare className="w-4 h-4 text-slate-500" />
                        </div>
                        <div>
                            <p className="text-sm">Anda membuat laporan</p>
                            <p className="text-xs" style={{ color: 'var(--text-muted)' }}>
                                {new Date(report.created_at).toLocaleString('id-ID')}
                            </p>
                        </div>
                    </div>

                    {report.acknowledged_at && (
                        <div className="flex gap-3">
                            <div className="w-8 h-8 rounded-full bg-yellow-100 flex items-center justify-center shrink-0">
                                <CheckCircle className="w-4 h-4 text-yellow-600" />
                            </div>
                            <div>
                                <p className="text-sm">
                                    Laporan diterima oleh <span className="font-medium">{report.acknowledged_user?.full_name}</span>
                                </p>
                                <p className="text-xs" style={{ color: 'var(--text-muted)' }}>
                                    {new Date(report.acknowledged_at).toLocaleString('id-ID')}
                                </p>
                            </div>
                        </div>
                    )}

                    {report.comments?.map((comment) => {
                        const isMe = user && comment.users?.id === user.id;
                        const isSystem = comment.is_system_message;

                        if (isSystem) {
                            return (
                                <div key={comment.id} className="flex justify-center my-2">
                                    <div className="bg-slate-100 rounded-full px-3 py-1 text-xs text-slate-500">
                                        {comment.content}
                                    </div>
                                </div>
                            );
                        }

                        // Own message - right aligned with emerald color
                        if (isMe) {
                            return (
                                <div key={comment.id} className="flex gap-3 justify-end">
                                    <div className="flex-1 max-w-[80%] space-y-1">
                                        <div className="flex items-baseline justify-end gap-2">
                                            <span className="text-[10px]" style={{ color: 'var(--text-muted)' }}>
                                                {new Date(comment.created_at).toLocaleTimeString('id-ID', {hour:'2-digit', minute:'2-digit'})}
                                            </span>
                                            <span className="text-xs font-bold text-emerald-600">Anda</span>
                                        </div>
                                        <div className="bg-emerald-500 text-white p-3 rounded-2xl rounded-tr-none text-sm leading-relaxed">
                                            {comment.content}
                                            {comment.attachments?.map((url, idx) => (
                                                <a key={idx} href={url} target="_blank" rel="noopener noreferrer" className="mt-2 flex items-center gap-1.5 text-xs underline opacity-80 hover:opacity-100">
                                                    <Link className="w-3 h-3 shrink-0" />{url.length > 40 ? url.slice(0, 40) + '...' : url}
                                                </a>
                                            ))}
                                        </div>
                                    </div>
                                    <div className="w-8 h-8 rounded-full bg-emerald-500 flex items-center justify-center shrink-0 text-white text-xs font-bold">
                                        {comment.users?.full_name?.charAt(0)}
                                    </div>
                                </div>
                            );
                        }

                        // Other's message - left aligned
                        return (
                            <div key={comment.id} className="flex gap-3">
                                <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center shrink-0 text-slate-600 text-xs font-bold">
                                    {comment.users?.full_name?.charAt(0)}
                                </div>
                                <div className="flex-1 max-w-[80%] space-y-1">
                                    <div className="flex items-baseline justify-between">
                                        <span className="text-xs font-bold">{comment.users?.full_name}</span>
                                        <span className="text-[10px]" style={{ color: 'var(--text-muted)' }}>
                                            {new Date(comment.created_at).toLocaleTimeString('id-ID', {hour:'2-digit', minute:'2-digit'})}
                                        </span>
                                    </div>
                                    <div className="bg-white border border-slate-200 p-3 rounded-2xl rounded-tl-none text-sm leading-relaxed">
                                        {comment.content}
                                        {comment.attachments?.map((url, idx) => (
                                            <img key={idx} src={url} className="mt-2 rounded-lg max-h-32 border" />
                                        ))}
                                    </div>
                                </div>
                            </div>
                        );
                    })}
                    <div ref={commentsEndRef} />
                </div>

                {/* Comment Input */}
                {canComment && (
                    <div className="mt-4 pt-4 border-t flex gap-2">
                        <input
                            type="text"
                            placeholder="Balas atau tambah informasi..."
                            className="input-field flex-1"
                            value={newComment}
                            onChange={(e) => setNewComment(e.target.value)}
                            onKeyPress={(e) => e.key === 'Enter' && sendComment()}
                        />
                        <button
                            onClick={sendComment}
                            disabled={sendingComment || !newComment.trim()}
                            className="btn-primary px-4"
                        >
                            {sendingComment ? <Loader2 className="w-4 h-4 animate-spin" /> : <Send className="w-4 h-4" />}
                        </button>
                    </div>
                )}
            </div>
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';
import { type Report } from '@/types';
import { ReportMasterDetail } from '@/components/dashboard/ReportMasterDetail';

export default function EmployeeReportsPage() {
    const [reports, setReports] = useState([]);
    const [loading, setLoading] = useState(true);

    const fetchReports = async () => {
        setLoading(true);
        try {
            // For employee, we want their own reports. 
            // Usually /api/reports returns reports for the user if they are basic user?
            // Or we might need a specific endpoint like /api/reports/me or query param
            // Let's assume /api/reports filters by user if not admin. 
            // If /api/reports returns all for admin, we might need to check the API implementation.
            // But for now, let's try /api/reports.
            const res = await fetch('/api/reports?filter=mine'); // Adding hint just in case
            if (res.ok) {
                const data = await res.json();
                // Filter client side if API doesn't support it yet to be safe, 
                // but ideally API handles it.
                // For now, let's assume the API returns what the user is allowed to see.
                setReports(data || []);
            }
        } catch (error) {
            console.error('Failed to fetch reports:', error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchReports();
    }, []);

    return (
        <ReportMasterDetail 
            title="Laporan Saya" 
            reports={reports} 
            loading={loading}
            // Employee usually can't update status directly from here unless permitted
            // Keeping it undefined implies read-only status in the view
            userRole="CABANG"
        />
    );
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import {
    Clock, CheckCircle2, FileText, RefreshCw, Loader2,
    Plane, ClipboardList
} from 'lucide-react';

import { STATUS_CONFIG, type ReportStatus } from '@/lib/constants/report-status';
import { NoiseTexture } from '@/components/ui/NoiseTexture';
import { cn } from '@/lib/utils';
import { Report } from '@/types';
import { ReportDetailModal } from '@/components/dashboard/ReportDetailModal';

// Division Configuration
const DIVISION_CONFIG = {
    code: 'OP',
    name: 'Operasi',
    color: '#06b6d4', // Cyan
    gradient: 'from-cyan-500 via-cyan-600 to-teal-600',
    bgLight: 'bg-cyan-50',
    textColor: 'text-cyan-600',
};

export default function OPDashboard() {
    const [reports, setReports] = useState<Report[]>([]);
    const [selectedReport, setSelectedReport] = useState<Report | null>(null);
    const [loading, setLoading] = useState(true);
    const [currentTime, setCurrentTime] = useState(new Date());

    useEffect(() => {
        const timer = setInterval(() => setCurrentTime(new Date()), 1000);
        return () => clearInterval(timer);
    }, []);

    const fetchData = useCallback(async () => {
        setLoading(true);
        try {
            const res = await fetch('/api/admin/reports');
            if (res.ok) {
                const data = await res.json();
                // Temporarily show all reports (no division filter)
                setReports(Array.isArray(data) ? data : []);
            }
        } catch (err) {
            console.error('Failed to fetch data:', err);
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        fetchData();
    }, [fetchData]);

    const pendingCount = reports.filter(r => r.status === 'MENUNGGU_FEEDBACK').length;
    const resolvedCount = reports.filter(r => r.status === 'SELESAI').length;
    const totalCount = reports.length;

    if (loading) {
        return (
            <div className="min-h-[60vh] flex flex-col items-center justify-center space-y-4">
                <div className="relative">
                    <div className={`absolute inset-0 ${DIVISION_CONFIG.bgLight} rounded-full blur-xl animate-pulse`} />
                    <Loader2 className={`w-12 h-12 animate-spin ${DIVISION_CONFIG.textColor} relative`} />
                </div>
                <p className="text-[var(--text-secondary)] tracking-widest uppercase text-xs font-bold">
                    Loading {DIVISION_CONFIG.name}...
                </p>
            </div>
        );
    }

    return (
        <div className="space-y-6 pb-24 stagger-children">
            <header className={`relative overflow-hidden rounded-3xl p-8 lg:p-10 animate-fade-in-up bg-gradient-to-br ${DIVISION_CONFIG.gradient}`}>
                <NoiseTexture />
                <div className="absolute -top-20 -right-20 w-60 h-60 bg-white/10 rounded-full blur-2xl" />

                <div className="relative z-10 flex flex-col lg:flex-row lg:items-center justify-between gap-6">
                    <div>
                        <div className="flex items-center gap-3 mb-4">
                            <span className="flex items-center gap-2 px-3 py-1.5 rounded-full bg-white/20 border border-white/30">
                                <Plane size={14} className="text-white" />
                                <span className="text-white text-xs font-bold uppercase tracking-wider">{DIVISION_CONFIG.code}</span>
                            </span>
                            <span className="text-white/70 text-sm font-mono">
                                {currentTime.toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit' })}
                            </span>
                        </div>
                        <h1 className="text-3xl lg:text-4xl font-bold tracking-tight text-white mb-2">
                            Dashboard {DIVISION_CONFIG.name}
                        </h1>
                        <p className="text-white/80 text-sm">Kelola laporan operasional penerbangan</p>
                    </div>

                    <button onClick={fetchData} className="inline-flex items-center gap-2 px-4 py-2.5 rounded-xl text-sm font-bold transition-all bg-white/20 hover:bg-white/30 text-white border border-white/30">
                        <RefreshCw size={16} /> Refresh
                    </button>
                </div>

                <div className="relative z-10 grid grid-cols-3 gap-4 mt-8 pt-6 border-t border-white/20">
                    <MiniStat icon={FileText} label="Total" value={totalCount} />
                    <MiniStat icon={Clock} label="Pending" value={pendingCount} highlight />
                    <MiniStat icon={CheckCircle2} label="Selesai" value={resolvedCount} />
                </div>
            </header>

            <div className="card-solid p-0 overflow-hidden animate-fade-in-up">
                <div className={`p-6 border-b border-[var(--surface-4)] ${DIVISION_CONFIG.bgLight}`}>
                    <div className="flex items-center gap-3">
                        <ClipboardList size={20} className={DIVISION_CONFIG.textColor} />
                        <div>
                            <h3 className="font-bold text-lg text-[var(--text-primary)]">Laporan Divisi {DIVISION_CONFIG.code}</h3>
                            <p className="text-xs text-[var(--text-muted)]">{totalCount} laporan total</p>
                        </div>
                    </div>
                </div>

                <div className="overflow-x-auto">
                    <table className="w-full">
                        <thead>
                            <tr className="border-b border-[var(--surface-4)]">
                                <th className="text-left text-xs font-bold uppercase tracking-wider text-[var(--text-muted)] p-4">ID</th>
                                <th className="text-left text-xs font-bold uppercase tracking-wider text-[var(--text-muted)] p-4">Judul</th>
                                <th className="text-left text-xs font-bold uppercase tracking-wider text-[var(--text-muted)] p-4">Status</th>
                                <th className="text-left text-xs font-bold uppercase tracking-wider text-[var(--text-muted)] p-4">Stasiun</th>
                                <th className="text-left text-xs font-bold uppercase tracking-wider text-[var(--text-muted)] p-4">Tanggal</th>
                            </tr>
                        </thead>
                        <tbody>
                            {reports.length === 0 ? (
                                <tr><td colSpan={5} className="p-8 text-center text-[var(--text-muted)]">Tidak ada laporan untuk divisi {DIVISION_CONFIG.name}</td></tr>
                            ) : (
                                reports.map((r) => (
                                    <tr key={r.id} className="border-b border-[var(--surface-4)] hover:bg-[var(--surface-2)] transition-colors cursor-pointer" onClick={() => setSelectedReport(r)}>
                                        <td className="p-4 font-mono text-sm">{r.id.slice(0, 8)}</td>
                                        <td className="p-4 text-sm font-medium text-[var(--text-primary)] max-w-[300px] truncate">{r.title}</td>
                                        <td className="p-4">
                                            <span className="px-2 py-1 rounded-full text-[10px] font-bold uppercase" style={{ color: STATUS_CONFIG[r.status as ReportStatus]?.color, backgroundColor: STATUS_CONFIG[r.status as ReportStatus]?.bgColor }}>
                                                {STATUS_CONFIG[r.status as ReportStatus]?.label || r.status}
                                            </span>
                                        </td>
                                        <td className="p-4 text-sm text-[var(--text-secondary)]">{r.stations?.code || r.branch || '-'}</td>
                                        <td className="p-4 text-sm text-[var(--text-muted)]">{new Date(r.created_at).toLocaleDateString('id-ID')}</td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>

            <ReportDetailModal
                isOpen={!!selectedReport}
                onClose={() => setSelectedReport(null)}
                report={selectedReport}
            />
        </div>
    );
}

function MiniStat({ icon: Icon, label, value, highlight }: { icon: any; label: string; value: string | number; highlight?: boolean }) {
    return (
        <div className="flex items-center gap-3">
            <div className={cn("p-2.5 rounded-xl", highlight ? "bg-white/30" : "bg-white/20")}><Icon size={18} className="text-white" /></div>
            <div>
                <p className="text-white/70 text-[10px] uppercase tracking-wider font-medium">{label}</p>
                <p className="text-white text-xl font-bold">{value}</p>
            </div>
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { ArrowLeft, AlertCircle, Loader2, Plane } from 'lucide-react';
import { supabase } from '@/lib/supabase';
import { Report, User } from '@/types';
import { ReportDetailView } from '@/components/dashboard/ReportDetailView';

const DIVISION = { code: 'OP', name: 'Operasi', color: '#06b6d4' };

export default function OPReportDetailPage() {
    const params = useParams();
    const router = useRouter();
    const reportId = params.id as string;

    const [report, setReport] = useState<Report | null>(null);
    const [loading, setLoading] = useState(true);
    const [actionLoading, setActionLoading] = useState(false);
    const [error, setError] = useState('');
    const [user, setUser] = useState<User | null>(null);

    useEffect(() => {
        fetchUser();
        fetchReport();
    }, [reportId]);

    const fetchUser = async () => {
        try {
            const res = await fetch('/api/auth/me');
            if (res.ok) setUser(await res.json());
        } catch (err) { console.error('Error fetching user:', err); }
    };

    const fetchReport = async () => {
        try {
            const res = await fetch(`/api/reports/${reportId}`);
            if (!res.ok) throw new Error('Failed to load report');
            setReport(await res.json());
        } catch (err) {
            setError(err instanceof Error ? err.message : 'Unknown error');
        } finally {
            setLoading(false);
        }
    };

    const handleStatusUpdate = async (id: string, status: string, notes?: string, evidenceUrl?: string) => {
        setActionLoading(true);
        try {
            const body: Record<string, any> = { reportId: id, status, notes };
            if (evidenceUrl) body.resolution_evidence_url = evidenceUrl;

            const res = await fetch('/api/admin/reports', {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(body),
            });

            if (res.ok) {
                await fetchReport();
            } else {
                alert('Gagal mengubah status');
            }
        } catch (error) {
            console.error('Error updating status:', error);
            alert('Terjadi kesalahan sistem');
        } finally {
            setActionLoading(false);
        }
    };

    if (loading) {
        return (
            <div className="flex items-center justify-center min-h-screen">
                <Loader2 className="w-8 h-8 animate-spin" style={{ color: DIVISION.color }} />
            </div>
        );
    }

    if (error || !report) {
        return (
            <div className="flex flex-col items-center justify-center min-h-screen gap-4">
                <AlertCircle className="w-12 h-12 text-red-500" />
                <h2 className="text-xl font-bold">Error Loading Report</h2>
                <p className="text-gray-500">{error}</p>
                <button onClick={() => router.back()} className="flex items-center gap-2 font-bold hover:underline" style={{ color: DIVISION.color }}>
                    <ArrowLeft size={16} /> Kembali
                </button>
            </div>
        );
    }

    return (
        <div className="h-screen bg-[var(--surface-1)] overflow-hidden">
            <ReportDetailView 
                report={report} 
                onUpdateStatus={handleStatusUpdate}
                onRefresh={fetchReport}
                onClose={() => router.push('/dashboard/op/reports')}
                userRole={user?.role || 'OP_ADMIN'}
                isModal={false}
                divisionColor={DIVISION.color}
                currentUserId={user?.id}
            />
        </div>
    );
}

'use client';

import { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import {
    FileText, Search, Filter, ChevronDown, RefreshCw, Eye, X,
    MapPin, AlertTriangle, Plane,
    Clock, CheckCircle2
} from 'lucide-react';
import { STATUS_CONFIG, SEVERITY_CONFIG, ReportStatus } from '@/lib/constants/report-status';
import { Report } from '@/types';

const DIVISION = { code: 'OP', name: 'Operasi', color: '#06b6d4' };

export default function OPReportsPage() {
    const router = useRouter();
    const [reports, setReports] = useState<Report[]>([]);
    const [loading, setLoading] = useState(true);
    const [filter, setFilter] = useState('all');
    const [severityFilter, setSeverityFilter] = useState('all');
    const [search, setSearch] = useState('');
    const [selectedReport, setSelectedReport] = useState<Report | null>(null);

    const fetchReports = async () => {
        setLoading(true);
        try {
            const res = await fetch('/api/admin/reports');
            const data = await res.json();
            // Temporarily show all reports (no division filter)
            setReports(Array.isArray(data) ? data : []);
        } catch (error) { console.error('Error:', error); } 
        finally { setLoading(false); }
    };

    useEffect(() => { fetchReports(); }, []);

    const filteredReports = reports.filter(r => {
        const matchesSearch = r.title.toLowerCase().includes(search.toLowerCase()) || r.location?.toLowerCase().includes(search.toLowerCase());
        const matchesSeverity = severityFilter === 'all' || r.severity === severityFilter;
        const matchesStatus = filter === 'all' || r.status === filter;
        return matchesSearch && matchesSeverity && matchesStatus;
    });

    const stats = { total: reports.length, high: reports.filter(r => r.severity === 'high').length, pending: reports.filter(r => ['MENUNGGU_FEEDBACK', 'SUDAH_DIVERIFIKASI'].includes(r.status)).length, resolved: reports.filter(r => r.status === 'SELESAI').length };

    return (
        <div className="space-y-8 stagger-children pb-24">
            <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-4 animate-fade-in-up">
                <div>
                    <div className="flex items-center gap-2 mb-2">
                        <Plane size={20} style={{ color: DIVISION.color }} />
                        <span className="text-xs font-bold uppercase tracking-wider px-2 py-1 rounded-full" style={{ background: `${DIVISION.color}20`, color: DIVISION.color }}>Divisi {DIVISION.code}</span>
                    </div>
                    <h1 className="text-3xl font-bold" style={{ color: 'var(--text-primary)' }}>Laporan {DIVISION.name}</h1>
                    <p className="mt-1" style={{ color: 'var(--text-secondary)' }}>Kelola laporan operasional penerbangan</p>
                </div>
                <button onClick={fetchReports} className="btn-secondary self-start"><RefreshCw size={16} /> Perbarui</button>
            </div>

            <div className="bento-grid bento-4 animate-fade-in-up" style={{ animationDelay: '50ms' }}>
                <StatCard icon={FileText} value={stats.total} label="Total" />
                <StatCard icon={AlertTriangle} value={stats.high} label="High" color="#dc2626" />
                <StatCard icon={Clock} value={stats.pending} label="Pending" color="#f59e0b" />
                <StatCard icon={CheckCircle2} value={stats.resolved} label="Selesai" color="#10b981" />
            </div>

            <div className="flex flex-col gap-4 animate-fade-in-up" style={{ animationDelay: '100ms' }}>
                <div className="relative">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5" style={{ color: 'var(--text-muted)' }} />
                    <input type="text" placeholder="Cari laporan..." value={search} onChange={(e) => setSearch(e.target.value)} className="input-field" style={{ paddingLeft: 'calc(var(--space-lg) + 1.5rem)' }} />
                </div>
                <div className="flex flex-wrap gap-3">
                    <FilterSelect value={filter} onChange={setFilter} icon={Filter} options={[{ value: 'all', label: 'Semua Status' }, { value: 'MENUNGGU_FEEDBACK', label: 'Menunggu Feedback' }, { value: 'SUDAH_DIVERIFIKASI', label: 'Diverifikasi' }, { value: 'SELESAI', label: 'Selesai' }]} />
                    <FilterSelect value={severityFilter} onChange={setSeverityFilter} icon={AlertTriangle} options={[{ value: 'all', label: 'Semua' }, { value: 'high', label: '🔴 High' }, { value: 'medium', label: '🟡 Medium' }, { value: 'low', label: '🟢 Low' }]} />
                </div>
            </div>

            <div className="card-solid animate-fade-in-up" style={{ padding: 0, overflow: 'hidden', animationDelay: '150ms' }}>
                <div className="flex items-center justify-between" style={{ padding: 'var(--space-lg) var(--space-xl)', borderBottom: '1px solid var(--surface-4)' }}>
                    <div className="flex items-center gap-3">
                        <div className="p-2.5 rounded-xl" style={{ background: `${DIVISION.color}20` }}><Plane size={18} style={{ color: DIVISION.color }} /></div>
                        <div><h3 className="font-bold" style={{ color: 'var(--text-primary)' }}>Daftar Laporan</h3><p className="text-xs" style={{ color: 'var(--text-muted)' }}>{filteredReports.length} laporan</p></div>
                    </div>
                </div>

                {loading ? (<div className="flex items-center justify-center py-16"><div className="w-10 h-10 rounded-full border-4 animate-spin" style={{ borderColor: 'var(--surface-4)', borderTopColor: DIVISION.color }} /></div>
                ) : filteredReports.length === 0 ? (<div className="py-16 text-center"><FileText size={40} className="mx-auto mb-4 opacity-50" style={{ color: 'var(--text-muted)' }} /><p style={{ color: 'var(--text-muted)' }}>Tidak ada laporan</p></div>
                ) : (
                    <div className="overflow-x-auto">
                        <table className="w-full text-sm">
                            <thead><tr style={{ background: 'var(--surface-3)', borderBottom: '1px solid var(--surface-4)' }}>
                                <th className="text-left py-3 px-5 font-semibold text-xs uppercase" style={{ color: 'var(--text-muted)', width: '45%' }}>Laporan</th>
                                <th className="text-left py-3 px-4 font-semibold text-xs uppercase" style={{ color: 'var(--text-muted)' }}>Pelapor</th>
                                <th className="text-center py-3 px-4 font-semibold text-xs uppercase" style={{ color: 'var(--text-muted)' }}>Status</th>
                                <th className="text-right py-3 px-5 font-semibold text-xs uppercase" style={{ color: 'var(--text-muted)' }}>Tanggal</th>
                            </tr></thead>
                            <tbody>
                                {filteredReports.map((r) => {
                                    const sev = SEVERITY_CONFIG[r.severity as keyof typeof SEVERITY_CONFIG] || SEVERITY_CONFIG.low;
                                    const stat = STATUS_CONFIG[r.status as ReportStatus] || STATUS_CONFIG.MENUNGGU_FEEDBACK;
                                    const StatIcon = stat.icon;
                                    return (
                                        <tr key={r.id} className="cursor-pointer transition-colors" style={{ borderBottom: '1px solid var(--surface-4)', borderLeft: `3px solid ${sev.color}` }} onClick={() => router.push(`/dashboard/op/reports/${r.id}`)} onMouseEnter={(e) => e.currentTarget.style.background = 'var(--surface-3)'} onMouseLeave={(e) => e.currentTarget.style.background = 'transparent'}>
                                            <td className="py-4 px-5"><p className="font-semibold truncate max-w-[280px]" style={{ color: 'var(--text-primary)' }}>{r.title}</p>{r.location && <p className="text-xs flex items-center gap-1 mt-1" style={{ color: 'var(--text-muted)' }}><MapPin size={10} /> {r.location}</p>}</td>
                                            <td className="py-4 px-4"><p className="font-medium" style={{ color: 'var(--text-primary)' }}>{r.users?.full_name || '-'}</p></td>
                                            <td className="py-4 px-4 text-center"><span className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-semibold" style={{ background: stat.bgColor, color: stat.color }}><StatIcon size={12} /> {stat.label}</span></td>
                                            <td className="py-4 px-5 text-right"><p className="text-xs" style={{ color: 'var(--text-secondary)' }}>{new Date(r.created_at).toLocaleDateString('id-ID', { day: 'numeric', month: 'short' })}</p></td>
                                        </tr>
                                    );
                                })}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>

            {selectedReport && <QuickModal report={selectedReport} onClose={() => setSelectedReport(null)} color={DIVISION.color} path={`/dashboard/op/reports/${selectedReport.id}`} />}
        </div>
    );
}

function StatCard({ icon: Icon, value, label, color }: { icon: any; value: number; label: string; color?: string }) {
    return (<div className="card-solid flex items-center gap-4" style={{ background: color ? `${color}10` : undefined }}><div className="p-3 rounded-xl" style={{ background: color ? `${color}20` : 'var(--surface-3)' }}><Icon size={22} style={{ color: color || 'var(--text-primary)' }} /></div><div><p className="text-2xl font-bold" style={{ color: color || 'var(--text-primary)' }}>{value}</p><p className="text-xs" style={{ color: 'var(--text-muted)' }}>{label}</p></div></div>);
}

function FilterSelect({ value, onChange, icon: Icon, options }: { value: string; onChange: (v: string) => void; icon: any; options: { value: string; label: string }[] }) {
    return (<div className="relative flex-1 min-w-[140px]"><select value={value} onChange={(e) => onChange(e.target.value)} className="input-field pl-10 pr-10 cursor-pointer" style={{ background: 'var(--surface-2)' }}>{options.map((o) => <option key={o.value} value={o.value}>{o.label}</option>)}</select><Icon className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4" style={{ color: 'var(--text-muted)' }} /><ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4" style={{ color: 'var(--text-muted)' }} /></div>);
}

function QuickModal({ report, onClose, color, path }: { report: Report; onClose: () => void; color: string; path: string }) {
    const status = STATUS_CONFIG[report.status as ReportStatus] || STATUS_CONFIG.MENUNGGU_FEEDBACK;
    const StatusIcon = status.icon;
    return (<><div className="fixed inset-0 z-[9999] bg-black/70 backdrop-blur-sm" onClick={onClose} /><div className="fixed inset-0 z-[10000] flex items-center justify-center p-4 pointer-events-none"><div className="bg-white rounded-2xl shadow-2xl max-w-lg w-full max-h-[80vh] overflow-hidden animate-scale-in pointer-events-auto"><div className="p-6 text-white" style={{ background: color }}><button onClick={onClose} className="absolute top-4 right-4 p-2 hover:bg-white/20 rounded-xl"><X size={20} /></button><h2 className="text-xl font-bold">{report.title}</h2></div><div className="p-6 space-y-4 overflow-y-auto max-h-[50vh]"><span className="inline-flex items-center gap-2 px-4 py-2 rounded-full text-sm font-semibold" style={{ background: status.bgColor, color: status.color }}><StatusIcon size={16} /> {status.label}</span><p className="text-gray-700">{report.description}</p></div><div className="p-5 flex justify-end gap-3 bg-gray-50 border-t"><button onClick={onClose} className="px-6 py-2.5 rounded-xl text-gray-600 font-semibold hover:bg-gray-100">Tutup</button><button onClick={() => window.location.href = path} className="px-6 py-2.5 rounded-xl text-white font-semibold flex items-center gap-2" style={{ background: color }}><Eye size={18} /> Detail</button></div></div></div></>);
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import { useRouter } from 'next/navigation';
import { AlertCircle, Loader2, Eye, TrendingUp } from 'lucide-react';
import {
    AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
    PieChart, Pie, Cell
} from 'recharts';

import { STATUS_CONFIG, type ReportStatus } from '@/lib/constants/report-status';
import { cn } from '@/lib/utils';
import { Report } from '@/types';
import { DashboardHeader } from '@/components/dashboard/DashboardHeader';
import { type TimePeriod } from '@/components/dashboard/TimePeriodFilter';
import { PresentationSlide } from '@/components/dashboard/PresentationSlide';
import { ReportDetailModal } from '@/components/dashboard/ReportDetailModal';

interface AnalyticsData {
    summary: {
        totalReports: number;
        resolvedReports: number;
        pendingReports: number;
        highSeverity: number;
        avgResolutionRate: number;
    };
    stationData: Array<{ station: string; total: number; resolved: number }>;
    statusData: Array<{ name: string; value: number; color: string }>;
    trendData: Array<{ month: string; total: number; resolved: number }>;
}

export default function OSDashboard() {
    const router = useRouter();
    const [reports, setReports] = useState<Report[]>([]);
    const [analytics, setAnalytics] = useState<AnalyticsData | null>(null);
    const [loading, setLoading] = useState(true);
    const [period, setPeriod] = useState<TimePeriod>(null);
    const [selectedReport, setSelectedReport] = useState<Report | null>(null);

    const fetchData = useCallback(async () => {
        setLoading(true);
        try {
            const analyticsUrl = period
                ? `/api/admin/analytics?period=${period}`
                : '/api/admin/analytics';

            const [reportsRes, analyticsRes] = await Promise.all([
                fetch('/api/admin/reports'),
                fetch(analyticsUrl)
            ]);

            if (reportsRes.ok) {
                const data = await reportsRes.json();
                setReports(Array.isArray(data) ? data : []);
            }
            if (analyticsRes.ok) {
                setAnalytics(await analyticsRes.json());
            }
        } catch (err) {
            console.error('Failed to fetch data:', err);
        } finally {
            setLoading(false);
        }
    }, [period]);

    useEffect(() => {
        fetchData();
    }, [fetchData]);

    const handlePeriodChange = (newPeriod: TimePeriod) => {
        setPeriod(newPeriod);
    };

    const CustomTooltip = ({ active, payload, label }: any) => {
        if (active && payload && payload.length) {
            return (
                <div className="bg-white/95 backdrop-blur-md p-3 border border-gray-200 rounded-xl shadow-xl">
                    <p className="text-xs font-bold text-gray-900 mb-1">{label}</p>
                    {payload.map((entry: any, idx: number) => (
                        <p key={idx} className="text-xs" style={{ color: entry.color }}>
                            {entry.name}: <span className="font-bold">{entry.value}</span>
                        </p>
                    ))}
                </div>
            );
        }
        return null;
    };

    if (loading) {
        return (
            <div className="min-h-[60vh] flex flex-col items-center justify-center space-y-4">
                <div className="relative">
                    <div className="absolute inset-0 bg-emerald-500/20 rounded-full blur-xl animate-pulse" />
                    <Loader2 className="w-12 h-12 animate-spin text-emerald-600 relative" />
                </div>
                <p className="text-[var(--text-secondary)] tracking-widest uppercase text-xs font-bold">
                    Loading Dashboard...
                </p>
            </div>
        );
    }

    const pendingCount = analytics?.summary.pendingReports || 0;
    const resolvedCount = analytics?.summary.resolvedReports || 0;
    const totalCount = analytics?.summary.totalReports || 0;

    // Map status names to status keys for drilldown
    const statusNameToKey: Record<string, string> = {
        'Menunggu Feedback': 'MENUNGGU_FEEDBACK',
        'Sudah Diverifikasi': 'SUDAH_DIVERIFIKASI',
        'Selesai': 'SELESAI',
    };

    return (
        <div className="space-y-6 pb-24 stagger-children snap-y">
            {/* Slide 1: Header */}
            <PresentationSlide className="!p-0 !min-h-0 !bg-transparent !shadow-none !border-0">
                <DashboardHeader
                    title="Dashboard Monitoring"
                    subtitle="Monitoring real-time laporan Divisi Operasional"
                    totalReports={totalCount}
                    pendingReports={pendingCount}
                    resolvedReports={resolvedCount}
                    period={period}
                    onPeriodChange={handlePeriodChange}
                />
            </PresentationSlide>

            {/* Slide 2: Tren Laporan (Area) + Distribusi Status (Pie) */}
            <PresentationSlide
                title="Tren & Distribusi"
                subtitle="Volume laporan dan distribusi status"
                icon={TrendingUp}
                hint="Klik chart untuk melihat detail laporan"
            >
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                    {/* Trend Chart */}
                    <div className="card-solid lg:col-span-2 p-6">
                        <div className="flex items-center justify-between mb-6">
                            <div>
                                <h3 className="font-bold text-lg text-[var(--text-primary)]">Tren Laporan</h3>
                                <p className="text-xs text-[var(--text-muted)]">Volume per bulan</p>
                            </div>
                            <TrendingUp size={20} className="text-emerald-600" />
                        </div>
                        <div className="h-[300px]">
                            <ResponsiveContainer width="100%" height="100%">
                                <AreaChart
                                    data={analytics?.trendData}
                                    margin={{ top: 10, right: 10, left: 0, bottom: 0 }}
                                    onClick={(state) => {
                                        if (state?.activeLabel) {
                                            router.push(`/dashboard/os/drilldown?type=trend_month&value=${String(state.activeLabel)}`);
                                        }
                                    }}
                                    style={{ cursor: 'pointer' }}
                                >
                                    <defs>
                                        <linearGradient id="colorTotal" x1="0" y1="0" x2="0" y2="1">
                                            <stop offset="5%" stopColor="#10b981" stopOpacity={0.3}/>
                                            <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
                                        </linearGradient>
                                    </defs>
                                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="var(--surface-4)" />
                                    <XAxis dataKey="month" tick={{fill: 'var(--text-secondary)', fontSize: 11}} axisLine={false} tickLine={false} />
                                    <YAxis tick={{fill: 'var(--text-secondary)', fontSize: 11}} axisLine={false} tickLine={false} />
                                    <Tooltip content={<CustomTooltip />} />
                                    <Area
                                        type="monotone"
                                        dataKey="total"
                                        name="Total"
                                        stroke="#10b981"
                                        strokeWidth={3}
                                        fillOpacity={1}
                                        fill="url(#colorTotal)"
                                    />
                                </AreaChart>
                            </ResponsiveContainer>
                        </div>
                    </div>

                    {/* Status Distribution */}
                    <div className="card-solid p-6">
                        <div className="flex items-center justify-between mb-6">
                            <div>
                                <h3 className="font-bold text-lg text-[var(--text-primary)]">Distribusi Status</h3>
                                <p className="text-xs text-[var(--text-muted)]">Status saat ini</p>
                            </div>
                            <Eye size={20} className="text-[var(--text-muted)]" />
                        </div>
                        <div className="h-[250px] relative">
                            <ResponsiveContainer width="100%" height="100%">
                                <PieChart>
                                    <Pie
                                        data={analytics?.statusData}
                                        cx="50%"
                                        cy="50%"
                                        innerRadius={70}
                                        outerRadius={95}
                                        paddingAngle={4}
                                        dataKey="value"
                                        cornerRadius={8}
                                        stroke="none"
                                        onClick={(data) => {
                                            const statusKey = statusNameToKey[data?.name] || data?.name;
                                            if (statusKey) {
                                                router.push(`/dashboard/os/drilldown?type=status&value=${statusKey}`);
                                            }
                                        }}
                                        style={{ cursor: 'pointer' }}
                                    >
                                        {analytics?.statusData.map((entry, index) => (
                                            <Cell key={`cell-${index}`} fill={entry.color} />
                                        ))}
                                    </Pie>
                                    <Tooltip content={<CustomTooltip />} />
                                </PieChart>
                            </ResponsiveContainer>
                            <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                                <span className="text-3xl font-bold text-[var(--text-primary)]">{totalCount}</span>
                                <span className="text-[10px] uppercase tracking-widest text-[var(--text-muted)]">Total</span>
                            </div>
                        </div>
                        <div className="grid grid-cols-2 gap-2 mt-4">
                            {analytics?.statusData?.slice(0, 4).map((s) => (
                                <div
                                    key={s.name}
                                    className="flex items-center gap-2 cursor-pointer hover:opacity-70 transition-opacity"
                                    onClick={() => {
                                        const statusKey = statusNameToKey[s.name] || s.name;
                                        router.push(`/dashboard/os/drilldown?type=status&value=${statusKey}`);
                                    }}
                                >
                                    <div className="w-3 h-3 rounded-full" style={{ background: s.color }} />
                                    <span className="text-xs text-[var(--text-secondary)] truncate">{s.name}</span>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
            </PresentationSlide>

            {/* Slide 3: Recent Reports */}
            {reports.length > 0 && (
                <PresentationSlide
                    title="Laporan Terbaru"
                    subtitle="Laporan terakhir yang masuk"
                    icon={AlertCircle}
                >
                    <div className="space-y-3">
                        {reports.slice(0, 5).map((report) => (
                            <div
                                key={report.id}
                                onClick={() => setSelectedReport(report)}
                                className="flex items-center gap-4 p-3 rounded-xl bg-[var(--surface-2)] hover:bg-[var(--surface-3)] transition-colors cursor-pointer"
                            >
                                <div className={cn(
                                    "w-10 h-10 rounded-xl flex items-center justify-center shrink-0",
                                    report.severity === 'high' || report.severity === 'urgent' ? "bg-red-100 text-red-600" :
                                    report.severity === 'medium' ? "bg-amber-100 text-amber-600" :
                                    "bg-emerald-100 text-emerald-600"
                                )}>
                                    <AlertCircle size={18} />
                                </div>
                                <div className="flex-1 min-w-0">
                                    <p className="font-medium text-sm text-[var(--text-primary)] truncate">{report.title}</p>
                                    <p className="text-xs text-[var(--text-muted)]">
                                        {report.stations?.code} • {new Date(report.created_at).toLocaleDateString('id-ID')}
                                    </p>
                                </div>
                                <span
                                    className="px-2 py-1 rounded-full text-[10px] font-bold uppercase shrink-0"
                                    style={{
                                        color: STATUS_CONFIG[report.status as ReportStatus]?.color,
                                        backgroundColor: STATUS_CONFIG[report.status as ReportStatus]?.bgColor
                                    }}
                                >
                                    {STATUS_CONFIG[report.status as ReportStatus]?.label || report.status}
                                </span>
                            </div>
                        ))}
                    </div>
                </PresentationSlide>
            )}

            {/* Report Detail Modal */}
            <ReportDetailModal
                isOpen={!!selectedReport}
                onClose={() => setSelectedReport(null)}
                report={selectedReport}
            />
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';
import { useParams, useRouter } from 'next/navigation';
import {
    ArrowLeft, AlertCircle, Loader2
} from 'lucide-react';
import { supabase } from '@/lib/supabase';
import { Report, User } from '@/types';
import { ReportDetailView } from '@/components/dashboard/ReportDetailView';

export default function OSReportDetailPage() {
    const params = useParams();
    const router = useRouter();
    const reportId = params.id as string;

    const [report, setReport] = useState<Report | null>(null);
    const [loading, setLoading] = useState(true);
    const [actionLoading, setActionLoading] = useState(false);
    const [error, setError] = useState('');
    const [user, setUser] = useState<User | null>(null);

    useEffect(() => {
        fetchUser();
        fetchReport();
    }, [reportId]);

    const fetchUser = async () => {
        try {
            const res = await fetch('/api/auth/me');
            if (res.ok) {
                const data = await res.json();
                setUser(data);
            }
        } catch (err) {
            console.error('Error fetching user:', err);
        }
    };

    const fetchReport = async () => {
        try {
            const res = await fetch(`/api/reports/${reportId}`);
            if (!res.ok) throw new Error('Failed to load report');
            const data = await res.json();
            setReport(data);
            setLoading(false);
        } catch (err) {
            setError(err instanceof Error ? err.message : 'Unknown error');
            setLoading(false);
        }
    };

    const handleStatusUpdate = async (id: string, status: string, notes?: string) => {
        // OS Admin typically shouldn't be updating status? Use API if allowed.
        setActionLoading(true);
        try {
            const res = await fetch('/api/admin/reports', {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ reportId: id, status, notes }),
            });

            if (res.ok) {
                await fetchReport();
            } else {
                alert('Gagal mengubah status');
            }
        } catch (error) {
            console.error('Error updating status:', error);
            alert('Terjadi kesalahan sistem');
        } finally {
            setActionLoading(false);
        }
    };

    if (loading) {
        return (
            <div className="flex items-center justify-center min-h-screen">
                <Loader2 className="w-8 h-8 animate-spin text-[var(--brand-primary)]" />
            </div>
        );
    }

    if (error || !report) {
        return (
            <div className="flex flex-col items-center justify-center min-h-screen gap-4">
                <AlertCircle className="w-12 h-12 text-red-500" />
                <h2 className="text-xl font-bold">Error Loading Report</h2>
                <p className="text-gray-500">{error}</p>
                <button 
                    onClick={() => router.back()}
                    className="flex items-center gap-2 text-[var(--brand-primary)] font-bold hover:underline"
                >
                    <ArrowLeft size={16} /> Kembali
                </button>
            </div>
        );
    }

    return (
        <div className="h-[calc(100vh-4rem)] md:h-screen bg-[var(--surface-1)] overflow-hidden -mx-4 -mb-6 md:-mx-8 md:-mb-8 -mt-16 md:-mt-8" style={{ width: 'calc(100% + 2rem)', maxWidth: 'none' }}>
            <ReportDetailView 
                report={report} 
                onUpdateStatus={handleStatusUpdate}
                onRefresh={fetchReport}
                onClose={() => router.push('/dashboard/os/reports')}
                userRole={user?.role || 'DIVISI_OS'}
                isModal={false}
                currentUserId={user?.id}
            />
        </div>
    );
}

'use client';

import { useEffect, useState } from 'react';
import {
    FileText, Search, Filter, ChevronDown, RefreshCw,
    MapPin, AlertTriangle,
