                                            </td>
                                            <td className="py-4 px-5 text-right">
                                                <p className="text-xs font-medium" style={{ color: 'var(--text-secondary)' }}>
                                                    {new Date(report.created_at).toLocaleDateString('id-ID', { day: 'numeric', month: 'short' })}
