                    </div>
                    <div className="p-5 flex justify-end gap-3 bg-gray-50 border-t">
                        <button onClick={onClose} className="px-6 py-2.5 rounded-xl text-gray-600 font-semibold hover:bg-gray-100">Tutup</button>
