                      title={chart.title}
                      data={cr.queryResult.rows}
                      xAxis={chart.visualization_config.xAxis || 'category'}
                      yAxis={chart.visualization_config.yAxis?.length === 1 ? chart.visualization_config.yAxis[0] : (chart.visualization_config.yAxis || ['branch'])}
