                              "flex items-center gap-2 px-4 py-2 text-xs font-bold rounded-xl transition-all whitespace-nowrap",
                              !cfDateFrom || !cfDateTo || ai.loading
                                ? "bg-[var(--surface-3)] text-[var(--text-muted)] cursor-not-allowed"
                                : "bg-gradient-to-r from-emerald-500 to-green-600 text-white hover:shadow-lg hover:shadow-emerald-500/25"
                            )}
                          >
                            {ai.loading ? <Loader2 size={14} className="animate-spin" /> : <BarChart3 size={14} />}
                            Generate
                          </button>
                        </div>
                        {ai.error && (
                          <p className="mt-2 text-xs text-red-500">{ai.error}</p>
                        )}
                      </div>
                    </div>

                    {/* Divider */}
                    <div className="flex items-center gap-3 mb-5">
                      <div className="flex-1 h-px bg-[var(--surface-4)]" />
                      <span className="text-[10px] text-[var(--text-muted)] font-medium uppercase tracking-wider">atau buat manual</span>
                      <div className="flex-1 h-px bg-[var(--surface-4)]" />
                    </div>

                    {/* Enhanced 3-step guide cards */}
                    <div className="flex gap-3">
                      <div className="flex-1 p-3 bg-[var(--surface-2)] border border-[var(--surface-4)] rounded-xl hover:-translate-y-0.5 transition-transform cursor-default group">
                        <div className="flex items-center gap-2 mb-1.5">
                          <span className="inline-flex w-5 h-5 rounded-full bg-gradient-to-br from-blue-400 to-blue-600 text-white items-center justify-center text-[10px] font-bold">1</span>
                          <MousePointerClick size={13} className="text-blue-400 opacity-60 group-hover:opacity-100 transition-opacity" />
                        </div>
                        <p className="text-xs text-[var(--text-secondary)]">Pilih field di panel kiri</p>
                      </div>
                      <div className="flex-1 p-3 bg-[var(--surface-2)] border border-[var(--surface-4)] rounded-xl hover:-translate-y-0.5 transition-transform cursor-default group">
                        <div className="flex items-center gap-2 mb-1.5">
                          <span className="inline-flex w-5 h-5 rounded-full bg-gradient-to-br from-emerald-400 to-emerald-600 text-white items-center justify-center text-[10px] font-bold">2</span>
                          <Play size={13} className="text-emerald-400 opacity-60 group-hover:opacity-100 transition-opacity" />
                        </div>
                        <p className="text-xs text-[var(--text-secondary)]">Klik &quot;Jalankan Query&quot;</p>
                      </div>
                      <div className="flex-1 p-3 bg-[var(--surface-2)] border border-[var(--surface-4)] rounded-xl hover:-translate-y-0.5 transition-transform cursor-default group">
                        <div className="flex items-center gap-2 mb-1.5">
                          <span className="inline-flex w-5 h-5 rounded-full bg-gradient-to-br from-purple-400 to-purple-600 text-white items-center justify-center text-[10px] font-bold">3</span>
                          <BarChart3 size={13} className="text-purple-400 opacity-60 group-hover:opacity-100 transition-opacity" />
                        </div>
                        <p className="text-xs text-[var(--text-secondary)]">Atur grafik &amp; simpan</p>
                      </div>
                    </div>
                  </div>
                </div>
              ) : (
                <ResultsPanel
                  result={qe.data}
                  loading={qe.loading}
                  error={qe.error}
                  visualization={visualization}
                  chartPreview={chartPreviewNode}
                />
              )}
            </div>
          </div>

          {/* Right: Chart Config — only show when we have results */}
          {hasResult && (
            <div className="w-[280px] shrink-0 overflow-hidden">
              <ChartConfigPanel
                visualization={visualization}
                result={qe.data}
                onChange={updateVisualization}
              />
            </div>
          )}
        </div>
      ) : (
        <DashboardComposer
          tiles={dash.tiles}
          onAddTile={dash.addEmptyTile}
          onEditTile={handleEditTile}
          onRemoveTile={dash.removeTile}
          onResizeTile={(id, w, h) => dash.updateTileLayout(id, { w, h })}
          onApplyPreset={dash.applyLayoutPreset}
          tileResults={tileResults}
          dashboardName={dash.name}
          dashboardDescription={dash.description}
          pages={dash.pages}
          yearRange={yearRange}
          onReset={dash.resetTiles}
          onFilterChange={setGlobalFilters}
          currentFilters={globalFilters}
        />
      )}

      <SaveDashboardModal
        isOpen={showSaveModal}
        onClose={() => setShowSaveModal(false)}
        initialName={dash.name}
        initialDescription={dash.description}
        onSave={handleSave}
        tileCount={dash.tiles.length}
        pageCount={dash.pages.length}
      />
    </div>
  );
}

'use client';

import React from 'react';
import {
  ResponsiveContainer,
  BarChart, Bar,
  LineChart, Line,
  AreaChart, Area,
  PieChart, Pie, Cell,
  XAxis, YAxis, CartesianGrid, Tooltip, Legend,
} from 'recharts';
import type { ChartVisualization, QueryResult, DashboardTile } from '@/types/builder';
import { CustomPivotTable } from './CustomPivotTable';
import { ChartClickHandler } from '@/components/chart-detail/ChartClickHandler';
import { formatDateValue, ISO_DATETIME_RE, processChartData, formatDisplayValue } from '@/lib/chart-utils';

interface ChartPreviewProps {
  visualization: ChartVisualization;
  result: QueryResult;
  compact?: boolean;
  tile?: DashboardTile;
  dashboardId?: string;
}

const GAPURA_GREEN_LIGHT = '#7cb342';
const GAPURA_GREEN_DARK = '#558b2f';
const GAPURA_BLUE = '#42a5f5';
const GAPURA_YELLOW = '#fdd835';

const DEFAULT_COLORS = [
  GAPURA_GREEN_LIGHT, GAPURA_BLUE, GAPURA_YELLOW, GAPURA_GREEN_DARK, '#aed581',
  '#33691e', '#9ccc65', '#689f38', '#c5e1a5', '#43a047', '#81c784', '#4caf50',
];

const TOOLTIP_STYLE = {
  backgroundColor: '#ffffff',
  border: '1px solid #e0e0e0',
  borderRadius: '6px',
  fontSize: '11px',
  boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
};

function DateTooltip({ active, payload, label }: any) {
  if (!active || !payload?.length) return null;
  return (
    <div style={TOOLTIP_STYLE} className="px-3 py-2">
      <p className="font-medium mb-1">{typeof label === 'string' && ISO_DATETIME_RE.test(label) ? formatDateValue(label) : String(label)}</p>
      {payload.map((p: any, i: number) => (
        <p key={i} style={{ color: p.color }}>
          {p.name}: {typeof p.value === 'number' ? p.value.toLocaleString('id-ID') : p.value}
        </p>
      ))}
    </div>
  );
}

export function ChartPreview({ visualization, result, compact = false, tile, dashboardId }: ChartPreviewProps) {
  const { chartType, colorField, showLegend, showLabels, colors } = visualization;
  const palette = (colors && colors.length > 0) ? colors : DEFAULT_COLORS;
  const rawData = result.rows as Record<string, unknown>[];

  if (rawData.length === 0) {
    return (
      <div className="flex items-center justify-center h-full text-sm text-[var(--text-muted)]">
        Tidak ada data untuk ditampilkan
      </div>
    );
  }

  const wrap = (children: React.ReactNode) => {
    if (!tile) return children;
    return (
      <ChartClickHandler tile={tile} result={result} dashboardId={dashboardId}>
        {children}
      </ChartClickHandler>
    );
  };

  // Logic to determine active dimensions and measures
  let activeXKey = visualization.xAxis || result.columns[0] || '';
  const rawY = visualization.yAxis;
  let activeYKeys = (Array.isArray(rawY) ? rawY : (rawY ? [String(rawY)] : []))
    .filter(y => result.columns.includes(y));

  if (activeYKeys.length === 0) {
    activeYKeys = result.columns.filter(c => {
      if (c === activeXKey) return false;
      return rawData.some(r => typeof r[c] === 'number' && isFinite(r[c] as number));
    });
  }

  // Self-healing for swapped keys
  if (activeYKeys.length > 0 && typeof rawData[0][activeXKey] === 'number' && typeof rawData[0][activeYKeys[0]] === 'string') {
    const temp = activeXKey;
    activeXKey = activeYKeys[0];
    activeYKeys = [temp, ...activeYKeys.slice(1)];
  }

  if (activeYKeys.length === 0) activeYKeys = result.columns.slice(1);

  const data = processChartData(rawData, activeXKey);

  // HEATMAP
  if (chartType === 'heatmap') {
    const cols = result.columns;
    if (cols.length < 3) return <div className="p-4 text-xs text-center text-muted-foreground">Heatmap requires 3 columns</div>;

    // Robustly detect numeric vs categorical columns
    const numericCols = cols.filter(c => {
      const vals = rawData.slice(0, 10).map(r => r[c]);
      return vals.some(v => typeof v === 'number' && isFinite(v));
    });
    const categCols = cols.filter(c => !numericCols.includes(c));

    // Value (measure) should be the first numeric column
    let valueKey = colorField && cols.includes(colorField) ? colorField : (numericCols[0] || activeYKeys[0] || cols[cols.length - 1]);

    // Dimensions should be the categorical ones
    let dimKeys = categCols.length >= 2 ? categCols.slice(0, 2) : cols.filter(c => c !== valueKey).slice(0, 2);

    // Prefer activeXKey for colKey (X-axis/Horizontal)
    let colKey = activeXKey && dimKeys.includes(activeXKey) ? activeXKey : dimKeys[0];
    let rowKey = dimKeys.find(d => d !== colKey) || dimKeys[1] || dimKeys[0];

    const rowLabels = [...new Set(rawData.map(d => String(d[rowKey] ?? '')))];
    const colLabels = [...new Set(rawData.map(d => String(d[colKey] ?? '')))];

    return (
      <div className="w-full h-full overflow-auto p-2">
        <div className="grid gap-px" style={{ gridTemplateColumns: `auto repeat(${colLabels.length}, minmax(50px, 1fr))` }}>
          <div /> {colLabels.map(cl => <div key={cl} className="text-[10px] text-center font-medium truncate">{cl}</div>)}
          {rowLabels.map(rl => (
            <React.Fragment key={rl}>
              <div className="text-[10px] pr-2 text-right font-medium truncate self-center">{rl}</div>
              {colLabels.map(cl => {
                const row = rawData.find(r => String(r[rowKey]) === rl && String(r[colKey]) === cl);
                const val = Number(row?.[valueKey] ?? 0);
                return (
                  <div key={cl} className="h-8 flex items-center justify-center text-[10px] rounded-sm" style={{ backgroundColor: val > 0 ? `${palette[0]}33` : '#f5f5f5' }}>
                    {val || '-'}
                  </div>
                );
              })}
            </React.Fragment>
          ))}
        </div>
      </div>
    );
  }

  // TABLE
  if (chartType === 'table') {
    return wrap(
      <div className="w-full h-full overflow-auto">
        <table className="min-w-full text-[11px] border-collapse">
          <thead className="sticky top-0 bg-gray-50 z-10">
            <tr>{result.columns.map(c => <th key={c} className="px-3 py-2 text-left font-bold border-b">{c}</th>)}</tr>
          </thead>
          <tbody>
            {rawData.slice(0, 50).map((row, i) => (
              <tr key={i} className="hover:bg-gray-50 border-b">
                {result.columns.map(c => <td key={c} className="px-3 py-1.5">{String(row[c] ?? '-')}</td>)}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    );
  }

  // PIVOT TABLE
  if (chartType === 'pivot') {
    return wrap(
      <CustomPivotTable result={result} title={visualization.title} />
    );
  }

  const commonProps = {
    tick: { fontSize: 10, fill: '#888' },
    axisLine: { stroke: '#eee' },
    tickLine: false,
  };

  // BAR / HORIZONTAL_BAR
  if (chartType === 'bar' || chartType === 'horizontal_bar') {
    const horizontal = chartType === 'horizontal_bar';

    // Compact adjustments
    const fontSize = compact ? 8 : 10;
    const itemHeight = compact ? 34 : 54; // Increased from 44
    const dynamicMinH = horizontal ? (data.length * itemHeight + (compact ? 40 : 100)) : '100%';

    let yAxisWidth = 80;
    if (horizontal) {
      const labels = data.map(d => String(d[activeXKey] ?? ''));
      const longestWord = Math.max(...labels.flatMap(l => l.split(' ').map(w => w.length)), 0);
      const maxLines = Math.max(...labels.map(l => l.split(' ').length), 1);

      // Calculate width based on longest word or wrapped lines
      const effectiveCharLen = Math.min(Math.max(longestWord, 12), 25);
      yAxisWidth = Math.min(Math.max(effectiveCharLen * (compact ? 5 : 7.5), compact ? 60 : 120), 220);
    }

    return wrap(
      <div style={{ width: '100%', height: '100%', minHeight: horizontal ? dynamicMinH : undefined, overflowY: horizontal ? 'auto' : 'visible' }}>
        <ResponsiveContainer width="100%" height={horizontal ? dynamicMinH : "100%"}>
          <BarChart 
            data={data} 
            layout={horizontal ? 'vertical' : 'horizontal'}
            margin={{ top: 10, right: horizontal ? (compact ? 35 : 60) : 10, left: horizontal ? (compact ? 0 : 0) : 0, bottom: 10 }}
            barCategoryGap={compact ? "10%" : "20%"}
            barSize={compact ? 12 : 20}
          >
            <CartesianGrid strokeDasharray="3 3" vertical={!horizontal} horizontal={horizontal} stroke="#f5f5f5" />
            {horizontal ? (
              <>
                <XAxis type="number" {...commonProps} allowDecimals={false} hide={compact} />
                <YAxis 
                  type="category" 
                  dataKey={activeXKey} 
                  {...commonProps} 
                  width={yAxisWidth} 
                  interval={0} 
                  tick={(props) => {
                    const { x, y, payload } = props;
                    const words = String(payload.value).split(' ');
                    const lines = [];
                    let cur = words[0];
                    for(let i=1; i<words.length; i++) {
                      if ((cur + ' ' + words[i]).length < (compact ? 12 : 20)) cur += ' ' + words[i];
                      else { lines.push(cur); cur = words[i]; }
                    }
                    lines.push(cur);
                    return (
                      <g transform={`translate(${x},${y})`}>
                        {lines.map((l, i) => (
                          <text 
                            key={i} 
                            x={-8} 
                            y={0} 
                            dy={i * (fontSize + 2) + 4 - ((lines.length - 1) * (fontSize/1.5))} 
                            textAnchor="end" 
                            fontSize={fontSize} 
                            fill="#444"
                            fontWeight={500}
                          >
                            {l}
                          </text>
                        ))}
                      </g>
                    );
                  }}
                />
              </>
            ) : (
              <>
                <XAxis 
                  dataKey={activeXKey} 
                  {...commonProps} 
                  height={compact ? 40 : 60}
                  interval={0} 
                  tick={(props) => {
                    const { x, y, payload } = props;
                    const label = String(payload.value);
                    const isLong = label.length > 10;
                    const shouldRotate = isLong || data.length > 6;

                    return (
                      <g transform={`translate(${x},${y})`}>
                        <text
                          x={0}
                          y={0}
                          dy={10}
                          textAnchor={shouldRotate ? "end" : "middle"}
                          fill="#666"
                          fontSize={fontSize}
                          transform={shouldRotate ? "rotate(-35)" : undefined}
                          fontWeight={500}
                        >
                          {label.length > (compact ? 15 : 25) ? label.substring(0, compact ? 12 : 22) + '...' : label}
                        </text>
                      </g>
                    );
                  }}
                />
                <YAxis {...commonProps} allowDecimals={false} />
              </>
            )}
            <Tooltip content={<DateTooltip />} />
            {activeYKeys.map((key, i) => (
              <Bar 
                key={key} 
                dataKey={key} 
                fill={palette[i % palette.length]} 
                radius={horizontal ? [0, 6, 6, 0] : [6, 6, 0, 0]} 
                minPointSize={2}
                label={showLabels ? { 
                  position: horizontal ? 'right' : 'top', 
                  fontSize: fontSize, 
                  fill: '#666',
                  formatter: (val: any) => formatDisplayValue(val),
                  offset: compact ? 4 : 10
                } : false}
              />
            ))}
          </BarChart>
        </ResponsiveContainer>
      </div>
    );
  }

  // LINE/AREA (Minimal for remaining)
  return wrap(
    <ResponsiveContainer width="100%" height="100%">
      {chartType === 'line' ? (
        <LineChart data={data} margin={{ top: 10, right: 10, left: 0, bottom: 5 }}>
          <CartesianGrid strokeDasharray="3 3" stroke="#f0f0f0" />
          <XAxis dataKey={activeXKey} {...commonProps} />
          <YAxis {...commonProps} />
          <Tooltip content={<DateTooltip />} />
          {activeYKeys.map((key, i) => <Line key={key} type="monotone" dataKey={key} stroke={palette[i % palette.length]} strokeWidth={2} dot={{r: 3}} />)}
        </LineChart>
      ) : (
        <AreaChart data={data} margin={{ top: 10, right: 10, left: 0, bottom: 5 }}>
          <CartesianGrid strokeDasharray="3 3" stroke="#f0f0f0" />
          <XAxis dataKey={activeXKey} {...commonProps} />
          <YAxis {...commonProps} />
          <Tooltip content={<DateTooltip />} />
          {activeYKeys.map((key, i) => <Area key={key} type="monotone" dataKey={key} stroke={palette[i % palette.length]} fill={palette[i % palette.length]} fillOpacity={0.2} />)}
        </AreaChart>
      )}
    </ResponsiveContainer>
  );
}

'use client';

import { useState, useMemo } from 'react';
import { ChevronLeft, ChevronRight } from 'lucide-react';
import type { QueryResult } from '@/types/builder';

interface CustomPivotTableProps {
  result: QueryResult;
  title?: string;
}

const GAPURA_GREEN = '#6b8e3d';
const GAPURA_GREEN_DARK = '#5a7a3a';

// Safe number conversion
function toSafeNumber(val: unknown): number {
  if (val === null || val === undefined) return 0;
  const num = Number(val);
  return isNaN(num) ? 0 : num;
}

// Safe string conversion
function toSafeString(val: unknown): string {
  if (val === null || val === undefined) return '';
  return String(val).trim();
}

export function CustomPivotTable({ result, title }: CustomPivotTableProps) {
  const [currentPage, setCurrentPage] = useState(1);
  const pageSize = 10;

  const processedData = useMemo(() => {
    const columns = result.columns;
    const data = result.rows as Record<string, unknown>[];

    if (data.length === 0) {
      return {
        displayRows: [] as Array<{ row: string; total: number }>,
        cols: [] as string[],
        matrix: new Map<string, number>(),
        rowTotals: {} as { [key: string]: number },
        colTotals: {} as { [key: string]: number },
        grandTotal: 0,
        maxValue: 0,
        totalRows: 0,
        isHierarchical: false,
        rowField: '',
        colField: ''
      };
    }

    // Auto-detect column types
    const sampleRow = data[0];
    const dimColumns: string[] = [];
    const measureColumns: string[] = [];

    columns.forEach(col => {
      const val = sampleRow[col];
      if (typeof val === 'number') {
        measureColumns.push(col);
      } else {
        dimColumns.push(col);
      }
    });

    // Determine structure based on title and columns
    const isCaseReportByArea = title === 'Case Report by Area';
    const isDetailByBranch = title?.includes('by Branch');
    const isDetailByAirlines = title?.includes('by Airlines');

    let rowField: string;
    let colField: string;
    let valueField: string;
    let isHierarchical = false;

    if (isCaseReportByArea) {
      // Hierarchical: Branch Report -> Airlines -> Area columns
      isHierarchical = true;
      rowField = dimColumns.find(c => c.toLowerCase().includes('branch')) || dimColumns[0];
      colField = dimColumns.find(c => c.toLowerCase().includes('area')) || dimColumns[2];
      valueField = measureColumns[0];
    } else if (isDetailByBranch) {
      // Simple pivot: Category (row) x Branch (col)
      rowField = dimColumns.find(c => c.toLowerCase().includes('category')) || dimColumns[0];
      colField = dimColumns.find(c => c.toLowerCase().includes('branch')) || dimColumns[1];
      valueField = measureColumns[0];
    } else if (isDetailByAirlines) {
      // Simple pivot: Category (row) x Airlines (col)
      rowField = dimColumns.find(c => c.toLowerCase().includes('category')) || dimColumns[0];
      colField = dimColumns.find(c => c.toLowerCase().includes('airlines')) || dimColumns[1];
      valueField = measureColumns[0];
    } else {
      // Default: first dim = row, second dim = col, first measure = value
      rowField = dimColumns[0];
      colField = dimColumns[1];
      valueField = measureColumns[0];
    }

    console.log(`[CustomPivotTable] ${title} - Structure:`, {
      isHierarchical,
      rowField,
      colField,
      valueField,
      dimColumns,
      measureColumns
    });

    // Extract unique values
    const rowValues = [...new Set(data.map(r => toSafeString(r[rowField])).filter(Boolean))];
    const colValues = [...new Set(data.map(r => toSafeString(r[colField])).filter(Boolean))].sort();

    // Build matrix
    const matrix = new Map<string, number>();
    let maxValue = 0;

    data.forEach(row => {
      const rowVal = toSafeString(row[rowField]);
      const colVal = toSafeString(row[colField]);
      const val = toSafeNumber(row[valueField]);

      if (rowVal && colVal) {
        const key = `${rowVal}__${colVal}`;
        matrix.set(key, val);
        if (val > maxValue) maxValue = val;
      }
    });

    // Build display rows with totals
    const displayRows = rowValues.map(rowVal => {
      const total = colValues.reduce((sum, colVal) => {
        return sum + (matrix.get(`${rowVal}__${colVal}`) || 0);
      }, 0);

      return {
        row: rowVal,
        total
      };
    }).sort((a, b) => b.total - a.total); // Sort by total descending

    // Calculate column totals
    const colTotals: { [key: string]: number } = {};
    colValues.forEach((colVal: string) => {
      colTotals[colVal] = displayRows.reduce((sum: number, row: { row: string; total: number }) => {
        return sum + (matrix.get(`${row.row}__${colVal}`) || 0);
      }, 0);
    });

    // Calculate row totals
    const rowTotals: Record<string, number> = {};
    displayRows.forEach(row => {
      rowTotals[row.row] = row.total;
    });

    // Calculate grand total
    const grandTotal = Object.values(colTotals).reduce((a, b) => a + b, 0);

    console.log(`[CustomPivotTable] ${title} - Totals:`, {
      grandTotal,
      colTotals,
      rowCount: displayRows.length
    });

    return {
      displayRows,
      cols: colValues,
      matrix,
      rowTotals,
      colTotals,
      grandTotal,
      maxValue,
      totalRows: displayRows.length,
      isHierarchical,
      rowField,
      colField
    };
  }, [result, title]);

  const { 
    displayRows, 
    cols, 
    matrix, 
    rowTotals, 
    colTotals, 
    grandTotal, 
    maxValue, 
    totalRows,
    isHierarchical,
    rowField,
    colField
  } = processedData;

  // Paginate
  const totalPages = Math.ceil(totalRows / pageSize);
  const paginatedRows = displayRows.slice((currentPage - 1) * pageSize, currentPage * pageSize);

  // Color intensity function
  function getCellColor(value: number): { bg: string; text: string } {
    if (value === 0) return { bg: '#ffffff', text: '#999' };

    const intensity = maxValue > 0 ? value / maxValue : 0;

    if (intensity <= 0.2) {
      return { bg: '#e8f5e9', text: '#333' };
    } else if (intensity <= 0.4) {
      return { bg: '#c8e6c9', text: '#333' };
    } else if (intensity <= 0.6) {
      return { bg: '#a5d6a7', text: '#333' };
    } else if (intensity <= 0.8) {
      return { bg: '#81c784', text: '#fff' };
    } else {
      return { bg: '#66bb6a', text: '#fff' };
    }
  }

  // Format subtitle
  const subtitle = title === 'Case Report by Area' 
    ? 'Area Report / Branch by Airlines'
    : title?.includes('by Branch')
      ? `${rowField} / Branch`
      : title?.includes('by Airlines')
        ? `${rowField} / Airlines`
        : '';

  return (
    <div className="w-full h-full flex flex-col bg-white rounded-lg border border-[#e0e0e0] overflow-hidden">
      {/* Header */}
      {subtitle && (
        <div className="bg-[#f5f5f5] border-b border-[#e0e0e0]">
          <div 
            className="px-3 py-2 text-white text-[11px] font-bold text-center"
            style={{ backgroundColor: GAPURA_GREEN }}
          >
            {subtitle}
          </div>
        </div>
      )}

      {/* Table */}
      <div className="flex-1 overflow-auto">
        <table className="w-full border-collapse">
          <thead>
            <tr>
              <th 
                className="px-2 py-2 text-left text-[10px] font-bold text-white border-r border-[#5a7a3a]"
                style={{ backgroundColor: GAPURA_GREEN, minWidth: 120 }}
              >
                {rowField}
              </th>
              {cols.map(col => (
                <th
                  key={col}
                  className="px-2 py-2 text-center text-[10px] font-bold text-white border-r border-[#5a7a3a] last:border-r-0"
                  style={{ 
                    backgroundColor: GAPURA_GREEN, 
                    minWidth: 80,
                    maxWidth: 120,
                    width: 100,
                    whiteSpace: 'normal',
                    wordWrap: 'break-word',
                    overflow: 'hidden',
                    lineHeight: '1.2',
                    verticalAlign: 'middle'
                  }}
                  title={col}
                >
                  {col}
                </th>
              ))}
              <th 
                className="px-2 py-2 text-center text-[10px] font-bold text-white"
                style={{ backgroundColor: GAPURA_GREEN_DARK, minWidth: 70 }}
              >
                Grand total
              </th>
            </tr>
          </thead>
          <tbody>
            {paginatedRows.length === 0 ? (
              <tr>
                <td 
                  colSpan={cols.length + 2} 
                  className="px-4 py-8 text-center text-[11px] text-[#999]"
                >
                  No data available
                </td>
              </tr>
            ) : (
              <>
                {paginatedRows.map((row, idx) => (
                  <tr
                    key={`${row.row}-${idx}`}
                    className="border-b border-[#f0f0f0]"
                    style={{ 
                      backgroundColor: idx % 2 === 0 ? '#ffffff' : '#f9f9f9'
                    }}
                  >
                    <td 
                      className="px-2 py-1.5 text-[10px] text-[#333] border-r border-[#f0f0f0] font-medium"
                      style={{ backgroundColor: '#f5f5f5' }}
                      title={row.row}
                    >
                      {row.row}
                    </td>
                    {cols.map(col => {
                      const val = matrix.get(`${row.row}__${col}`) || 0;
                      const { bg, text } = getCellColor(val);

                      return (
                        <td
                          key={col}
                          className="px-2 py-1.5 text-[10px] text-center border-r border-[#f0f0f0] font-bold"
                          style={{ backgroundColor: bg, color: text }}
                        >
                          {val > 0 ? val : '-'}
                        </td>
                      );
                    })}
                    <td 
                      className="px-2 py-1.5 text-[10px] text-center font-bold border-l-2 border-[#6b8e3d]"
                      style={{ backgroundColor: '#e8f5e9', color: '#333' }}
                    >
                      {row.total}
                    </td>
                  </tr>
                ))}
                {/* Grand total row */}
                <tr style={{ backgroundColor: '#e8f5e9' }}>
                  <td 
                    className="px-2 py-2 text-[10px] font-bold text-[#333] border-t-2 border-[#6b8e3d] border-r border-[#f0f0f0]"
                  >
                    Grand total
                  </td>
                  {cols.map(col => (
                    <td 
                      key={col}
                      className="px-2 py-2 text-[10px] text-center font-bold text-[#333] border-t-2 border-[#6b8e3d] border-r border-[#f0f0f0]"
                    >
                      {colTotals[col] || 0}
                    </td>
                  ))}
                  <td 
                    className="px-2 py-2 text-[10px] text-center font-bold text-[#333] border-t-2 border-[#6b8e3d] border-l-2 border-[#6b8e3d]"
                  >
                    {grandTotal}
                  </td>
                </tr>
              </>
            )}
          </tbody>
        </table>
      </div>

      {/* Pagination */}
      {totalRows > pageSize && (
        <div className="flex items-center justify-between px-3 py-2 border-t border-[#e0e0e0] bg-white">
          <span className="text-[9px] text-[#666]">
            Showing {(currentPage - 1) * pageSize + 1}-{Math.min(currentPage * pageSize, totalRows)} of {totalRows}
          </span>
          <div className="flex items-center gap-2">
            <button
              onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
              disabled={currentPage === 1}
              className="p-1 rounded hover:bg-[#f0f0f0] disabled:opacity-30 disabled:cursor-not-allowed"
              style={{ color: GAPURA_GREEN }}
            >
              <ChevronLeft size={14} />
            </button>
            <span className="text-[9px] text-[#666]">
              Page {currentPage} of {totalPages}
            </span>
            <button
              onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))}
              disabled={currentPage === totalPages}
              className="p-1 rounded hover:bg-[#f0f0f0] disabled:opacity-30 disabled:cursor-not-allowed"
              style={{ color: GAPURA_GREEN }}
            >
              <ChevronRight size={14} />
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

'use client';

import { useState } from 'react';
import { ChevronLeft, ChevronRight } from 'lucide-react';
import type { QueryResult } from '@/types/builder';
import { formatDisplayValue } from '@/lib/chart-utils';

interface CustomTableProps {
  result: QueryResult;
  title?: string;
}

const GAPURA_GREEN = '#6b8e3d';
const GAPURA_GREEN_DARK = '#5a7a3a';

function formatValue(val: unknown, colName: string): string {
  return formatDisplayValue(val, colName);
}

function isNumericColumn(rows: Record<string, unknown>[], col: string): boolean {
  let numericCount = 0;
  let totalCount = 0;

  for (const row of rows.slice(0, 10)) {
    const val = row[col];
    if (val !== null && val !== undefined) {
      totalCount++;
      if (typeof val === 'number' || (!isNaN(Number(val)) && String(val).trim() !== '')) {
        numericCount++;
      }
    }
  }

  return totalCount > 0 && numericCount / totalCount > 0.8;
}

export function CustomTable({ result, title }: CustomTableProps) {
  const columns = result.columns;
  const allRows = result.rows as Record<string, unknown>[];
  const totalRows = allRows.length;

  // Pagination
  const pageSize = 100;
  const [currentPage, setCurrentPage] = useState(1);
  const totalPages = Math.ceil(totalRows / pageSize);
  const startIdx = (currentPage - 1) * pageSize;
  const endIdx = Math.min(startIdx + pageSize, totalRows);
  const displayRows = allRows.slice(startIdx, endIdx);

  // Determine numeric columns for alignment
  const numericCols = new Set<string>();
  columns.forEach(col => {
    if (isNumericColumn(allRows, col)) {
      numericCols.add(col);
    }
  });

  return (
    <div className="w-full h-full flex flex-col bg-white rounded-lg border border-[#e0e0e0] overflow-hidden">
      {/* Header */}
      {title && (
        <div 
          className="px-4 py-2 text-white text-xs font-bold"
          style={{ backgroundColor: GAPURA_GREEN }}
        >
          {title}
        </div>
      )}

      {/* Table */}
      <div className="flex-1 overflow-auto">
        <table className="w-full border-collapse">
          <thead>
            <tr style={{ backgroundColor: GAPURA_GREEN }}>
              <th 
                className="px-3 py-2 text-left text-xs font-bold text-white border-r border-[#5a7a3a]"
                style={{ backgroundColor: GAPURA_GREEN_DARK }}
              >
                #
              </th>
              {columns.map((col, idx) => (
                <th
                  key={col}
                  className="px-3 py-2 text-xs font-bold text-white border-r border-[#5a7a3a] last:border-r-0 whitespace-nowrap"
                  style={{ 
                    backgroundColor: GAPURA_GREEN,
                    textAlign: numericCols.has(col) ? 'right' : 'left'
                  }}
                >
                  {col.replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase())}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {displayRows.map((row, idx) => (
              <tr
                key={idx}
                className="border-b border-[#f0f0f0] transition-colors"
                style={{ 
                  backgroundColor: idx % 2 === 0 ? '#ffffff' : '#f9f9f9'
                }}
              >
                <td className="px-3 py-2 text-[11px] text-[#999] border-r border-[#f0f0f0]">
                  {startIdx + idx + 1}
                </td>
                {columns.map(col => {
                  const val = row[col];
                  const isNum = numericCols.has(col);
                  const formatted = formatValue(val, col);
                  const isLong = formatted.length > 50;

                  return (
                    <td
                      key={col}
                      className="px-3 py-2 text-[11px] text-[#333] border-r border-[#f0f0f0] last:border-r-0"
                      style={{ 
                        textAlign: isNum ? 'right' : 'left',
                        maxWidth: 300
                      }}
                      title={isLong ? formatted : undefined}
                    >
                      <span className={isLong ? 'truncate block' : ''}>
                        {isLong ? formatted.substring(0, 47) + '...' : formatted}
                      </span>
                    </td>
                  );
                })}
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Pagination */}
      {totalRows > pageSize && (
        <div className="flex items-center justify-between px-4 py-2 border-t border-[#e0e0e0] bg-white">
          <span className="text-[10px] text-[#666]">
            Showing {startIdx + 1}-{endIdx} of {totalRows} records
          </span>
          <div className="flex items-center gap-2">
            <button
              onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
              disabled={currentPage === 1}
              className="p-1 rounded hover:bg-[#f0f0f0] disabled:opacity-30 disabled:cursor-not-allowed"
              style={{ color: GAPURA_GREEN }}
            >
              <ChevronLeft size={16} />
            </button>
            <span className="text-[10px] text-[#666]">
              Page {currentPage} of {totalPages}
            </span>
            <button
              onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))}
              disabled={currentPage === totalPages}
              className="p-1 rounded hover:bg-[#f0f0f0] disabled:opacity-30 disabled:cursor-not-allowed"
              style={{ color: GAPURA_GREEN }}
            >
              <ChevronRight size={16} />
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

