import { useState, useEffect } from 'react';
import { PrismSelect } from '@/components/ui/PrismSelect';

interface DynamicFilterHeaderProps {
  onFilterChange: (filters: any) => void;
  initialFilters?: any;
  variant?: 'default' | 'white';
}

export function DynamicFilterHeader({ onFilterChange, initialFilters, variant = 'default' }: DynamicFilterHeaderProps) {
  const [selectedHub, setSelectedHub] = useState(initialFilters?.hub || 'all');
  const [selectedBranch, setSelectedBranch] = useState(initialFilters?.branch || 'all');
  const [selectedMaskapai, setSelectedMaskapai] = useState(initialFilters?.maskapai || 'all');
  const [selectedAirlines, setSelectedAirlines] = useState(initialFilters?.airlines || 'all');
  const [selectedCategory, setSelectedCategory] = useState(initialFilters?.category || 'all');
  const [selectedArea, setSelectedArea] = useState(initialFilters?.area || 'all');

  const [options, setOptions] = useState<any>({
    hub: [{ value: 'all', label: 'HUB: All' }],
    branch: [{ value: 'all', label: 'Branch: All' }],
    airline: [{ value: 'all', label: 'Airlines: All' }],
    airline_type: [{ value: 'all', label: 'Maskapai: All' }],
    main_category: [{ value: 'all', label: 'Category: All' }],
    area: [{ value: 'all', label: 'Area: All' }]
  });

  useEffect(() => {
    async function fetchFilters() {
      try {
        const fields = ['hub', 'branch', 'airline', 'airline_type', 'main_category', 'area'].join(',');
        const res = await fetch(`/api/dashboards/filter-options?fields=${fields}`);
        const data = await res.json();

        const mapToOptions = (vals: string[]) => [
          { value: 'all', label: 'All' },
          ...(vals || []).map(v => ({ value: v, label: v }))
        ];

        setOptions({
          hub: mapToOptions(data.hub),
          branch: mapToOptions(data.branch),
          airline: mapToOptions(data.airline),
          airline_type: mapToOptions(data.airline_type),
          main_category: mapToOptions(data.main_category),
          area: mapToOptions(data.area)
        });
      } catch (err) {
        console.error('Error loading filters:', err);
      }
    }
    fetchFilters();
  }, []);

  useEffect(() => {
    onFilterChange({
      hub: selectedHub,
      branch: selectedBranch,
      maskapai: selectedMaskapai,
      airlines: selectedAirlines,
      category: selectedCategory,
      area: selectedArea
    });
  }, [selectedHub, selectedBranch, selectedMaskapai, selectedAirlines, selectedCategory, selectedArea, onFilterChange]);

  return (
    <div className="flex flex-wrap items-center gap-3">
      <div className="w-32">
        <PrismSelect 
          options={options.hub} 
          value={selectedHub} 
          onChange={setSelectedHub} 
          placeholder="HUB" 
          variant={variant}
          label="HUB Area"
        />
      </div>
      <div className="w-32">
        <PrismSelect 
          options={options.branch} 
          value={selectedBranch} 
          onChange={setSelectedBranch} 
          placeholder="Branch" 
          variant={variant}
          label="Branch / Station"
        />
      </div>
      <div className="w-32">
        <PrismSelect 
          options={options.airline_type} 
          value={selectedMaskapai} 
          onChange={setSelectedMaskapai} 
          placeholder="Maskapai" 
          variant={variant}
          label="Domestic/Intl"
        />
      </div>
      <div className="w-32">
        <PrismSelect 
          options={options.airline} 
          value={selectedAirlines} 
          onChange={setSelectedAirlines} 
          placeholder="Airlines" 
          variant={variant}
          label="Airlines Name"
        />
      </div>
      <div className="w-32">
        <PrismSelect 
          options={options.main_category} 
          value={selectedCategory} 
          onChange={setSelectedCategory} 
          placeholder="Category" 
          variant={variant}
          label="Case Category"
        />
      </div>
      <div className="w-32">
        <PrismSelect 
          options={options.area} 
          value={selectedArea} 
          onChange={setSelectedArea} 
          placeholder="Area" 
          variant={variant}
          label="Ops. Area"
        />
      </div>
    </div>
  );
}

'use client';

import { useState, useMemo } from 'react';
import {
  Search, Calendar, Hash, Type, ToggleLeft, Key,
  ChevronDown, ChevronRight, Link2, Check, Database, Columns3,
} from 'lucide-react';
import { TABLES, getJoinsForSource } from '@/lib/builder/schema';
import type { FieldDef, JoinDef } from '@/types/builder';
import { cn } from '@/lib/utils';

interface FieldSidebarProps {
  source: string;
  activeJoins: string[];
  onFieldClick: (table: string, field: FieldDef) => void;
  onToggleJoin: (joinKey: string) => void;
  onSetSource: (source: string) => void;
}

const FIELD_TYPE_ICONS: Record<string, typeof Type> = {
  string: Type,
  number: Hash,
  date: Calendar,
  datetime: Calendar,
  boolean: ToggleLeft,
  uuid: Key,
};

const FIELD_TYPE_COLORS: Record<string, string> = {
  string: 'text-blue-500',
  number: 'text-emerald-500',
  date: 'text-amber-500',
  datetime: 'text-amber-500',
  boolean: 'text-purple-500',
  uuid: 'text-gray-400',
};

const FIELD_TYPE_LABELS: Record<string, string> = {
  string: 'Teks',
  number: 'Angka',
  date: 'Tanggal',
  datetime: 'Waktu',
  boolean: 'Ya/Tidak',
  uuid: 'ID',
};

export function FieldSidebar({
  source,
  activeJoins,
  onFieldClick,
  onToggleJoin,
  onSetSource,
}: FieldSidebarProps) {
  const [search, setSearch] = useState('');
  const [expandedTables, setExpandedTables] = useState<Set<string>>(new Set([source]));

  const availableJoins = useMemo(() => getJoinsForSource(source), [source]);

  const visibleTables = useMemo(() => {
    const tables = [TABLES.find(t => t.name === source)!];
    for (const joinKey of activeJoins) {
      const joinDef = availableJoins.find(j => j.key === joinKey);
      if (joinDef) {
        const t = TABLES.find(tb => tb.name === joinDef.to);
        if (t) tables.push(t);
      }
    }
    return tables.filter(Boolean);
  }, [source, activeJoins, availableJoins]);

  const toggleTable = (name: string) => {
    setExpandedTables(prev => {
      const next = new Set(prev);
      if (next.has(name)) next.delete(name);
      else next.add(name);
      return next;
    });
  };

  const filterFields = (fields: FieldDef[]) => {
    if (!search) return fields;
    const q = search.toLowerCase();
    return fields.filter(f => f.label.toLowerCase().includes(q) || f.name.toLowerCase().includes(q));
  };

  const totalFields = visibleTables.reduce((sum, t) => sum + filterFields(t.fields).length, 0);

  return (
    <div className="flex flex-col h-full bg-[var(--surface-1)] border-r border-[var(--surface-4)]">
      {/* Header */}
      <div className="p-3 border-b border-[var(--surface-4)]">
        <div className="flex items-center gap-2 mb-2">
          <Database size={14} className="text-[var(--brand-primary)]" />
          <span className="text-xs font-bold text-[var(--text-primary)]">Pilih Data</span>
        </div>

        {/* Source selector */}
        <label className="text-[10px] text-[var(--text-muted)] mb-1 block">
          Tabel utama:
        </label>
        <select
          value={source}
          onChange={e => onSetSource(e.target.value)}
          className="w-full px-2 py-1.5 text-sm bg-[var(--surface-2)] border border-[var(--surface-4)] rounded-lg text-[var(--text-primary)] focus:outline-none focus:ring-1 focus:ring-[var(--brand-primary)]"
        >
          {TABLES.map(t => (
            <option key={t.name} value={t.name}>{t.label}</option>
          ))}
        </select>
      </div>

      {/* Joins */}
      {availableJoins.length > 0 && (
        <div className="p-3 border-b border-[var(--surface-4)]">
          <label className="text-[10px] text-[var(--text-muted)] mb-2 flex items-center gap-1">
            <Link2 size={10} />
            Gabungkan dengan tabel lain:
          </label>
          <div className="flex flex-wrap gap-1.5">
            {availableJoins.map(j => {
              const active = activeJoins.includes(j.key);
              return (
                <button
                  key={j.key}
                  onClick={() => onToggleJoin(j.key)}
                  className={cn(
                    "px-2 py-1 text-[10px] font-medium rounded-md border transition-all",
                    active
                      ? "bg-[var(--brand-primary)] text-white border-[var(--brand-primary)]"
                      : "bg-[var(--surface-2)] text-[var(--text-secondary)] border-[var(--surface-4)] hover:border-[var(--brand-primary)]"
                  )}
                >
                  {active && <Check size={10} className="inline mr-0.5" />}
                  {j.label}
                </button>
              );
            })}
          </div>
        </div>
      )}

      {/* Search */}
      <div className="p-3 border-b border-[var(--surface-4)]">
        <div className="relative">
          <Search size={14} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-[var(--text-muted)]" />
          <input
            type="text"
            placeholder="Cari field..."
            value={search}
            onChange={e => setSearch(e.target.value)}
            className="w-full pl-8 pr-3 py-1.5 text-sm bg-[var(--surface-2)] border border-[var(--surface-4)] rounded-lg text-[var(--text-primary)] placeholder:text-[var(--text-muted)] focus:outline-none focus:ring-1 focus:ring-[var(--brand-primary)]"
          />
        </div>
        <span className="text-[10px] text-[var(--text-muted)] mt-1.5 block">{totalFields} field tersedia</span>
      </div>

      {/* Fields list */}
      <div className="flex-1 overflow-y-auto p-2">
        {visibleTables.map(table => {
          const fields = filterFields(table.fields);
          const isExpanded = expandedTables.has(table.name);
          const isSource = table.name === source;

          return (
            <div key={table.name} className="mb-1">
              <button
                onClick={() => toggleTable(table.name)}
                className="w-full flex items-center gap-2 px-2 py-1.5 text-xs font-bold text-[var(--text-secondary)] hover:bg-[var(--surface-2)] rounded-md transition-colors"
              >
                {isExpanded ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
                <Columns3 size={12} className={isSource ? 'text-[var(--brand-primary)]' : 'text-[var(--text-muted)]'} />
                <span className="uppercase tracking-wider">{table.label}</span>
                {isSource && <span className="text-[9px] text-[var(--brand-primary)] font-normal">(utama)</span>}
                <span className="text-[var(--text-muted)] font-normal ml-auto">{fields.length}</span>
              </button>

              {isExpanded && (
                <div className="ml-2 space-y-0.5">
                  {fields.map(field => {
                    const Icon = FIELD_TYPE_ICONS[field.type] || Type;
                    const colorClass = FIELD_TYPE_COLORS[field.type] || 'text-[var(--text-muted)]';
                    return (
                      <button
                        key={`${table.name}.${field.name}`}
                        onClick={() => onFieldClick(table.name, field)}
                        className="w-full flex items-center gap-2 px-2 py-1.5 text-xs text-[var(--text-secondary)] hover:bg-[var(--surface-2)] hover:text-[var(--text-primary)] rounded-md transition-colors group"
                        title={`Klik untuk menambahkan "${field.label}" ke query`}
                      >
                        <Icon size={12} className={cn("shrink-0 transition-colors", colorClass)} />
                        <span className="truncate flex-1 text-left">{field.label}</span>
                        <span className="text-[9px] text-[var(--text-muted)] opacity-0 group-hover:opacity-100 transition-opacity">
                          {FIELD_TYPE_LABELS[field.type] || field.type}
                        </span>
                      </button>
                    );
                  })}
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}

'use client';

import { X, Play, ChevronDown, ChevronRight, ArrowUpDown, Layers, BarChart3, Filter, ArrowDownUp, Zap } from 'lucide-react';
import type {
  QueryDefinition,
  QueryDimension,
  QueryMeasure,
  QueryFilter,
  QuerySort,
  DateGranularity,
  AggregateFunction,
  FieldDef,
} from '@/types/builder';
import { getFieldDef } from '@/lib/builder/schema';
import { FilterBuilder } from './FilterBuilder';
import { cn } from '@/lib/utils';
import { useState } from 'react';

interface QueryPanelProps {
  query: QueryDefinition;
  availableFields: Array<{ table: string; field: FieldDef }>;
  loading: boolean;
  onRemoveDimension: (index: number) => void;
  onUpdateDimension: (index: number, updates: Partial<QueryDimension>) => void;
  onRemoveMeasure: (index: number) => void;
  onUpdateMeasure: (index: number, updates: Partial<QueryMeasure>) => void;
  onAddFilter: (filter: QueryFilter) => void;
  onRemoveFilter: (index: number) => void;
  onUpdateFilter: (index: number, updates: Partial<QueryFilter>) => void;
  onAddSort: (sort: QuerySort) => void;
  onRemoveSort: (index: number) => void;
  onExecute: () => void;
}

const DATE_GRANULARITIES: { value: DateGranularity; label: string }[] = [
  { value: 'day', label: 'Hari' },
  { value: 'week', label: 'Minggu' },
  { value: 'month', label: 'Bulan' },
  { value: 'quarter', label: 'Kuartal' },
  { value: 'year', label: 'Tahun' },
];

const AGG_FUNCTIONS: { value: AggregateFunction; label: string }[] = [
  { value: 'COUNT', label: 'Jumlah (COUNT)' },
  { value: 'COUNT_DISTINCT', label: 'Jumlah Unik' },
  { value: 'SUM', label: 'Total (SUM)' },
  { value: 'AVG', label: 'Rata-rata (AVG)' },
  { value: 'MIN', label: 'Minimum' },
  { value: 'MAX', label: 'Maksimum' },
];

export function QueryPanel({
  query,
  availableFields,
  loading,
  onRemoveDimension,
  onUpdateDimension,
  onRemoveMeasure,
  onUpdateMeasure,
  onAddFilter,
  onRemoveFilter,
  onUpdateFilter,
  onAddSort,
  onRemoveSort,
  onExecute,
}: QueryPanelProps) {
  const [showFilters, setShowFilters] = useState(false);
  const [showSorts, setShowSorts] = useState(false);

  const hasDimensions = query.dimensions.length > 0;
  const hasMeasures = query.measures.length > 0;
  const canExecute = hasDimensions || hasMeasures;

  return (
    <div className="flex flex-col gap-2 p-3 bg-[var(--surface-1)]">
      {/* Dimensions */}
      <div>
        <div className="flex items-center gap-2 mb-1.5">
          <Layers size={12} className={hasDimensions ? "text-blue-500" : "text-[var(--text-muted)]"} />
          <label className="text-[10px] font-bold uppercase tracking-wider text-[var(--text-muted)]">
            Dimensi
          </label>
        </div>
        <div className="flex flex-wrap gap-1.5 min-h-[28px] pl-5">
          {!hasDimensions && (
            <span className="text-[10px] text-[var(--text-muted)] italic py-1">
              Klik field teks/tanggal di panel kiri
            </span>
          )}
          {query.dimensions.map((dim, idx) => {
            const fieldDef = getFieldDef(dim.table, dim.field);
            const isDate = fieldDef && (fieldDef.type === 'date' || fieldDef.type === 'datetime');
            return (
              <div key={idx} className="flex items-center gap-1 px-2 py-0.5 text-xs bg-blue-50 text-blue-700 border border-blue-200 rounded-md">
                <span className="font-medium">{fieldDef?.label || dim.field}</span>
                {isDate && (
                  <select
                    value={dim.dateGranularity || 'month'}
                    onChange={e => onUpdateDimension(idx, { dateGranularity: e.target.value as DateGranularity })}
                    className="px-1 py-0 text-[10px] bg-transparent border-none focus:outline-none cursor-pointer"
                  >
                    {DATE_GRANULARITIES.map(g => (
                      <option key={g.value} value={g.value}>{g.label}</option>
                    ))}
                  </select>
                )}
                <button onClick={() => onRemoveDimension(idx)} className="hover:text-red-500 transition-colors">
                  <X size={12} />
                </button>
              </div>
            );
          })}
        </div>
      </div>

      {/* Measures */}
      <div>
        <div className="flex items-center gap-2 mb-1.5">
          <BarChart3 size={12} className={hasMeasures ? "text-emerald-500" : "text-[var(--text-muted)]"} />
          <label className="text-[10px] font-bold uppercase tracking-wider text-[var(--text-muted)]">
            Ukuran
          </label>
        </div>
        <div className="flex flex-wrap gap-1.5 min-h-[28px] pl-5">
          {!hasMeasures && (
            <span className="text-[10px] text-[var(--text-muted)] italic py-1">
              Klik field angka di panel kiri
            </span>
          )}
          {query.measures.map((m, idx) => {
            const fieldDef = getFieldDef(m.table, m.field);
            return (
              <div key={idx} className="flex items-center gap-1 px-2 py-0.5 text-xs bg-emerald-50 text-emerald-700 border border-emerald-200 rounded-md">
                <select
                  value={m.function}
                  onChange={e => onUpdateMeasure(idx, { function: e.target.value as AggregateFunction })}
                  className="px-0 py-0 text-[10px] bg-transparent border-none focus:outline-none cursor-pointer font-bold"
                >
                  {AGG_FUNCTIONS.map(fn => (
                    <option key={fn.value} value={fn.value}>{fn.label}</option>
                  ))}
                </select>
                <span className="font-medium">({fieldDef?.label || m.field})</span>
                <button onClick={() => onRemoveMeasure(idx)} className="hover:text-red-500 transition-colors">
                  <X size={12} />
                </button>
              </div>
            );
          })}
        </div>
      </div>

      {/* Optional: Filters */}
      <div>
        <button
          onClick={() => setShowFilters(!showFilters)}
          className="flex items-center gap-2 text-[10px] font-bold uppercase tracking-wider text-[var(--text-muted)] hover:text-[var(--text-primary)] transition-colors pl-5"
        >
          <Filter size={10} />
          {showFilters ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
          Filter {query.filters.length > 0 && (
            <span className="px-1.5 py-0.5 rounded-full bg-amber-100 text-amber-600 text-[9px] font-bold">
              {query.filters.length}
            </span>
          )}
          <span className="text-[9px] font-normal normal-case text-[var(--text-muted)]">
            (opsional)
          </span>
        </button>
        {showFilters && (
          <div className="mt-2 pl-5">
            <FilterBuilder
              filters={query.filters}
              availableFields={availableFields}
              onAdd={onAddFilter}
              onRemove={onRemoveFilter}
              onUpdate={onUpdateFilter}
            />
          </div>
        )}
      </div>

      {/* Optional: Sorts */}
      <div>
        <button
          onClick={() => setShowSorts(!showSorts)}
          className="flex items-center gap-2 text-[10px] font-bold uppercase tracking-wider text-[var(--text-muted)] hover:text-[var(--text-primary)] transition-colors pl-5"
        >
          <ArrowDownUp size={10} />
          {showSorts ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
          Urutkan {query.sorts.length > 0 && (
            <span className="px-1.5 py-0.5 rounded-full bg-purple-100 text-purple-600 text-[9px] font-bold">
              {query.sorts.length}
            </span>
          )}
          <span className="text-[9px] font-normal normal-case text-[var(--text-muted)]">
            (opsional)
          </span>
        </button>
        {showSorts && (
          <div className="mt-2 pl-5 space-y-1">
            {query.sorts.map((s, idx) => (
              <div key={idx} className="flex items-center gap-2">
                <span className="text-xs text-[var(--text-secondary)]">{s.alias || s.field}</span>
                <button
                  onClick={() => {
                    onRemoveSort(idx);
                    onAddSort({ ...s, direction: s.direction === 'asc' ? 'desc' : 'asc' });
                  }}
                  className="text-[10px] text-[var(--text-muted)] hover:text-[var(--brand-primary)]"
                >
                  <ArrowUpDown size={12} />
                </button>
                <span className="text-[10px] text-[var(--text-muted)]">{s.direction === 'asc' ? 'A→Z' : 'Z→A'}</span>
                <button onClick={() => onRemoveSort(idx)} className="text-[var(--text-muted)] hover:text-red-500">
                  <X size={12} />
                </button>
              </div>
            ))}
            <button
              onClick={() => {
                if (availableFields.length > 0) {
                  const f = availableFields[0];
                  onAddSort({ field: `${f.table}_${f.field.name}`, direction: 'asc' });
                }
              }}
              className="text-[10px] text-[var(--text-muted)] hover:text-[var(--brand-primary)]"
            >
              + Tambah Urutan
            </button>
          </div>
        )}
      </div>

      {/* Run Query Button */}
      <div className="flex items-center gap-3 pt-2 border-t border-[var(--surface-4)]">
        <button
          onClick={onExecute}
          disabled={loading || !canExecute}
          className={cn(
            "flex items-center gap-2 px-4 py-2 text-sm font-bold rounded-lg transition-all",
            loading
              ? "bg-[var(--surface-3)] text-[var(--text-muted)] cursor-not-allowed"
              : canExecute
                ? "bg-[var(--brand-primary)] text-white hover:opacity-90 shadow-sm"
                : "bg-[var(--surface-3)] text-[var(--text-muted)] cursor-not-allowed"
          )}
        >
          {loading ? (
            <div className="w-3.5 h-3.5 border-2 border-[var(--text-muted)] border-t-transparent rounded-full animate-spin" />
          ) : (
            <Zap size={14} />
          )}
          {loading ? 'Menjalankan...' : 'Jalankan Query'}
        </button>
        <span className="text-[10px] text-[var(--text-muted)]">Ctrl+Enter</span>
        {!canExecute && !loading && (
          <span className="text-[10px] text-amber-500">Pilih minimal 1 dimensi atau ukuran</span>
        )}
      </div>
    </div>
  );
}

'use client';

import { useState } from 'react';
import { Table2, BarChart3, Clock, Rows3, AlertCircle } from 'lucide-react';
import { DataTable } from './DataTable';
import type { QueryResult, ChartVisualization } from '@/types/builder';
import { cn } from '@/lib/utils';

interface ResultsPanelProps {
  result: QueryResult | null;
  loading: boolean;
  error: string | null;
  visualization: ChartVisualization;
  chartPreview: React.ReactNode;
}

export function ResultsPanel({ result, loading, error, visualization, chartPreview }: ResultsPanelProps) {
  const [tab, setTab] = useState<'table' | 'chart'>('table');

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center h-full gap-3">
        <div
          className="w-8 h-8 rounded-full border-3 animate-spin"
          style={{ borderColor: 'var(--surface-4)', borderTopColor: 'var(--brand-primary)' }}
        />
        <p className="text-xs text-[var(--text-muted)]">Menjalankan query...</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex flex-col items-center justify-center h-full gap-2 p-4">
        <AlertCircle size={24} className="text-red-400" />
        <p className="text-sm text-red-500 text-center max-w-md">{error}</p>
      </div>
    );
  }

  if (!result) {
    return (
      <div className="flex flex-col items-center justify-center h-full gap-2">
        <Table2 size={32} className="text-[var(--text-muted)] opacity-30" />
        <p className="text-xs text-[var(--text-muted)]">Jalankan query untuk melihat hasil</p>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full">
      {/* Tab bar + stats */}
      <div className="flex items-center justify-between px-3 py-1.5 bg-[var(--surface-2)] border-b border-[var(--surface-4)]">
        <div className="flex items-center gap-1">
          <button
            onClick={() => setTab('table')}
            className={cn(
              "flex items-center gap-1 px-2.5 py-1 text-xs font-medium rounded-md transition-colors",
              tab === 'table'
                ? "bg-[var(--surface-1)] text-[var(--text-primary)] shadow-sm"
                : "text-[var(--text-muted)] hover:text-[var(--text-primary)]"
            )}
          >
            <Table2 size={12} /> Tabel
          </button>
          <button
            onClick={() => setTab('chart')}
            className={cn(
              "flex items-center gap-1 px-2.5 py-1 text-xs font-medium rounded-md transition-colors",
              tab === 'chart'
                ? "bg-[var(--surface-1)] text-[var(--text-primary)] shadow-sm"
                : "text-[var(--text-muted)] hover:text-[var(--text-primary)]"
            )}
          >
            <BarChart3 size={12} /> Grafik
          </button>
        </div>

        <div className="flex items-center gap-3">
          <div className="flex items-center gap-1 text-[10px] text-[var(--text-muted)]">
            <Rows3 size={10} />
            {result.rowCount} baris
          </div>
          <div className="flex items-center gap-1 text-[10px] text-[var(--text-muted)]">
            <Clock size={10} />
            {result.executionTimeMs}ms
          </div>
        </div>
      </div>

      {/* Content */}
      <div className="flex-1 overflow-hidden">
        {tab === 'table' ? (
          <DataTable columns={result.columns} rows={result.rows} />
        ) : (
          <div className="p-4 h-full">
            {chartPreview}
          </div>
        )}
      </div>
    </div>
  );
}

'use client';

import { Pencil, Trash2, Eye } from 'lucide-react';
import { useRouter } from 'next/navigation';
import type { DashboardTile, QueryResult } from '@/types/builder';
import { ChartPreview } from './ChartPreview';

interface TileCardProps {
  tile: DashboardTile;
  result?: QueryResult | null;
  error?: string | null;
  onEdit: (id: string) => void;
  onRemove: (id: string) => void;
  onResize: (id: string, w: number, h: number) => void;
  dashboardId?: string;
}

const SIZE_OPTIONS = [
  { label: '1/3', w: 4, h: 2 },
  { label: '1/2', w: 6, h: 2 },
  { label: 'Full', w: 12, h: 2 },
  { label: '1/2 Tall', w: 6, h: 3 },
  { label: 'Full Tall', w: 12, h: 3 },
];

const GAPURA_GREEN = '#6b8e3d';

export function TileCard({ tile, result, error, onEdit, onRemove, onResize, dashboardId }: TileCardProps) {
  const router = useRouter();
  const title = tile.visualization.title || 'Tile Tanpa Judul';
  const hasDims = tile.query.dimensions.length > 0;
  const hasMeasures = tile.query.measures.length > 0;
  const isConfigured = hasDims || hasMeasures;
  const isTable = tile.visualization.chartType === 'table';

  const handleViewDetails = () => {
    if (!result) return;

    // Store data in sessionStorage for the detail page
    const detailData = {
      tile,
      result,
      dashboardId,
      timestamp: Date.now()
    };

    sessionStorage.setItem('chartDetailData', JSON.stringify(detailData));

    // Navigate to detail page
    const params = new URLSearchParams();
    if (dashboardId) params.set('dashboardId', dashboardId);
    params.set('tileId', tile.id);

    router.push(`/dashboard/chart-detail?${params.toString()}`);
  };

  return (
    <div 
      className="group bg-white rounded-xl overflow-hidden flex flex-col h-full transition-shadow hover:shadow-md border border-[#eaeaea]"
    >
      {/* Header */}
      <div className="flex items-center justify-between px-4 py-2.5 border-b border-[#f0f0f0]">
        <h4 className="m-0 text-sm font-bold text-[#333] truncate flex-1">
          {title}
        </h4>
        <div className="flex items-center gap-1 ml-2">
          {/* View Details button - always visible */}
          {result && result.rows.length > 0 && (
            <button
              onClick={handleViewDetails}
              className="flex items-center gap-1 px-2 py-1 text-xs font-medium text-[#6b8e3d] bg-[#e8f5e9] hover:bg-[#c8e6c9] rounded transition-colors"
              title="Lihat Detail"
            >
              <Eye size={14} />
              <span>Detail</span>
            </button>
          )}
          {/* Resize dropdown + edit/delete — visible on hover */}
          <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
            <select
              value={`${tile.layout.w}-${tile.layout.h}`}
              onChange={e => {
                const [w, h] = e.target.value.split('-').map(Number);
                onResize(tile.id, w, h);
              }}
              className="py-0.5 px-1 text-xs bg-transparent border border-[#e0e0e0] rounded text-[#666] outline-none cursor-pointer hover:border-[#6b8e3d]"
            >
              {SIZE_OPTIONS.map(s => (
                <option key={`${s.w}-${s.h}`} value={`${s.w}-${s.h}`}>{s.label}</option>
              ))}
            </select>
            <button
              onClick={() => onEdit(tile.id)}
              className="p-1.5 text-[#666] hover:text-[#6b8e3d] transition-colors"
              title="Edit"
            >
              <Pencil size={14} />
            </button>
            <button
              onClick={() => onRemove(tile.id)}
              className="p-1.5 text-[#666] hover:text-red-500 transition-colors"
              title="Hapus"
            >
              <Trash2 size={14} />
            </button>
          </div>
        </div>
      </div>

      {/* Body */}
      <div className={`flex-1 ${isTable ? 'overflow-hidden' : 'min-h-[150px]'} p-4`}>
        {!isConfigured ? (
          <div
            className="flex items-center justify-center h-full cursor-pointer rounded hover:bg-[#f5f5f5] transition-colors"
            onClick={() => onEdit(tile.id)}
          >
            <p className="text-xs text-[#999]">Klik Edit untuk mengkonfigurasi query</p>
          </div>
        ) : error ? (
          <div className="flex items-center justify-center h-full px-4 text-center">
            <p className="text-xs text-red-500">{error}</p>
          </div>
        ) : result && result.rows.length > 0 ? (
          <ChartPreview 
            visualization={tile.visualization} 
            result={result} 
            compact={tile.layout.w < 6}
          />
        ) : result ? (
          <div className="flex items-center justify-center h-full">
            <p className="text-xs text-[#999]">Tidak ada data</p>
          </div>
        ) : (
          <div className="flex items-center justify-center h-full">
            <p className="text-xs text-[#999]">Menunggu data...</p>
          </div>
        )}
      </div>
    </div>
  );
}

