                />
                <HorizontalBarChart 
                    title="Airlines Report" 
                    data={data.airlines} 
                    onViewDetail={() => handleViewDetail('Airlines Report', data.airlines, 'horizontal_bar')}
                />
                <HorizontalBarChart 
