'use client';

import { useState, useRef, useEffect } from 'react';
import {
    Send,
    X,
    Loader2,
    Link,
    Plus
} from 'lucide-react';
import { cn } from '@/lib/utils';

interface CommentInputProps {
    reportId: string;
    onSuccess?: () => void;
    placeholder?: string;
    compact?: boolean;
}

export function CommentInput({
    reportId,
    onSuccess,
    placeholder = "Ketik pesan...",
    compact = false
}: CommentInputProps) {
    const [content, setContent] = useState('');
    const [sending, setSending] = useState(false);
    const [attachments, setAttachments] = useState<string[]>([]);
    const [linkInput, setLinkInput] = useState('');
    const [showLinkInput, setShowLinkInput] = useState(false);
    const textareaRef = useRef<HTMLTextAreaElement>(null);

    // Auto-resize textarea
    useEffect(() => {
        if (textareaRef.current) {
            textareaRef.current.style.height = 'auto';
            textareaRef.current.style.height = textareaRef.current.scrollHeight + 'px';
        }
    }, [content]);

    const handleAddLink = () => {
        const link = linkInput.trim();
        if (!link) return;

        try {
            new URL(link);
        } catch {
            return;
        }

        setAttachments(prev => [...prev, link]);
        setLinkInput('');
        setShowLinkInput(false);
    };

    const removeAttachment = (index: number) => {
        setAttachments(prev => prev.filter((_, i) => i !== index));
    };

    const handleSubmit = async (e?: React.FormEvent) => {
        e?.preventDefault();
        if ((!content.trim() && attachments.length === 0) || sending) return;

        setSending(true);
        try {
            const res = await fetch(`/api/reports/${reportId}/comments`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    content,
                    attachments
                })
            });

            if (res.ok) {
                setContent('');
                setAttachments([]);
                if (onSuccess) onSuccess();
                if (textareaRef.current) textareaRef.current.style.height = 'auto';
            }
        } catch (err) {
            console.error('Failed to send comment', err);
        } finally {
            setSending(false);
        }
    };

    const handleKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === 'Enter' && !e.shiftKey) {
            e.preventDefault();
            handleSubmit();
        }
    };

    const canSubmit = content.trim() || attachments.length > 0;

    return (
        <div className="space-y-3">
            {/* Textarea */}
            <textarea
                ref={textareaRef}
                value={content}
                onChange={(e) => setContent(e.target.value)}
                onKeyDown={handleKeyDown}
                placeholder={placeholder}
                className="w-full bg-gray-50 border border-gray-200 rounded-xl p-3 text-sm focus:ring-2 focus:ring-[var(--brand-primary)]/20 focus:border-[var(--brand-primary)] outline-none transition-all resize-none"
                rows={3}
            />

            {/* Attachments Preview */}
            {attachments.length > 0 && (
                <div className="space-y-1.5">
                    {attachments.map((url, i) => (
                        <div key={i} className="flex items-center gap-2 p-2 bg-blue-50 rounded-lg border border-blue-200">
                            <Link size={12} className="text-blue-500 shrink-0" />
                            <a href={url} target="_blank" rel="noopener noreferrer" className="text-xs text-blue-600 hover:underline truncate flex-1">{url}</a>
                            <button
                                type="button"
                                onClick={() => removeAttachment(i)}
                                className="p-0.5 hover:bg-red-100 text-red-500 rounded transition-colors"
                            >
                                <X size={12} />
                            </button>
                        </div>
                    ))}
                </div>
            )}

            {/* Link Input */}
            {showLinkInput && (
                <div className="flex gap-2">
                    <input
                        type="url"
                        value={linkInput}
                        onChange={(e) => setLinkInput(e.target.value)}
                        placeholder="https://drive.google.com/..."
                        className="flex-1 text-xs bg-gray-50 border border-gray-200 rounded-lg px-3 py-2 focus:ring-2 focus:ring-[var(--brand-primary)]/20 focus:border-[var(--brand-primary)] outline-none"
                        onKeyDown={(e) => { if (e.key === 'Enter') { e.preventDefault(); handleAddLink(); } }}
                        autoFocus
                    />
                    <button
                        type="button"
                        onClick={handleAddLink}
                        className="px-3 py-2 bg-[var(--brand-primary)] text-white rounded-lg text-xs font-semibold hover:brightness-110 transition-all"
                    >
                        <Plus size={14} />
                    </button>
                    <button
                        type="button"
                        onClick={() => { setShowLinkInput(false); setLinkInput(''); }}
                        className="px-2 py-2 text-gray-400 hover:text-gray-600 transition-colors"
                    >
                        <X size={14} />
                    </button>
                </div>
            )}

            {/* Actions */}
            <div className="flex items-center gap-2">
                {/* Add Link Button */}
                <button
                    type="button"
                    onClick={() => setShowLinkInput(true)}
                    className={cn(
                        "flex items-center gap-1.5 px-3 py-2 rounded-lg border border-gray-200 bg-white hover:bg-gray-50 cursor-pointer transition-colors text-sm text-gray-600",
                        showLinkInput && "opacity-50 pointer-events-none"
                    )}
                >
                    <Link size={14} />
                    <span className="text-xs font-medium">Lampiran</span>
                </button>

                <div className="flex-1" />

                {/* Submit Button */}
                <button
                    onClick={() => handleSubmit()}
                    disabled={!canSubmit || sending}
                    className={cn(
                        "flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-semibold transition-all",
                        canSubmit && !sending
                            ? "bg-[var(--brand-primary)] text-white hover:brightness-110 shadow-sm"
                            : "bg-gray-100 text-gray-400 cursor-not-allowed"
                    )}
                >
                    {sending ? <Loader2 size={14} className="animate-spin" /> : <Send size={14} />}
                    <span>Kirim</span>
                </button>
            </div>
        </div>
    );
}

'use client';

import { useState, useCallback } from 'react';
import { motion, Reorder } from 'framer-motion';

interface ChartConfig {
  id: string;
  title: string;
  chartType: 'pie' | 'bar' | 'line' | 'area' | 'kpi';
  dataField: 'airline' | 'category' | 'status' | 'severity' | 'area' | 'station' | 'division';
  width: 'full' | 'half' | 'third';
}

interface DashboardBuilderProps {
  onSave: (name: string, description: string, charts: ChartConfig[]) => Promise<{ embedUrl: string } | null>;
}

const CHART_TYPES = [
  { value: 'pie', label: 'Pie Chart', icon: '◐' },
  { value: 'bar', label: 'Bar Chart', icon: '▭' },
  { value: 'line', label: 'Line Chart', icon: '📈' },
  { value: 'area', label: 'Area Chart', icon: '▲' },
  { value: 'kpi', label: 'KPI Card', icon: '#' }
] as const;

const DATA_FIELDS = [
  { value: 'airline', label: 'Airline' },
  { value: 'category', label: 'Kategori' },
  { value: 'status', label: 'Status' },
  { value: 'severity', label: 'Severity' },
  { value: 'area', label: 'Area' },
  { value: 'station', label: 'Station' },
  { value: 'division', label: 'Division' }
] as const;

const WIDTH_OPTIONS = [
  { value: 'half', label: '50%' },
  { value: 'full', label: '100%' },
  { value: 'third', label: '33%' }
] as const;

export function DashboardBuilder({ onSave }: DashboardBuilderProps) {
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [charts, setCharts] = useState<ChartConfig[]>([]);
  const [saving, setSaving] = useState(false);
  const [embedUrl, setEmbedUrl] = useState<string | null>(null);

  const addChart = useCallback(() => {
    const newChart: ChartConfig = {
      id: `chart-${Date.now()}`,
      title: `Chart ${charts.length + 1}`,
      chartType: 'pie',
      dataField: 'airline',
      width: 'half'
    };
    setCharts(prev => [...prev, newChart]);
  }, [charts.length]);

  const updateChart = useCallback((id: string, updates: Partial<ChartConfig>) => {
    setCharts(prev => prev.map(c => c.id === id ? { ...c, ...updates } : c));
  }, []);

  const removeChart = useCallback((id: string) => {
    setCharts(prev => prev.filter(c => c.id !== id));
  }, []);

  const handleSave = async () => {
    if (!name.trim() || charts.length === 0) return;

    setSaving(true);
    try {
      const result = await onSave(name, description, charts);
      if (result?.embedUrl) {
        setEmbedUrl(result.embedUrl);
      }
    } finally {
      setSaving(false);
    }
  };

  const copyUrl = () => {
    if (embedUrl) {
      const fullUrl = `${window.location.origin}${embedUrl}`;
      navigator.clipboard.writeText(fullUrl);
    }
  };

  return (
    <div className="dashboard-builder">
      {/* Success State */}
      {embedUrl && (
        <div className="builder-success">
          <h3>✓ Dashboard Berhasil Dibuat!</h3>
          <p>Link untuk PowerPoint:</p>
          <div className="builder-url-box">
            <code>{window.location.origin}{embedUrl}</code>
            <button onClick={copyUrl} className="builder-copy-btn">Copy</button>
          </div>
          <div className="builder-actions" style={{ marginTop: '1rem' }}>
            <a href={embedUrl} target="_blank" rel="noopener noreferrer" className="builder-btn primary">
              Preview Dashboard
            </a>
            <button onClick={() => { setEmbedUrl(null); setCharts([]); setName(''); }} className="builder-btn secondary">
              Buat Baru
            </button>
          </div>
        </div>
      )}

      {/* Builder Form */}
      {!embedUrl && (
        <>
          <div className="builder-header">
            <h2>Dashboard Builder</h2>
            <p>Drag & drop untuk mengatur urutan chart</p>
          </div>

          {/* Dashboard Info */}
          <div className="builder-section">
            <label className="builder-label">Nama Dashboard</label>
            <input
              type="text"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="e.g., Weekly Airline Report"
              className="builder-input"
            />

            <label className="builder-label" style={{ marginTop: '1rem' }}>Deskripsi (opsional)</label>
            <input
              type="text"
              value={description}
              onChange={(e) => setDescription(e.target.value)}
