'use client';

import { useState, useRef, useEffect } from 'react';
import { Search, ChevronDown, Check, X } from 'lucide-react';

interface Option {
    value: string;
    label: string;
    description?: string;
    icon?: React.ReactNode;
}

interface PrismSelectProps {
    options: Option[];
    value: string;
    onChange: (value: string) => void;
    placeholder?: string;
    label?: string;
    searchable?: boolean;
    required?: boolean;
    variant?: 'default' | 'white';
}

export function PrismSelect({ 
    options, 
    value, 
    onChange, 
    placeholder = 'Select option', 
    label,
    searchable = true,
    required = false,
    variant = 'default'
}: PrismSelectProps) {
    const [isOpen, setIsOpen] = useState(false);
    const [searchTerm, setSearchTerm] = useState('');
    const containerRef = useRef<HTMLDivElement>(null);

    // Close on click outside
    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
                setIsOpen(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    const filteredOptions = options.filter(opt => 
        opt.label.toLowerCase().includes(searchTerm.toLowerCase()) || 
        opt.value.toLowerCase().includes(searchTerm.toLowerCase()) ||
        (opt.description && opt.description.toLowerCase().includes(searchTerm.toLowerCase()))
    );

    const selectedOption = options.find(opt => opt.value === value);

    return (
        <div className="relative" ref={containerRef}>
            {label && (
                <label className={`block text-[10px] font-bold uppercase tracking-wider mb-1.5 ml-1 ${variant === 'white' ? 'text-white/80' : 'text-[var(--text-secondary)]'}`}>
                    {label} {required && <span className="text-[var(--status-error)]">*</span>}
                </label>
            )}

            {/* Trigger Button */}
            <button
                type="button"
                onClick={() => setIsOpen(!isOpen)}
                className={`
                    w-full flex items-center justify-between px-3 py-1.5 rounded-lg border transition-all duration-200
                    ${variant === 'white'
                        ? isOpen 
                            ? 'border-white/40 bg-white/25 text-white shadow-lg' 
                            : 'border-white/10 bg-white/5 text-white/90 hover:bg-white/15 hover:border-white/20'
                        : isOpen 
                            ? 'border-[var(--brand-primary)] bg-[var(--surface-2)] border-2' 
                            : 'border-transparent bg-[var(--surface-3)] hover:bg-[var(--surface-4)] border-2'
                    }
                `}
            >
                {selectedOption ? (
                    <div className="flex flex-col items-start text-left min-w-0">
                        <span className={`font-semibold truncate w-full ${variant === 'white' ? 'text-sm text-white' : 'text-base text-[var(--text-primary)]'}`}>
                            {selectedOption.label}
                        </span>
                        {selectedOption.description && (
                            <span className="text-[10px] opacity-70 truncate w-full">{selectedOption.description}</span>
                        )}
                    </div>
                ) : (
                    <span className={`text-sm ${variant === 'white' ? 'text-white/60' : 'text-[var(--text-muted)]'}`}>{placeholder}</span>
                )}
                <ChevronDown 
                    size={16} 
                    className={`${variant === 'white' ? 'text-white' : 'text-[var(--text-secondary)]'} transition-transform duration-300 ${isOpen ? 'rotate-180' : ''}`} 
                />
            </button>

            {/* Dropdown Menu */}
            {isOpen && (
                <div 
                    className="absolute top-full left-0 right-0 mt-2 p-2 rounded-2xl bg-[var(--surface-2)] border border-[var(--surface-3)] shadow-xl z-50 animate-scale-in origin-top"
                    style={{ maxHeight: '300px', display: 'flex', flexDirection: 'column' }}
                >
                    {/* Search Bar */}
                    {searchable && (
                        <div className="sticky top-0 px-2 pb-2 mb-2 border-b border-[var(--surface-3)]">
                            <div className="relative">
                                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-[var(--text-muted)] w-4 h-4" />
                                <input
                                    type="text"
                                    className="w-full pl-9 pr-4 py-2 rounded-lg bg-[var(--surface-1)] border border-transparent focus:border-[var(--brand-primary)] focus:outline-none text-sm transition-colors"
                                    placeholder="Search..."
                                    value={searchTerm}
                                    onChange={(e) => setSearchTerm(e.target.value)}
                                    autoFocus
                                />
                            </div>
                        </div>
                    )}

                    {/* Options List */}
                    <div className="overflow-y-auto custom-scrollbar flex-1 space-y-1">
                        {filteredOptions.length === 0 ? (
                            <div className="p-4 text-center text-sm text-[var(--text-muted)]">
                                No results found.
                            </div>
                        ) : (
                            filteredOptions.map((opt) => (
                                <button
                                    key={opt.value}
                                    type="button"
                                    onClick={() => {
                                        onChange(opt.value);
                                        setIsOpen(false);
                                        setSearchTerm('');
                                    }}
                                    className={`
                                        w-full flex items-center justify-between px-3 py-2 rounded-lg text-left transition-colors
                                        ${value === opt.value 
                                            ? 'bg-[var(--brand-primary)] text-white' 
                                            : 'hover:bg-[var(--surface-3)] text-[var(--text-primary)]'
                                        }
                                    `}
                                >
                                    <div className="flex items-center gap-3">
                                        {opt.icon}
                                        <div>
                                            <div className="font-medium text-sm">{opt.label}</div>
                                            {opt.description && (
                                                <div className={`text-xs ${value === opt.value ? 'text-white/80' : 'text-[var(--text-muted)]'}`}>
                                                    {opt.description}
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                    {value === opt.value && <Check size={16} />}
                                </button>
                            ))
                        )}
                    </div>
                </div>
            )}
        </div>
    );
}

import bcrypt from 'bcryptjs';
import { SignJWT, jwtVerify } from 'jose';

const SECRET_KEY = process.env.JWT_SECRET || 'changeme_this_is_unsafe_for_production';
const key = new TextEncoder().encode(SECRET_KEY);

export async function hashPassword(password: string): Promise<string> {
    const salt = await bcrypt.genSalt(10);
    return bcrypt.hash(password, salt);
}

export async function verifyPassword(password: string, hash: string): Promise<boolean> {
    return bcrypt.compare(password, hash);
}

export async function signSession(payload: any) {
    return await new SignJWT(payload)
        .setProtectedHeader({ alg: 'HS256' })
        .setIssuedAt()
        .setExpirationTime('24h')
        .sign(key);
}

export async function verifySession(token: string) {
    try {
        const { payload } = await jwtVerify(token, key, {
            algorithms: ['HS256'],
        });
        return payload;
    } catch (error) {
        return null;
    }
}

import type { DashboardDefinition, DashboardTile, DashboardPage } from '@/types/builder';

// ─── Division Filters ────────────────────────────────────────────────────────
// Use a sentinel string to identify the division filter for CGO page cloning
const DIVISION_SENTINEL = '__DIVISION_FILTER__';

function landsideFilter() {
  return { table: 'reports', field: 'target_division', operator: 'not_in' as const, value: ['UQ'], conjunction: 'AND' as const, _tag: DIVISION_SENTINEL };
}

function cgoFilter() {
  return { table: 'reports', field: 'target_division', operator: 'eq' as const, value: 'UQ', conjunction: 'AND' as const };
}

function dateFilters(dateFrom: string, dateTo: string) {
  return [
    { table: 'reports', field: 'created_at', operator: 'gte' as const, value: dateFrom, conjunction: 'AND' as const },
    { table: 'reports', field: 'created_at', operator: 'lte' as const, value: dateTo, conjunction: 'AND' as const },
  ];
}

let tileCounter = 0;
function tileId() { return `cft-${Date.now()}-${++tileCounter}`; }

/** Clone tiles for CGO pages: swap landside filter → CGO filter, rename titles */
function cloneForCGO(tiles: DashboardTile[]): DashboardTile[] {
  return tiles.map(t => ({
    ...t,
    id: tileId(),
    query: {
      ...t.query,
      filters: t.query.filters.map((f: any) =>
        f._tag === DIVISION_SENTINEL ? cgoFilter() : { ...f }
      ),
    },
    visualization: {
      ...t.visualization,
      title: t.visualization.title?.replace('Landside & Airside', 'CGO Cargo') || t.visualization.title,
    },
  }));
}

export function generateCustomerFeedbackDashboard(dateFrom: string, dateTo: string): DashboardDefinition {
  tileCounter = 0;

  // Parse dates safely - handle ISO format (YYYY-MM-DD)
  const parseDate = (dateStr: string): Date => {
    // If already in YYYY-MM-DD format, parse directly to avoid timezone issues
    if (/^\d{4}-\d{2}-\d{2}$/.test(dateStr)) {
      const [year, month, day] = dateStr.split('-').map(Number);
      return new Date(year, month - 1, day); // month is 0-indexed
    }
    return new Date(dateStr);
  };

  const df = dateFilters(dateFrom, dateTo);
  const ls = landsideFilter();
  const fromDate = parseDate(dateFrom);
  const toDate = parseDate(dateTo);
  const fromYear = fromDate.getFullYear();
  const toYear = toDate.getFullYear();

