    incident_types?: IncidentType; 
    
    // Alternative Joined Relations (for consistency)
    user?: User;
    station?: Station;
    incident_type?: IncidentType;
    
    // Frontend-specific props that might be added
    comments?: Comment[];
    
    // Legacy / Alternative fields from API
