    root_cause?: string;
    action_taken?: string;
    airline?: string;
    route?: string;
    area?: string;
    area_category?: string;
    branch?: string;
    reporter_name?: string;
    event_date?: string;
    station_code?: string;

    // CSV-aligned fields
